@app.template_filter('moeda')
def _moeda(v):
    """R$ 10.104,66"""
    try:
        v = float(v or 0)
        neg = v < 0
        v = abs(v)
        cents = f"{v:.2f}".split('.')[1]
        inteiro = str(int(v))
        grupos = []
        while len(inteiro) > 3:
            grupos.insert(0, inteiro[-3:])
            inteiro = inteiro[:-3]
        grupos.insert(0, inteiro)
        return ('R$ -' if neg else 'R$ ') + '.'.join(grupos) + ',' + cents
    except:
        return 'R$ 0,00'

