def campanhas_participantes():
    """Define QUEM participa da roleta de disparo — qualquer usuário ativo (admin
    incluso), escolhido a dedo. Recebe a lista de ids marcados; zera o resto."""
    ids = (request.json or {}).get('ids') or []
    conn = db()
