        {'k': 'adm_operadora',  'label': 'Operadora',        'tipo': 'text'},
        {'k': 'produto',        'label': 'Produto / Plano',  'tipo': 'text'},
        {'k': 'modalidade',     'label': 'Modalidade',       'tipo': 'text'},
