# ─── OPERADORAS (régua de recebimento) ───────────────────────────────────────────
@app.route('/operadoras')
@login_required
@admin_required
def operadoras():
    conn = db()
    rows = conn.execute("SELECT * FROM recebimento ORDER BY operadora,plano").fetchall()
    # Toda operadora cadastrada aparece — inclusive as SEM preço ainda (vindas do
    # registro de nomes / repasse / propostas). Sem isso, um nome recém-cadastrado
    # ou usado só em proposta ficava invisível aqui.
    lista = _operadoras_lista(conn)
    close_db(conn)
    grupos = {}
    for x in lista:
        key = (x['operadora'], x['obs'])
        grupos[key] = {'operadora': x['operadora'], 'obs': x['obs'], 'PME': None, 'PF': None, 'ADESAO': None, 'ids': {}}
    for r in rows:
        key = (r['operadora'], r['obs'] or '')
        grupos.setdefault(key, {'operadora': r['operadora'], 'obs': r['obs'] or '', 'PME': None, 'PF': None, 'ADESAO': None, 'ids': {}})
        grupos[key][r['plano']] = r['total']
        grupos[key]['ids'][r['plano']] = r['id']
    ordenado = sorted(grupos.values(), key=lambda g: (g['operadora'].lower(), g['obs'].lower()))
    return render_template('operadoras.html', grupos=ordenado)

@app.route('/operadora/salvar', methods=['POST'])
@login_required
@admin_required
def operadora_salvar():
    """Cadastra/atualiza uma operadora: registra o NOME (aparece em todas as
    telas mesmo sem preço) e grava o recebimento (mensalidades) por plano que
    vier preenchido. Cadastrar só o nome (sem preço) é válido — pra depois
    configurar preço/repasse."""
    d = request.json or {}
    nome = (d.get('operadora') or '').strip()
    obs = (d.get('obs') or '').strip()
    if not nome:
        return jsonify({"ok": False, "msg": "Informe o nome"}), 400
    display = _op_display(nome, obs)
    conn = db()
    # Registra o nome (fonte única) — é o que faz um nome novo aparecer em
    # /repasses, no form da proposta, etc., independente de ter preço.
    if DB_MODE == 'postgres':
        conn.execute("INSERT INTO operadoras (operadora) VALUES (%s) ON CONFLICT (operadora) DO NOTHING", (display,))
    else:
        conn.execute("INSERT OR IGNORE INTO operadoras (operadora) VALUES (?)", (display,))
    for plano in ['PME', 'PF', 'ADESAO']:
        val = d.get(plano)
        if val in (None, ''): continue
        try: total = float(val)
        except: continue
        conn.execute("""INSERT INTO recebimento (operadora,obs,plano,total) VALUES (?,?,?,?)
            ON CONFLICT(operadora,obs,plano) DO UPDATE SET total=excluded.total""",
            (nome, obs, plano, total))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})

@app.route('/operadora/excluir', methods=['POST'])
@login_required
@admin_required
def operadora_excluir():
    """Exclui uma operadora (identidade operadora+obs) do registro e das tabelas
    de preço. BLOQUEIA se houver proposta usando esse nome — senão a proposta
    ficaria órfã (comissão zerada ao recalcular). O admin renomeia/reatribui
    antes. Nunca apaga proposta."""
    d = request.json or {}
    op = (d.get('operadora') or '').strip()
    obs = (d.get('obs') or '').strip()
    if not op:
        return jsonify({"ok": False, "msg": "Operadora não informada"}), 400
    display = _op_display(op, obs)
    conn = db()
    n_props = conn.execute("SELECT COUNT(*) c FROM propostas WHERE adm_operadora=? AND status<>'Excluída'",
                           (display,)).fetchone()['c']
    if n_props > 0:
        close_db(conn)
        return jsonify({"ok": False, "bloqueado": True, "propostas": n_props,
                        "msg": f"{n_props} proposta(s) usam \"{display}\". Renomeie a operadora "
                               "(o nome troca em todas de uma vez) ou reatribua essas propostas antes de excluir."}), 409
    conn.execute("DELETE FROM recebimento WHERE operadora=? AND obs=?", (op, obs))
    conn.execute("DELETE FROM repasse_corretor WHERE operadora=? AND obs=?", (op, obs))
    conn.execute("DELETE FROM operadoras WHERE operadora=?", (display,))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


@app.route('/operadora/renomear', methods=['POST'])
@login_required
@admin_required
def operadora_renomear():
    """Renomeia uma operadora e PROPAGA em cascata pra recebimento,
    repasse_corretor, o registro de nomes E propostas.adm_operadora — tudo numa
    transação. É o que garante o sincronismo perfeito: trocar o nome num lugar
    troca em todos, e a comissão continua batendo. NÃO permite renomear pra um
    nome que já existe (evita fusão ambígua de preços / perda de dado); nesse
    caso o admin ajusta manual. Nunca apaga proposta — só reescreve o nome."""
    d = request.json or {}
    op_old = (d.get('operadora') or '').strip()
    obs_old = (d.get('obs') or '').strip()
    op_new = (d.get('operadora_novo') or '').strip()
    obs_new = (d.get('obs_novo') or '').strip()
    if not op_old or not op_new:
        return jsonify({"ok": False, "msg": "Informe o nome atual e o novo"}), 400
    disp_old = _op_display(op_old, obs_old)
    disp_new = _op_display(op_new, obs_new)
    if disp_old == disp_new:
        return jsonify({"ok": True, "propostas": 0})
    conn = db()
    # alvo já existe? (em qualquer uma das fontes) -> bloqueia a fusão
    existe = (conn.execute("SELECT 1 FROM recebimento WHERE operadora=? AND obs=? LIMIT 1", (op_new, obs_new)).fetchone()
              or conn.execute("SELECT 1 FROM repasse_corretor WHERE operadora=? AND obs=? LIMIT 1", (op_new, obs_new)).fetchone()
              or conn.execute("SELECT 1 FROM operadoras WHERE operadora=? LIMIT 1", (disp_new,)).fetchone())
    if existe and not d.get('fundir'):
        close_db(conn)
        return jsonify({"ok": False, "existe": True,
                        "msg": f"Já existe uma operadora \"{disp_new}\". Confirme a fusão para juntar as duas "
                               "num nome só (as comissões já salvas nas propostas são mantidas)."}), 409
    if existe and d.get('fundir'):
        # FUSÃO: junta a origem no destino que já existe. Move preços que NÃO colidem
        # (colisão: o destino já tem aquele plano/modelo/nível -> mantém o do destino),
        # reatribui as propostas pro nome do destino SEM recalcular comissão (mantém o
        # que está salvo, como o admin pediu) e remove a origem. Tudo numa transação.
        try:
            for tab, keys in (('recebimento', ['plano']),
                              ('repasse_corretor', ['plano', 'modelo', 'nivel'])):
                origem = conn.execute(f"SELECT * FROM {tab} WHERE operadora=? AND obs=?",
                                      (op_old, obs_old)).fetchall()
                for r in origem:
                    cond = " AND ".join(f"COALESCE({k},'')=?" for k in keys)
                    vals = [r[k] if r[k] is not None else '' for k in keys]
                    colide = conn.execute(
                        f"SELECT 1 FROM {tab} WHERE operadora=? AND obs=? AND {cond} LIMIT 1",
                        (op_new, obs_new, *vals)).fetchone()
                    if colide:
                        conn.execute(f"DELETE FROM {tab} WHERE operadora=? AND obs=? AND {cond}",
                                     (op_old, obs_old, *vals))       # destino ganha
                    else:
                        conn.execute(f"UPDATE {tab} SET operadora=?, obs=? WHERE operadora=? AND obs=? AND {cond}",
                                     (op_new, obs_new, op_old, obs_old, *vals))
            cur = conn.execute("UPDATE propostas SET adm_operadora=? WHERE adm_operadora=?",
                               (disp_new, disp_old))
            n_props = cur.rowcount if cur.rowcount is not None and cur.rowcount >= 0 else \
                conn.execute("SELECT COUNT(*) c FROM propostas WHERE adm_operadora=?", (disp_new,)).fetchone()['c']
            conn.execute("DELETE FROM operadoras WHERE operadora=?", (disp_old,))
            if DB_MODE == 'postgres':
                conn.execute("INSERT INTO operadoras (operadora) VALUES (%s) ON CONFLICT (operadora) DO NOTHING", (disp_new,))
            else:
                conn.execute("INSERT OR IGNORE INTO operadoras (operadora) VALUES (?)", (disp_new,))
            conn.commit()
        except Exception as e:
            try: conn.rollback()
            except Exception: pass
            close_db(conn)
            app.logger.warning(f"[OPERADORA] fusão falhou: {e}")
            return jsonify({"ok": False, "msg": "Falha ao fundir — nada foi alterado."}), 500
        close_db(conn)
        return jsonify({"ok": True, "fundido": True, "propostas": n_props})
    try:
        conn.execute("UPDATE recebimento SET operadora=?, obs=? WHERE operadora=? AND obs=?",
                     (op_new, obs_new, op_old, obs_old))
        conn.execute("UPDATE repasse_corretor SET operadora=?, obs=? WHERE operadora=? AND obs=?",
                     (op_new, obs_new, op_old, obs_old))
        conn.execute("UPDATE operadoras SET operadora=? WHERE operadora=?", (disp_new, disp_old))
        # registro pode não existir ainda pro nome antigo — garante o novo
        if DB_MODE == 'postgres':
            conn.execute("INSERT INTO operadoras (operadora) VALUES (%s) ON CONFLICT (operadora) DO NOTHING", (disp_new,))
        else:
            conn.execute("INSERT OR IGNORE INTO operadoras (operadora) VALUES (?)", (disp_new,))
        cur = conn.execute("UPDATE propostas SET adm_operadora=? WHERE adm_operadora=?", (disp_new, disp_old))
        n_props = cur.rowcount if cur.rowcount is not None and cur.rowcount >= 0 else \
            conn.execute("SELECT COUNT(*) c FROM propostas WHERE adm_operadora=?", (disp_new,)).fetchone()['c']
        conn.commit()
    except Exception as e:
        try: conn.rollback()
        except Exception: pass
        close_db(conn)
        app.logger.warning(f"[OPERADORA] renomear falhou: {e}")
        return jsonify({"ok": False, "msg": "Falha ao renomear — nada foi alterado."}), 500
    close_db(conn)
    return jsonify({"ok": True, "propostas": n_props})

