@app.route('/nivel/salvar', methods=['POST'])
@login_required
@admin_required
def nivel_salvar():
    """Sincroniza a lista completa de níveis: cria, atualiza e remove."""
    dados = request.json.get('niveis', [])
    conn = db()
    codigos = []
    for i, n in enumerate(dados):
        cod = (n.get('codigo') or '').strip().lower() or f"n{i+1}"
        label = (n.get('label') or cod.upper()).strip()
        fmin = float(n['faixa_min']) if n.get('faixa_min') not in (None,'') else 0
        fmax = float(n['faixa_max']) if n.get('faixa_max') not in (None,'') else None
        codigos.append(cod)
        conn.execute("""INSERT INTO niveis (codigo,label,faixa_min,faixa_max,ordem) VALUES (?,?,?,?,?)
            ON CONFLICT(codigo) DO UPDATE SET label=excluded.label, faixa_min=excluded.faixa_min,
            faixa_max=excluded.faixa_max, ordem=excluded.ordem""", (cod, label, fmin, fmax, i+1))
    if codigos:
        ph = ','.join('?'*len(codigos))
        conn.execute(f"DELETE FROM niveis WHERE codigo NOT IN ({ph})", codigos)
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})

# ─── SCORE DE UTILIZAÇÃO ───────────────────────────────────────────────────────
# Cada tipo de ação tem seu peso — pedido explícito do Guilherme ("cada coisa
# tem a sua pontuação"). Ações que exigem mais esforço/geram mais resultado
# (proposta criada, cotação enviada) pesam mais que sinais passivos (minuto
# ativo no navegador).
SCORE_PESOS = {
    'login': 10,
    'minuto_ativo': 1,       # cada heartbeat = ~2min de uso ativo real (mouse/teclado)
    'crm_ligacao': 3,
    'crm_nota': 2,
    'crm_movimentacao': 3,   # mover etapa, criar lead, qualificar
    'crm_whatsapp': 4,
    'crm_sms': 4,
    'crm_email': 3,
    'proposta_criada': 15,
    'proposta_editada': 5,
    'cotacao_enviada': 8,
}
SCORE_LABELS = {
    'login': 'Logins', 'minutos_ativos': 'Minutos ativos (navegador)',
    'crm_ligacao': 'Ligações registradas', 'crm_nota': 'Notas no CRM',
    'crm_movimentacao': 'Movimentações no CRM', 'crm_whatsapp': 'WhatsApp enviados',
    'crm_sms': 'SMS enviados', 'crm_email': 'E-mails enviados',
    'proposta_criada': 'Propostas criadas', 'proposta_editada': 'Edições de proposta',
    'cotacao_enviada': 'Cotações enviadas',
}


def _calcular_score_periodo(conn, data_inicio, data_fim):
    """data_inicio/data_fim: 'YYYY-MM-DD' (inclusive nos dois extremos — pode
    ser o mesmo dia pra manter o comportamento diário). Retorna a lista de
    usuários ativos com o score do período, ordenada do maior pro menor, com
    o detalhe de cada categoria que compôs o score (pra nunca ser uma
    caixa-preta) e o perfil (tipo) de cada usuário, pra permitir ranking
    separado por tipo de usuário na tela."""
    usuarios = conn.execute("SELECT id, nome, perfil FROM usuarios WHERE ativo=1 ORDER BY nome").fetchall()
    resultado = []
    for u in usuarios:
        uid, nome, perfil = u['id'], u['nome'], u['perfil']
        d = {}
        d['login'] = conn.execute(
            "SELECT COUNT(*) c FROM login_log WHERE usuario_id=? AND DATE(criado_em) BETWEEN ? AND ?",
            (uid, data_inicio, data_fim)).fetchone()['c']
        hb = conn.execute(
            "SELECT COALESCE(SUM(minutos_ativos),0) c FROM score_heartbeat WHERE usuario_id=? AND dia BETWEEN ? AND ?",
            (uid, data_inicio, data_fim)).fetchone()
        d['minutos_ativos'] = (hb['c'] if hb else 0) or 0

        ativ = conn.execute("""SELECT tipo, COUNT(*) c FROM crm_atividades
            WHERE usuario_nome=? AND DATE(criado_em) BETWEEN ? AND ? GROUP BY tipo""",
            (nome, data_inicio, data_fim)).fetchall()
        am = {a['tipo']: a['c'] for a in ativ}
        d['crm_ligacao'] = am.get('ligacao', 0)
        d['crm_nota'] = am.get('nota', 0)
        d['crm_movimentacao'] = am.get('movimentacao', 0) + am.get('criacao', 0) + am.get('atividade', 0)
        d['crm_whatsapp'] = am.get('whatsapp', 0)
        d['crm_sms'] = am.get('sms', 0)
        d['crm_email'] = am.get('email', 0) + am.get('cliente_email', 0)

        d['proposta_criada'] = conn.execute(
            "SELECT COUNT(*) c FROM propostas WHERE usuario_id=? AND DATE(criado_em) BETWEEN ? AND ?",
            (uid, data_inicio, data_fim)).fetchone()['c']
        d['proposta_editada'] = conn.execute(
            "SELECT COUNT(*) c FROM historico_proposta WHERE usuario_nome=? AND DATE(criado_em) BETWEEN ? AND ?",
            (nome, data_inicio, data_fim)).fetchone()['c']
        d['cotacao_enviada'] = conn.execute(
            "SELECT COUNT(*) c FROM cotacao_salva WHERE corretor_id=? AND DATE(criado_em) BETWEEN ? AND ?",
            (uid, data_inicio, data_fim)).fetchone()['c']

        score = sum(d[k] * SCORE_PESOS.get(k if k != 'minutos_ativos' else 'minuto_ativo', 0) for k in d)
        resultado.append({'usuario_id': uid, 'nome': nome, 'perfil': perfil, 'score': score, 'detalhe': d})
    resultado.sort(key=lambda x: -x['score'])
    return resultado


def _calcular_score_dia(conn, dia):
    """Compatibilidade: score de um único dia."""
    return _calcular_score_periodo(conn, dia, dia)


@app.route('/score')
@login_required
@admin_required
def score_utilizacao():
    """Painel de utilização do sistema por consultor — pra saber quem esteve
    ativo de verdade e quem sumiu, com o detalhe de cada ação que compôs o
    score (nunca é uma caixa-preta). Suporta 3 janelas: dia, semana (segunda
    a domingo da semana do dia informado) e mês (1º ao último dia do mês)."""
    dia = (request.args.get('dia') or datetime.now(TZ_SP).strftime('%Y-%m-%d')).strip()
    periodo = (request.args.get('periodo') or 'dia').strip()
    dia_dt = datetime.strptime(dia, '%Y-%m-%d').date()

    if periodo == 'semana':
        data_inicio = dia_dt - timedelta(days=dia_dt.weekday())
        data_fim = data_inicio + timedelta(days=6)
    elif periodo == 'mes':
        data_inicio = dia_dt.replace(day=1)
        prox_mes = (data_inicio.replace(day=28) + timedelta(days=4)).replace(day=1)
        data_fim = prox_mes - timedelta(days=1)
    else:
        data_inicio = data_fim = dia_dt

    conn = db()
    ranking = _calcular_score_periodo(conn, data_inicio.isoformat(), data_fim.isoformat())
    close_db(conn)
    max_score = max([r['score'] for r in ranking], default=0) or 1

    ranking_por_perfil = {}
    for r in ranking:
        ranking_por_perfil.setdefault(r['perfil'] or 'consultor', []).append(r)

    return render_template('score.html', dia=dia, periodo=periodo, ranking=ranking, max_score=max_score,
                           labels=SCORE_LABELS, pesos=SCORE_PESOS,
                           ranking_por_perfil=ranking_por_perfil,
                           data_inicio=data_inicio.strftime('%d/%m'), data_fim=data_fim.strftime('%d/%m'))


# ─── FINANCEIRO: fixo, custos, aporte, comissões futuras, estorno ─────────────────
def competencia_atual():
    return date.today().strftime('%Y-%m')

def gerar_fixo_mes(ano_mes):
    """Gera os lançamentos de FIXO do mês para cada consultor com fixo.
    Pago em 2 fluxos: dia 15 e dia 30 (metade em cada), conforme o calendário."""
    conn = db()
    consultores = conn.execute("""SELECT id,nome,valor_fixo FROM usuarios
        WHERE ativo=1 AND regime_base='com_fixo_lead' AND COALESCE(valor_fixo,0)>0""").fetchall()
    criados = 0
    for u in consultores:
        metade = round((u['valor_fixo'] or 0)/2, 2)
        for dia in (15, 30):
            ja = conn.execute("""SELECT id FROM lancamentos WHERE tipo='fixo' AND usuario_id=?
                AND data_competencia=? AND descricao LIKE ?""",
                (u['id'], ano_mes, f"%dia {dia}%")).fetchone()
            if not ja:
                conn.execute("""INSERT INTO lancamentos (tipo,categoria,descricao,valor,data_competencia,data_lancamento,usuario_id,status)
                    VALUES ('fixo','Fixo consultor',?,?,?,?,?,'Previsto')""",
                    (f"Fixo {u['nome']} — dia {dia}", metade, ano_mes, f"{ano_mes}-{dia:02d}", u['id']))
                criados += 1
    conn.commit(); close_db(conn)
    return criados


# ─── Meios de pagamento (cadastro) ──────────────────────────────────────────
# Registro de cartões/contas específicos usados nos custos da empresa — além
# do tipo genérico (Pix, Cartão de crédito...), guarda titular/final do
# cartão/dia de fechamento e vencimento da fatura "quando cabe" (só cartão
# tem esses campos; Pix/boleto/dinheiro/transferência não precisam).
_MEIO_TIPOS_CARTAO = ('cartao_credito', 'cartao_debito')


@app.route('/meio-pagamento/salvar', methods=['POST'])
@login_required
@admin_required
def meio_pagamento_salvar():
    d = request.json or {}
    nome = (d.get('nome') or '').strip()
    tipo = (d.get('tipo') or '').strip()
    if not nome or not tipo:
        return jsonify({"ok": False, "msg": "Nome e tipo são obrigatórios"}), 400

    def num_ou_none(v):
        try:
            return int(v)
        except (TypeError, ValueError):
            return None

    eh_cartao = tipo in _MEIO_TIPOS_CARTAO
    conn = db()
    conn.execute("""INSERT INTO meios_pagamento
        (nome, tipo, banco, titular, final_cartao, dia_fechamento, dia_vencimento_fatura, ativo)
        VALUES (?,?,?,?,?,?,?,1)""",
        (nome, tipo, (d.get('banco') or '').strip() or None,
         (d.get('titular') or '').strip() or None if eh_cartao else None,
         (d.get('final_cartao') or '').strip()[:4] or None if eh_cartao else None,
         num_ou_none(d.get('dia_fechamento')) if tipo == 'cartao_credito' else None,
         num_ou_none(d.get('dia_vencimento_fatura')) if tipo == 'cartao_credito' else None))
    mid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == 'postgres'
           else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "id": mid})


@app.route('/meio-pagamento/<int:mid>/editar', methods=['POST'])
@login_required
@admin_required
def meio_pagamento_editar(mid):
    d = request.json or {}
    nome = (d.get('nome') or '').strip()
    tipo = (d.get('tipo') or '').strip()
    if not nome or not tipo:
        return jsonify({"ok": False, "msg": "Nome e tipo são obrigatórios"}), 400

    def num_ou_none(v):
        try:
            return int(v)
        except (TypeError, ValueError):
            return None

    eh_cartao = tipo in _MEIO_TIPOS_CARTAO
    conn = db()
    if not conn.execute("SELECT id FROM meios_pagamento WHERE id=?", (mid,)).fetchone():
        close_db(conn); return jsonify({"ok": False, "msg": "Meio de pagamento não encontrado"}), 404
    conn.execute("""UPDATE meios_pagamento SET nome=?, tipo=?, banco=?, titular=?, final_cartao=?,
        dia_fechamento=?, dia_vencimento_fatura=? WHERE id=?""",
        (nome, tipo, (d.get('banco') or '').strip() or None,
         (d.get('titular') or '').strip() or None if eh_cartao else None,
         (d.get('final_cartao') or '').strip()[:4] or None if eh_cartao else None,
         num_ou_none(d.get('dia_fechamento')) if tipo == 'cartao_credito' else None,
         num_ou_none(d.get('dia_vencimento_fatura')) if tipo == 'cartao_credito' else None,
         mid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


@app.route('/meio-pagamento/<int:mid>/toggle', methods=['POST'])
@login_required
@admin_required
def meio_pagamento_toggle(mid):
    conn = db()
    m = conn.execute("SELECT ativo FROM meios_pagamento WHERE id=?", (mid,)).fetchone()
    if not m:
        close_db(conn); return jsonify({"ok": False, "msg": "Meio de pagamento não encontrado"}), 404
    novo = 0 if m['ativo'] else 1
    conn.execute("UPDATE meios_pagamento SET ativo=? WHERE id=?", (novo, mid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "ativo": bool(novo)})


@app.route('/meio-pagamento/<int:mid>/excluir', methods=['POST'])
@login_required
@admin_required
def meio_pagamento_excluir(mid):
    """Só exclui se não tiver nenhum lançamento vinculado — meio de pagamento
    é registro financeiro (quem pagou o quê, com qual cartão), apagar um que
    já foi usado deixaria lançamentos antigos órfãos e sem explicação. Se já
    foi usado, o caminho é desativar (toggle), não excluir."""
    conn = db()
    if not conn.execute("SELECT id FROM meios_pagamento WHERE id=?", (mid,)).fetchone():
        close_db(conn); return jsonify({"ok": False, "msg": "Meio de pagamento não encontrado"}), 404
    em_uso = conn.execute("SELECT COUNT(*) c FROM lancamentos WHERE meio_pagamento_id=?", (mid,)).fetchone()['c']
    if em_uso:
        close_db(conn)
        return jsonify({"ok": False, "msg": f"Esse meio já foi usado em {em_uso} lançamento(s) — desative em vez de excluir, pra não perder o histórico."}), 400
    conn.execute("DELETE FROM meios_pagamento WHERE id=?", (mid,))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


@app.route('/financeiro')
@login_required
@admin_required
def financeiro():
    mes = request.args.get('mes', competencia_atual())
    # Deep-link: notificação de "comprovante recebido" aponta pra cá com o
    # lançamento específico — antes caía sempre na aba/mês genérico.
    try:
        lancamento_focus = int(request.args.get('lancamento', '') or 0) or None
    except (TypeError, ValueError):
        lancamento_focus = None
    conn = db()
    # Comissões a receber (futuras) agrupadas por competência
    futuras = conn.execute("""SELECT competencia,
            COALESCE(SUM(valor),0) consultor, COALESCE(SUM(valor_corretora),0) corretora, COUNT(*) qtd
        FROM parcelas WHERE status NOT IN ('Pago ao corretor') AND competencia IS NOT NULL
        GROUP BY competencia ORDER BY competencia""").fetchall()
    # Lançamentos do mês (custos vêm com o meio de pagamento vinculado, se
    # houver, pra mostrar "Nubank •••• 4521" em vez de só "Cartão crédito").
    custos = conn.execute("""SELECT l.*, mp.nome AS meio_nome, mp.tipo AS meio_tipo, mp.banco AS meio_banco,
            mp.titular AS meio_titular, mp.final_cartao AS meio_final_cartao,
            mp.dia_vencimento_fatura AS meio_dia_vencimento
        FROM lancamentos l LEFT JOIN meios_pagamento mp ON mp.id = l.meio_pagamento_id
        WHERE l.tipo='custo' AND l.data_competencia=? ORDER BY l.id DESC""", (mes,)).fetchall()
    aportes = conn.execute("SELECT * FROM lancamentos WHERE tipo='aporte' AND data_competencia=? ORDER BY id DESC", (mes,)).fetchall()
    reembolsos = conn.execute("SELECT * FROM lancamentos WHERE tipo='reembolso' AND data_competencia=? ORDER BY id DESC", (mes,)).fetchall()
    fixos = conn.execute("""SELECT l.*, u.nome consultor_nome FROM lancamentos l
        LEFT JOIN usuarios u ON u.id=l.usuario_id WHERE l.tipo='fixo' AND l.data_competencia=? ORDER BY l.data_lancamento""", (mes,)).fetchall()
    # dict (não Row) — precisa ir serializado como JSON pro JS do template
    # montar o preview do meio selecionado sem chamada extra ao servidor.
    meios_pagamento = [dict(m) for m in conn.execute(
        "SELECT * FROM meios_pagamento ORDER BY ativo DESC, tipo, nome").fetchall()]
    # Totais do mês
    receber_mes = conn.execute("""SELECT COALESCE(SUM(valor_corretora),0) v FROM parcelas
        WHERE competencia=? AND status NOT IN ('Pago ao corretor')""", (mes,)).fetchone()['v']
    pagar_consultor = conn.execute("""SELECT COALESCE(SUM(valor),0) v FROM parcelas
        WHERE competencia=? AND status NOT IN ('Pago ao corretor')""", (mes,)).fetchone()['v']
    total_custos_puro = sum(c['valor'] for c in custos)
    total_fixos = sum(f['valor'] for f in fixos)
    total_custos = total_custos_puro + total_fixos
    total_aportes = sum(a['valor'] for a in aportes)
    total_reembolsos = sum(r['valor'] for r in reembolsos)
    saldo = receber_mes - pagar_consultor - total_custos_puro - total_fixos + total_aportes - total_reembolsos
    # ─── DRE do mês (regime de COMPETÊNCIA: tudo do mês, pago ou não) ───
    # Antes a DRE somava só parcelas NÃO pagas: pagar um consultor fazia a
    # receita e o repasse daquele valor SUMIREM do relatório, distorcendo o
    # resultado do mês conforme os pagamentos aconteciam. E a receita bruta só
    # contava a parte da corretora (valor_corretora), mas o repasse era
    # descontado por cima — dupla subtração da parte do consultor. Agora:
    # receita = comissão TOTAL da operadora (consultor + corretora), repasse =
    # parte do consultor (pago + a pagar), margem = parte líquida da corretora.
    tot_mes = conn.execute("""SELECT COALESCE(SUM(valor),0) consultor,
            COALESCE(SUM(valor_corretora),0) corretora FROM parcelas
        WHERE competencia=?""", (mes,)).fetchone()
    repasse_pago = conn.execute("""SELECT COALESCE(SUM(valor),0) v FROM parcelas
        WHERE competencia=? AND status='Pago ao corretor'""", (mes,)).fetchone()['v']
    dre = {
        'receita_bruta': (tot_mes['consultor'] or 0) + (tot_mes['corretora'] or 0),
        'repasse_consultores': tot_mes['consultor'] or 0,      # (-) repasses (pago + a pagar)
        'repasse_pago': repasse_pago,                          # quanto do repasse já foi pago
        'repasse_a_pagar': (tot_mes['consultor'] or 0) - repasse_pago,
        'custos_operacionais': total_custos_puro,              # (-) custos lançados
        'fixos': total_fixos,                                  # (-) fixos
        'aportes': total_aportes,                              # (+) aportes
        'reembolsos': total_reembolsos,                        # (-) reembolsos pagos aos sócios
    }
    dre['margem_bruta'] = dre['receita_bruta'] - dre['repasse_consultores']
    dre['resultado'] = dre['margem_bruta'] - dre['custos_operacionais'] - dre['fixos'] + dre['aportes'] - dre['reembolsos']

    # ─── Saldo entre sócios (histórico completo, não só do mês) ───
    # Quanto a empresa deve a cada sócio: aportes que ele colocou + custos que
    # ele pagou do próprio bolso (fonte_pagamento='Terceiro'), menos o que já
    # foi reembolsado a ele. Não é "sócio A deve a sócio B" direto (não há % de
    # sociedade cadastrado), é "quanto falta a empresa devolver a cada um".
    socios_aportes = conn.execute("""SELECT socio, COALESCE(SUM(valor),0) v FROM lancamentos
        WHERE tipo='aporte' AND socio IS NOT NULL AND socio != '' GROUP BY socio""").fetchall()
    socios_adiantado = conn.execute("""SELECT pago_por AS socio, COALESCE(SUM(valor),0) v FROM lancamentos
        WHERE tipo='custo' AND fonte_pagamento='Terceiro' AND pago_por IS NOT NULL AND pago_por != '' AND pago_por != 'Caixa da empresa'
        GROUP BY pago_por""").fetchall()
    socios_reembolsados = conn.execute("""SELECT socio, COALESCE(SUM(valor),0) v FROM lancamentos
        WHERE tipo='reembolso' AND socio IS NOT NULL AND socio != '' GROUP BY socio""").fetchall()
    saldo_socios = {}
    for r in socios_aportes:
        saldo_socios[r['socio']] = saldo_socios.get(r['socio'], 0) + r['v']
    for r in socios_adiantado:
        saldo_socios[r['socio']] = saldo_socios.get(r['socio'], 0) + r['v']
    for r in socios_reembolsados:
        saldo_socios[r['socio']] = saldo_socios.get(r['socio'], 0) - r['v']
    saldo_socios_lista = sorted(
        [{'socio': s, 'saldo': v} for s, v in saldo_socios.items() if abs(v) > 0.005],
        key=lambda x: -x['saldo'])

    close_db(conn)
    return render_template('financeiro.html', mes=mes, futuras=futuras,
        custos=custos, aportes=aportes, fixos=fixos, reembolsos=reembolsos,
        meios_pagamento=meios_pagamento,
        receber_mes=receber_mes, pagar_consultor=pagar_consultor,
        total_custos=total_custos, total_custos_puro=total_custos_puro, total_fixos=total_fixos,
        total_aportes=total_aportes, total_reembolsos=total_reembolsos,
        saldo=saldo, dre=dre, saldo_socios=saldo_socios_lista, lancamento_focus=lancamento_focus)

def _proximo_mes(competencia, n):
    """Soma n meses a uma competência 'YYYY-MM'. Retorna 'YYYY-MM'."""
    ano, mes = int(competencia[:4]), int(competencia[5:7])
    total = (ano * 12 + (mes - 1)) + n
    return f"{total // 12}-{(total % 12) + 1:02d}"


# ─── FECHAMENTO MENSAL POR CONSULTOR ─────────────────────────────────────────
@app.route('/fechamento')
@login_required
@admin_required
def fechamento():
    """Fechamento do mês por consultor: "quanto devo ao Fulano em {mes}?" —
    fixo (lancamentos tipo fixo) + comissões (parcelas da competência) num
    lugar só, com pagamento em lote. Antes o fixo vivia no /financeiro e a
    comissão no /fluxo-caixa, e fechar o mês era caçar parcela por parcela
    (auditoria 14/07)."""
    mes = request.args.get('mes', competencia_atual())
    if len(mes) != 7:
        mes = competencia_atual()
    conn = db()
    consultores = conn.execute("""SELECT id, nome, chave_pix FROM usuarios
        WHERE ativo=1 AND perfil='consultor' ORDER BY nome""").fetchall()
    linhas = []
    tot = {'fixo_a_pagar': 0.0, 'liberado': 0.0, 'em_fluxo': 0.0, 'pago': 0.0, 'total_a_pagar': 0.0}
    for u in consultores:
        fixo = conn.execute("""SELECT COALESCE(SUM(valor),0) total,
                COALESCE(SUM(CASE WHEN status IN ('Pago','Conciliado') THEN valor ELSE 0 END),0) pago
            FROM lancamentos WHERE tipo='fixo' AND usuario_id=? AND data_competencia=?""",
            (u['id'], mes)).fetchone()
        com = conn.execute("""SELECT
                COALESCE(SUM(CASE WHEN pa.status='Liberado para o corretor' THEN pa.valor ELSE 0 END),0) liberado,
                COUNT(CASE WHEN pa.status='Liberado para o corretor' THEN 1 END) qtd_liberadas,
                COALESCE(SUM(CASE WHEN pa.status='Pago ao corretor' THEN pa.valor ELSE 0 END),0) pago,
                COALESCE(SUM(CASE WHEN pa.status NOT IN ('Liberado para o corretor','Pago ao corretor') THEN pa.valor ELSE 0 END),0) em_fluxo
            FROM parcelas pa JOIN propostas p ON p.id=pa.proposta_id
            WHERE p.usuario_id=? AND pa.competencia=?""", (u['id'], mes)).fetchone()
        fixo_a_pagar = round((fixo['total'] or 0) - (fixo['pago'] or 0), 2)
        linha = {
            'id': u['id'], 'nome': u['nome'], 'chave_pix': (u['chave_pix'] or '').strip(),
            'fixo_total': fixo['total'] or 0, 'fixo_pago': fixo['pago'] or 0, 'fixo_a_pagar': fixo_a_pagar,
            'liberado': com['liberado'] or 0, 'qtd_liberadas': com['qtd_liberadas'] or 0,
            'pago': com['pago'] or 0, 'em_fluxo': com['em_fluxo'] or 0,
        }
        linha['total_a_pagar'] = round(fixo_a_pagar + linha['liberado'], 2)
        # consultor sem nenhum movimento no mês não polui a tela
        if not any([linha['fixo_total'], linha['liberado'], linha['pago'], linha['em_fluxo']]):
            continue
        tot['fixo_a_pagar'] += fixo_a_pagar
        tot['liberado'] += linha['liberado']
        tot['em_fluxo'] += linha['em_fluxo']
        tot['pago'] += linha['pago'] + linha['fixo_pago']
        tot['total_a_pagar'] += linha['total_a_pagar']
        linhas.append(linha)
    close_db(conn)
    return render_template('fechamento.html', mes=mes, linhas=linhas, tot=tot,
                           mes_ant=_proximo_mes(mes, -1), mes_prox=_proximo_mes(mes, 1),
                           asaas_ok=asaas_configurado())


@app.route('/fechamento/pagar', methods=['POST'])
@login_required
@admin_required
def fechamento_pagar():
    """Paga o mês de UM consultor em lote.
    metodo='manual': marca as parcelas liberadas como pagas + fixo como pago
      (registro, não transfere dinheiro) e avisa o consultor com UM resumo.
    metodo='asaas': dispara PIX real parcela por parcela via Asaas — cada uma
      vira 'Pago ao corretor' quando o webhook confirmar (que também notifica).
      O fixo NÃO vai pelo Asaas (não é parcela) — marcar manual depois."""
    d = request.json or {}
    try:
        uid = int(d.get('usuario_id') or 0)
    except (TypeError, ValueError):
        uid = 0
    mes = str(d.get('mes') or '').strip()
    metodo = d.get('metodo')
    if not uid or len(mes) != 7 or metodo not in ('manual', 'asaas'):
        return jsonify({"ok": False, "erro": "Parâmetros inválidos"}), 400
    conn = db()
    parcelas = conn.execute("""SELECT pa.id, pa.valor FROM parcelas pa
        JOIN propostas p ON p.id=pa.proposta_id
        WHERE p.usuario_id=? AND pa.competencia=? AND pa.status='Liberado para o corretor'
        ORDER BY pa.id""", (uid, mes)).fetchall()
    resultado = {"parcelas_ok": 0, "parcelas_erro": [], "fixo_pago": 0.0, "total": 0.0}
    if metodo == 'asaas':
        if not asaas_configurado():
            close_db(conn)
            return jsonify({"ok": False, "erro": "Asaas não configurado. Adicione ASAAS_API_KEY no Railway."}), 400
        for pa in parcelas:
            ok, info = _pagar_parcela_asaas_core(conn, pa['id'], session.get('nome'))
            if ok:
                resultado['parcelas_ok'] += 1
                resultado['total'] += pa['valor'] or 0
            else:
                resultado['parcelas_erro'].append(f"parcela {pa['id']}: {info}")
    else:
        agora = datetime.now(TZ_SP).isoformat()
        for pa in parcelas:
            conn.execute("UPDATE parcelas SET status='Pago ao corretor', data_pagamento=? WHERE id=?",
                         (agora, pa['id']))
            resultado['parcelas_ok'] += 1
            resultado['total'] += pa['valor'] or 0
        fx = conn.execute("""SELECT COALESCE(SUM(valor),0) v FROM lancamentos
            WHERE tipo='fixo' AND usuario_id=? AND data_competencia=?
              AND COALESCE(status,'') NOT IN ('Pago','Conciliado')""", (uid, mes)).fetchone()
        if fx and fx['v']:
            conn.execute("""UPDATE lancamentos SET status='Pago', data_pagamento=?
                WHERE tipo='fixo' AND usuario_id=? AND data_competencia=?
                  AND COALESCE(status,'') NOT IN ('Pago','Conciliado')""",
                (_fmt_data_br(datetime.now(TZ_SP)), uid, mes))
            resultado['fixo_pago'] = fx['v']
            resultado['total'] += fx['v']
        conn.commit()
        if resultado['total'] > 0:
            _notificar(uid, 'comissao', f'Fechamento de {mes} pago',
                       f"{resultado['parcelas_ok']} parcela(s)" +
                       (f" + fixo de {_moeda(resultado['fixo_pago'])}" if resultado['fixo_pago'] else '') +
                       f" — total {_moeda(resultado['total'])}", '/fluxo-caixa')
    close_db(conn)
    return jsonify({"ok": True, **resultado})


@app.route('/lancamento/salvar', methods=['POST'])
@login_required
@admin_required
def lancamento_salvar():
    """Cria um lançamento. Se num_parcelas > 1, divide o valor em N lançamentos
    mensais ligados por grupo_parcela (ex: compra parcelada no cartão) — cada
    parcela cai na competência do mês correspondente à emissão + i meses.
    A competência SEMPRE é derivada de data_emissao (nunca do mês que está
    sendo visualizado na tela) — evita lançamento cair na competência errada."""
    d = request.json or {}
    tipo = d.get('tipo')
    descricao = d.get('descricao')
    valor_total = float(str(d.get('valor') or 0).replace('.', '').replace(',', '.')) if isinstance(d.get('valor'), str) and ',' in str(d.get('valor')) else float(d.get('valor') or 0)
    data_emissao = (d.get('data_emissao') or d.get('data_lancamento') or '').strip()
    data_vencimento = (d.get('data_vencimento') or '').strip()
    try:
        num_parcelas = max(1, int(d.get('num_parcelas') or 1))
    except (ValueError, TypeError):
        num_parcelas = 1

    competencia_base = data_emissao[:7] if len(data_emissao) >= 7 else (d.get('data_competencia') or competencia_atual())

    conn = db()
    # Se veio um meio de pagamento cadastrado, a forma de pagamento é sempre
    # derivada do TIPO dele (não confia no que veio solto do front) — garante
    # que "Nubank final 4521" sempre aparece corretamente como cartão de
    # crédito, mesmo que o forma_pagamento enviado esteja desatualizado.
    forma_pagamento = (d.get('forma_pagamento') or '').strip()
    try:
        meio_pagamento_id = int(d.get('meio_pagamento_id')) if d.get('meio_pagamento_id') else None
    except (TypeError, ValueError):
        meio_pagamento_id = None
    if meio_pagamento_id:
        meio = conn.execute("SELECT tipo FROM meios_pagamento WHERE id=?", (meio_pagamento_id,)).fetchone()
        if meio:
            forma_pagamento = meio['tipo']
        else:
            meio_pagamento_id = None

    grupo = secrets.token_hex(6) if num_parcelas > 1 else None
    valor_parcela = round(valor_total / num_parcelas, 2)
    ids = []
    for i in range(num_parcelas):
        # Última parcela absorve a diferença de arredondamento
        valor_i = round(valor_total - valor_parcela * (num_parcelas - 1), 2) if i == num_parcelas - 1 else valor_parcela
        competencia_i = _proximo_mes(competencia_base, i) if competencia_base else competencia_atual()
        desc_i = f"{descricao} ({i+1}/{num_parcelas})" if num_parcelas > 1 else descricao
        conn.execute("""INSERT INTO lancamentos
            (tipo,categoria,descricao,valor,data_competencia,data_lancamento,data_emissao,data_vencimento,
             socio,recorrente,status,pago_por,fonte_pagamento,forma_pagamento,meio_pagamento_id,grupo_parcela,parcela_num,parcela_total)
            VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
            (tipo, d.get('categoria', ''), desc_i, valor_i, competencia_i,
             data_emissao or competencia_i, data_emissao or None, data_vencimento or None,
             d.get('socio', ''), 1 if d.get('recorrente') else 0, 'Previsto',
             (d.get('pago_por') or '').strip(), (d.get('fonte_pagamento') or '').strip(),
             forma_pagamento, meio_pagamento_id,
             grupo, i + 1 if num_parcelas > 1 else None, num_parcelas if num_parcelas > 1 else None))
        lid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == 'postgres'
               else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
        ids.append(lid)
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "id": ids[0], "ids": ids, "parcelas_criadas": num_parcelas})


@app.route('/lancamento/<int:lid>/editar', methods=['POST'])
@login_required
@admin_required
def lancamento_editar(lid):
    """Edição de um lançamento já criado — antes não existia nenhuma forma de
    corrigir um lançamento, só excluir e recriar. Só atualiza os campos
    enviados no payload — campo ausente preserva o valor atual (edição
    parcial), em vez de apagar pago_por/fonte_pagamento/socio não reenviados."""
    d = request.json or {}
    conn = db()
    atual = conn.execute("SELECT * FROM lancamentos WHERE id=?", (lid,)).fetchone()
    if not atual:
        close_db(conn); return jsonify({"ok": False, "msg": "Lançamento não encontrado"}), 404

    def campo(chave, default=''):
        return d[chave] if chave in d else (atual[chave] if chave in atual.keys() else default)

    valor_raw = campo('valor', atual['valor'])
    valor = float(str(valor_raw).replace('.', '').replace(',', '.')) if isinstance(valor_raw, str) and ',' in str(valor_raw) else float(valor_raw or 0)
    data_emissao = (campo('data_emissao') or '').strip()
    competencia = data_emissao[:7] if len(data_emissao) >= 7 else (campo('data_competencia') or atual['data_competencia'])

    meio_raw = campo('meio_pagamento_id', atual['meio_pagamento_id'])
    try:
        meio_pagamento_id = int(meio_raw) if meio_raw else None
    except (TypeError, ValueError):
        meio_pagamento_id = None
    forma_pagamento = (campo('forma_pagamento') or '').strip()
    if meio_pagamento_id:
        meio = conn.execute("SELECT tipo FROM meios_pagamento WHERE id=?", (meio_pagamento_id,)).fetchone()
        if meio:
            forma_pagamento = meio['tipo']
        else:
            meio_pagamento_id = None

    conn.execute("""UPDATE lancamentos SET descricao=?, categoria=?, valor=?, data_emissao=?, data_vencimento=?,
        data_competencia=?, socio=?, pago_por=?, fonte_pagamento=?, forma_pagamento=?, meio_pagamento_id=?
        WHERE id=?""",
        (campo('descricao'), campo('categoria'), valor, data_emissao or None, (campo('data_vencimento') or '').strip() or None,
         competencia, campo('socio'), (campo('pago_por') or '').strip(), (campo('fonte_pagamento') or '').strip(),
         forma_pagamento, meio_pagamento_id, lid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


