    # Métricas
    total_excluidas = conn.execute("SELECT COUNT(*) c FROM propostas WHERE status='Excluída'").fetchone()['c']
    valor_excluido = conn.execute("SELECT COALESCE(SUM(valor),0) v FROM propostas WHERE status='Excluída'").fetchone()['v']
