_CLAUDE_MAX_IMAGENS = 8  # teto por análise (controle de custo/payload)
_CLAUDE_MAX_DOCUMENTOS = 5  # teto de PDFs por análise (custo/payload maior que imagem)


def _calcular_idade(nascimento_str):
    """Idade a partir de DD/MM/AAAA. None se não der pra ler."""
    m = re.match(r'\s*(\d{1,2})/(\d{1,2})/(\d{4})', str(nascimento_str or ''))
    if not m:
        return None
    try:
        d, mes, ano = int(m.group(1)), int(m.group(2)), int(m.group(3))
        hoje = datetime.now(TZ_SP).date()
        idade = hoje.year - ano - ((hoje.month, hoje.day) < (mes, d))
        return idade if 0 <= idade <= 120 else None
    except Exception:
        return None


def _formatar_docs_extraidos(pessoas, empresa):
    """Formata os dados extraídos dos documentos no padrão EXATO pedido pelo
    Guilherme: CAIXA ALTA, bullets, sem nome de campo (só EMISSÃO:/NATURAL:/CEP:),
    'NÃO LOCALIZADO' pro que faltar, idade calculada. Um bloco por pessoa +
    bloco de empresa/plano no fim. Devolve '' se não houver nada."""
    NL = 'NÃO LOCALIZADO'
    def U(v):
        v = str(v or '').strip()
        return v.upper() if v else NL
    blocos = []
    for p in (pessoas or []):
        nasc = str(p.get('nascimento') or '').strip()
        idade = _calcular_idade(nasc)
        linha_nasc = (nasc.upper() + (f" — {idade} ANOS" if idade is not None else '')) if nasc else NL
        b = [
            '• ' + U(p.get('nome')),
            '• ' + U(p.get('cpf')),
            '• ' + U(p.get('rg')),
            '• ' + linha_nasc,
            '• EMISSÃO: ' + U(p.get('emissao')),
            '• NATURAL: ' + U(p.get('natural')),
            '• ' + U(p.get('pai')),
            '• ' + U(p.get('mae')),
            '• ' + U(p.get('cns')),
            '',
            '• ' + U(p.get('email')),
            '• ' + U(p.get('telefone')),
            '',
            '• ' + U(p.get('endereco_rua')),
            '• ' + U(p.get('endereco_numero')),
            '• ' + U(p.get('endereco_bairro')),
            '• ' + U(p.get('endereco_cidade')),
            '• CEP: ' + U(p.get('endereco_cep')),
        ]
        blocos.append('\n'.join(b))
    emp = empresa or {}
    if any((emp.get(k) or '').strip() for k in ('razao_social', 'cnpj', 'plano_atual', 'operadora_atual', 'casamento_vigencia')):
        eb = ['EMPRESA / PLANO ATUAL',
              '• ' + U(emp.get('razao_social')),
              '• CNPJ: ' + U(emp.get('cnpj')),
              '• PLANO ATUAL: ' + U(emp.get('plano_atual')),
              '• OPERADORA ATUAL: ' + U(emp.get('operadora_atual')),
              '• CASAMENTO DE VIGÊNCIA: ' + U(emp.get('casamento_vigencia'))]
        blocos.append('\n'.join(eb))
    return '\n\n'.join(blocos)


def _pdf_extrair_conteudo(b64, max_paginas=4):
    """Prepara um PDF pro Claude ler MELHOR. Retorna (texto, paginas_jpeg_b64):
    - PDF digital (tem camada de texto, ex: CNH-e, declaração de operadora):
      devolve o texto completo — leitura perfeita, sem depender de visão.
    - PDF escaneado ("Whatsapp Scan": foto de RG/CNH/certidão dentro de um PDF,
      SEM camada de texto): renderiza as páginas em alta resolução (~200 DPI,
      via pdfplumber/pypdfium2 que já são dependência do projeto) e devolve como
      JPEG base64 — a visão da Claude lê texto miúdo de scan muito melhor assim
      do que pelo pipeline nativo de PDF em resolução padrão.
    Qualquer erro degrada gracioso pra ('', []) — o chamador manda o PDF nativo."""
    import io
    import base64 as _b64
    try:
        raw = _b64.b64decode(b64)
        import pdfplumber
        paginas = []
        with pdfplumber.open(io.BytesIO(raw)) as pdf:
            pgs = pdf.pages[:max_paginas]
            partes = [(pg.extract_text() or '').strip() for pg in pgs]
            texto = '\n\n'.join(p for p in partes if p).strip()
            # >=120 chars = camada de texto de verdade (menos que isso costuma ser
            # só número de página/rodapé de scanner — trata como escaneado).
            if len(texto) >= 120:
                return texto, []
            for pg in pgs:
                try:
                    img = pg.to_image(resolution=200).original.convert('RGB')
                    if max(img.size) > 2000:  # teto de payload/custo por página
                        img.thumbnail((2000, 2000))
                    buf = io.BytesIO()
                    img.save(buf, format='JPEG', quality=88)
                    paginas.append(_b64.b64encode(buf.getvalue()).decode())
                except Exception:
                    continue
        return '', paginas
    except Exception as e:
        app.logger.warning(f"[PDF] extração de conteúdo falhou: {e}")
        return '', []


def _analisar_com_claude(mensagens, extracao, score, faixa, imagens=None, documentos=None, links=None):
    """Chama a Claude para uma leitura qualitativa da conversa (texto + imagens + PDFs + links).
    Retorna dict {resumo, fase_funil, leitura_imagens, leitura_documentos, proximas_acoes,
    sinais_atencao, modelo, imagens_lidas, documentos_lidos} ou None se não há chave ou algo
    falhar (chamador trata None como 'sem camada de IA')."""
    api_key = os.environ.get('ANTHROPIC_API_KEY', '').strip()
    if not api_key:
        return None
    try:
        import anthropic
    except Exception as e:
        app.logger.warning(f"[CLAUDE] pacote anthropic ausente: {e}")
        return None
    try:
        linhas = []
        for m in mensagens:
            txt = (m.get('texto') or '').strip()
            if not txt:
                continue
            quem = 'CLIENTE' if m.get('de') == 'lead' else 'CONSULTOR'
            linhas.append(f"[{m.get('hora', '')}] {quem}: {txt}")
        conversa_txt = '\n'.join(linhas)[:24000]

        # Blocos de imagem (base64). Cada uma precedida de um rótulo de texto pra
        # preservar quem-enviou e quando (a Claude cruza a imagem com a conversa).
        blocos_img = []
        for img in (imagens or [])[:_CLAUDE_MAX_IMAGENS]:
            b64 = (img.get('base64') or '').strip()
            if not b64:
                continue
            mime = (img.get('mime') or 'image/jpeg').strip()
            if mime not in ('image/jpeg', 'image/png', 'image/webp', 'image/gif'):
                mime = 'image/jpeg'
            quem = 'CLIENTE' if img.get('de') == 'lead' else 'CONSULTOR'
            blocos_img.append({"type": "text", "text": f"[{img.get('hora', '')}] Imagem enviada pelo {quem}:"})
            blocos_img.append({"type": "image", "source": {"type": "base64", "media_type": mime, "data": b64}})

        # Blocos de documento PDF (base64) — mesma lógica de rótulo dos blocos de
        # imagem. Cada PDF passa por _pdf_extrair_conteudo: digital vira TEXTO
        # extraído (leitura perfeita, ex: CNH-e); escaneado vira PÁGINAS em alta
        # resolução (a Claude lia mal o scan pelo PDF nativo — "Whatsapp Scan"
        # de RG/CNH/certidão voltava sem extração, caso do Aluizio 14/07).
        blocos_doc = []
        docs_processados = 0
        for doc in (documentos or [])[:_CLAUDE_MAX_DOCUMENTOS]:
            b64 = (doc.get('base64') or '').strip()
            if not b64:
                continue
            quem = 'CLIENTE' if doc.get('de') == 'lead' else 'CONSULTOR'
            nome_doc = (doc.get('nome') or 'documento.pdf').strip()
            rotulo = f"[{doc.get('hora', '')}] PDF enviado pelo {quem} ({nome_doc})"
            texto_pdf, paginas_img = _pdf_extrair_conteudo(b64)
            if texto_pdf:
                blocos_doc.append({"type": "text", "text": rotulo + " — texto extraído do PDF:\n" + texto_pdf[:8000]})
                blocos_doc.append({"type": "document", "source": {"type": "base64", "media_type": "application/pdf", "data": b64}})
            elif paginas_img:
                blocos_doc.append({"type": "text", "text": rotulo + f" — scan renderizado em alta resolução ({len(paginas_img)} página(s)):"})
                for pb64 in paginas_img:
                    blocos_doc.append({"type": "image", "source": {"type": "base64", "media_type": "image/jpeg", "data": pb64}})
            else:
                blocos_doc.append({"type": "text", "text": rotulo + ":"})
                blocos_doc.append({"type": "document", "source": {"type": "base64", "media_type": "application/pdf", "data": b64}})
            docs_processados += 1

        # Links compartilhados na conversa — só o texto (URL + prévia que o
        # WhatsApp já mostra), NUNCA abrimos/buscamos o link no servidor.
        links_linhas = []
        for lk in (links or [])[:15]:
            url = (lk.get('url') or '').strip()
            if not url:
                continue
            quem = 'CLIENTE' if lk.get('de') == 'lead' else 'CONSULTOR'
            preview = (lk.get('preview') or '').strip()
            linha = f"[{lk.get('hora', '')}] Link enviado pelo {quem}: {url}"
            if preview:
                linha += f" — prévia: {preview[:300]}"
            links_linhas.append(linha)
        links_txt = '\n'.join(links_linhas)

        if not conversa_txt and not blocos_img and not blocos_doc and not links_txt:
            return None

        conteudo = [{"type": "text", "text":
                     f"Dados já extraídos pelo motor de regras: {json.dumps(extracao, ensure_ascii=False)}\n"
                     f"Score heurístico (referência, não recalcular): {score}/1000 ({faixa}).\n\n"
                     f"CONVERSA (ordem cronológica):\n{conversa_txt or '(sem texto)'}"
                     + (f"\n\nLINKS COMPARTILHADOS NA CONVERSA:\n{links_txt}" if links_txt else "")}]
        conteudo.extend(blocos_img)
        conteudo.extend(blocos_doc)

        # timeout 150s (era 60): o Sonnet lendo documento é mais lento e passava
        # de 60s, aí a chamada estourava e o SDK re-tentava sozinho (2x60s ~ 2min),
        # terminando em falha -> análise sem IA, custo R$ 0,00 e score sem o cap
        # (parte do "score oscila" e "não calcula custo"). max_retries=1 evita o
        # empilhamento de tentativas lentas.
        client = anthropic.Anthropic(api_key=api_key, timeout=150.0, max_retries=1)
        # Modelo mais forte quando a conversa tem documento/imagem, se configurado.
        modelo = _CLAUDE_MODEL_DOCS if (_CLAUDE_MODEL_DOCS and (blocos_img or blocos_doc)) else _CLAUDE_MODEL
        # Chama com folga de tokens; se AINDA truncar (documento muito pesado),
        # refaz 1x com o dobro do teto em vez de deixar o json.loads quebrar e a
        # análise inteira virar None. Antes era max_tokens=1500 fixo -> a conversa
        # de fechamento da Cintia estourava e sumia com tudo (sem pista no log).
        max_tokens = _CLAUDE_MAX_TOKENS_ANALISE
        resp = None
        txt = ''
        for tentativa in range(2):
            resp = client.messages.create(
                model=modelo,
                max_tokens=max_tokens,
                system=_CLAUDE_SYSTEM_ANALISE,
                output_config={"format": {"type": "json_schema", "schema": _CLAUDE_SCHEMA_ANALISE}},
                messages=[{"role": "user", "content": conteudo}],
            )
            txt = next((b.text for b in resp.content if b.type == 'text'), '')
            if getattr(resp, 'stop_reason', None) != 'max_tokens':
                break
            app.logger.warning(f"[CLAUDE] resposta truncada em {max_tokens} tokens (stop_reason=max_tokens)"
                               + (" — refazendo com o dobro do teto" if tentativa == 0
                                  else " — teto dobrado ainda não bastou, desisto"))
            max_tokens = min(max_tokens * 2, 16000)
        try:
            dados = json.loads(txt)
        except Exception as e:
            # NÃO engole mais o erro em silêncio — era isso que deixava o bug
            # invisível ("motor burro" sem nada no log). Loga a causa e o pedaço.
            app.logger.warning(f"[CLAUDE] parse do JSON falhou: {repr(e)} | stop_reason="
                               f"{getattr(resp, 'stop_reason', None)} | inicio={txt[:200]!r} | fim={txt[-200:]!r}")
            return None
        dados['modelo'] = modelo
        dados['imagens_lidas'] = len(blocos_img) // 2
        dados['documentos_lidos'] = docs_processados
        tok_in = getattr(resp.usage, 'input_tokens', 0) or 0
        tok_out = getattr(resp.usage, 'output_tokens', 0) or 0
        dados['tokens_entrada'] = tok_in
        dados['tokens_saida'] = tok_out
        preco_in, preco_out = _precos_modelo(modelo)
        dados['custo_usd'] = round(tok_in * preco_in / 1_000_000
                                    + tok_out * preco_out / 1_000_000, 6)
        return dados
    except Exception as e:
        app.logger.warning(f"[CLAUDE] análise falhou ({_CLAUDE_MODEL}): {e}")
        return None


# ─── TRANSCRIÇÃO DE ÁUDIO (Fase 2) — mensagens de voz do WhatsApp ─────────────
# A extensão baixa o áudio (OGG/Opus) da conversa via wa-js e manda base64.
# Aqui transcrevemos pra PT-BR e injetamos como mensagem na conversa, pra o áudio
# entrar no Score e na leitura da IA como qualquer texto.
# CORREÇÃO 12/07/2026: Groq (whisper-large-v3-turbo) agora é o provedor
# PRIMÁRIO — ~9x mais barato que a OpenAI (US$0,000667/min vs US$0,006/min),
# decisão explícita do Guilherme dado o volume (centenas de clientes/mês).
# OpenAI vira fallback só se GROQ_API_KEY não estiver configurada. Trade-off
# consciente: a OpenAI tem retenção-zero documentada oficialmente pro endpoint
# de transcrição (relevante por ser dado de saúde) — a política pública da
# Groq não confirma a mesma garantia com a mesma clareza. Sem NENHUMA chave =
# não transcreve (degrada gracioso, resto funciona). Jargão do setor melhora
# a precisão em ambos os provedores.
_WA_JARGAO_SMS = ("plano de saúde, cotação, operadora, coparticipação, carência, reajuste, MEI, "
                  "CNPJ, PME, adesão, enfermaria, apartamento, Vera Cruz, Amil, Unimed, Bradesco, "
                  "SulAmérica, Porto, Hapvida, NotreDame, Intermédica, MedSênior, Beneficência")


def _transcrever_chamar(url, headers, data, raw, ext, mime, provedor, preco_min):
    """Uma tentativa de transcrição contra um provedor específico. Retorna
    {'texto','segundos','custo_usd','provedor'}, None (áudio sem fala/vazio,
    não adianta tentar outro provedor) ou lança exceção (erro de
    rede/HTTP/rate-limit — quem chama decide se tenta o próximo provedor)."""
    import requests as _rq
    files = {'file': (f'audio.{ext}', raw, mime)}
    r = _rq.post(url, headers=headers, files=files, data=data, timeout=90)
    if r.status_code != 200:
        raise RuntimeError(f'HTTP {r.status_code}: {r.text[:200]}')
    try:
        corpo = r.json()
        texto = (corpo.get('text') or '').strip()
    except Exception:
        texto, corpo = (r.text or '').strip(), {}
    if not texto:
        return None
    segundos = float(corpo.get('duration') or 0) or None
    custo = round((segundos / 60.0) * preco_min, 6) if segundos else None
    if segundos is None:
        # HTTP 200 mas sem 'duration' no corpo — a transcrição em si
        # funcionou, mas o custo dessa análise fica subestimado no
        # painel sem a gente perceber. Não trava a análise, só avisa.
        app.logger.warning(f"[TRANSCRICAO] {provedor}: resposta 200 sem 'duration' em verbose_json — custo desse áudio não será contabilizado")
    return {'texto': texto, 'segundos': segundos, 'custo_usd': custo, 'provedor': provedor}


def _transcrever_audio(b64, mime='audio/ogg'):
    """Transcreve um áudio (base64) em PT-BR. Retorna {'texto', 'segundos',
    'custo_usd', 'provedor'} ou None (sem chave, áudio inválido, ou falha nos
    provedores configurados → degrada gracioso). Pede 'verbose_json' pra vir
    a duração real do áudio (junto com o texto), assim o custo estimado usa
    segundos de verdade em vez de chutar pelo tamanho do arquivo.
    Tenta Groq primeiro (mais barato); se a CHAMADA falhar de verdade (rate
    limit do plano grátis, erro de rede, 5xx — não só "não configurada"),
    tenta a OpenAI em seguida em vez de simplesmente perder o áudio. Nunca
    fica só na mão do provedor mais barato estar de pé no momento."""
    import base64 as _b64
    try:
        raw = _b64.b64decode(b64)
    except Exception:
        return None
    if not raw or len(raw) > 25 * 1024 * 1024:  # limite da API de transcrição
        return None
    openai_key = os.environ.get('OPENAI_API_KEY', '').strip()
    groq_key = os.environ.get('GROQ_API_KEY', '').strip()
    mime = (mime or 'audio/ogg').split(';')[0].strip()
    ext = 'ogg'
    if 'm4a' in mime or 'mp4' in mime or 'aac' in mime:
        ext = 'm4a'
    elif 'mpeg' in mime or 'mp3' in mime:
        ext = 'mp3'
    elif 'wav' in mime:
        ext = 'wav'

    tentativas = []
    if groq_key:
        tentativas.append((
            'https://api.groq.com/openai/v1/audio/transcriptions',
            {'Authorization': f'Bearer {groq_key}'},
            {'model': os.environ.get('GROQ_TRANSCRICAO_MODELO', 'whisper-large-v3-turbo'),
             'language': 'pt', 'prompt': _WA_JARGAO_SMS, 'response_format': 'verbose_json'},
            'groq', _GROQ_TRANSCRICAO_PRECO_USD_MIN,
        ))
    if openai_key:
        tentativas.append((
            'https://api.openai.com/v1/audio/transcriptions',
            {'Authorization': f'Bearer {openai_key}'},
            {'model': os.environ.get('OPENAI_TRANSCRICAO_MODELO', 'whisper-1'),
             'language': 'pt', 'prompt': _WA_JARGAO_SMS, 'response_format': 'verbose_json'},
            'openai', _OPENAI_TRANSCRICAO_PRECO_USD_MIN,
        ))
    if not tentativas:
        return None

    for i, (url, headers, data, provedor, preco_min) in enumerate(tentativas):
        try:
            return _transcrever_chamar(url, headers, data, raw, ext, mime, provedor, preco_min)
        except Exception as e:
            ultimo = (i == len(tentativas) - 1)
            nivel = app.logger.warning if ultimo else app.logger.info
            nivel(f"[TRANSCRICAO] {provedor} falhou ({e})" +
                  ('' if ultimo else ' — tentando próximo provedor'))
            if ultimo:
                return None
    return None


def _wa_transcricao_cache_buscar(conn, msg_id):
    """Devolve {'texto','segundos'} se esse áudio (pela wpp_msg_id, estável
    entre releituras da mesma conversa) já foi transcrito antes, ou None.
    NUNCA usado pra decidir se um áudio entra ou não na análise — só evita
    pagar de novo por uma transcrição que já temos. Ver _wa_chave_dedup: o
    conjunto de áudios considerados continua sendo sempre todos os que a
    extensão manda; isso só troca a CHAMADA cara por uma leitura de cache."""
    if not msg_id:
        return None
    row = conn.execute("SELECT texto, segundos FROM whatsapp_transcricoes_cache WHERE msg_id=?",
                        (msg_id,)).fetchone()
    if not row:
        return None
    return {'texto': row['texto'], 'segundos': row['segundos']}


def _wa_transcricao_cache_salvar(conn, msg_id, texto, segundos, custo_usd):
    if not msg_id or not texto:
        return
    try:
        conn.execute("""INSERT OR IGNORE INTO whatsapp_transcricoes_cache
                        (msg_id, texto, segundos, custo_usd) VALUES (?,?,?,?)""",
                     (msg_id, texto, segundos, custo_usd))
    except Exception as e:
        app.logger.warning(f"[TRANSCRICAO_CACHE] falhou ao salvar {msg_id}: {e}")


def _wa_analisar_conversa(mensagens, nome_contato='', imagens=None, documentos=None, links=None):
    """Orquestra a análise completa: extração + score oficial + diagnóstico + IA."""
    ex, flags, msgs_lead = _wa_extrair_lead(mensagens, nome_contato)
    sc = _wa_score_lead(ex, flags, mensagens, msgs_lead)

    def _montar_extracao(ex):
        return {k: ex[k] for k in ('nome', 'cidade', 'idades', 'faixa_etaria_texto', 'vidas', 'tipo_contratacao',
                                    'cnpj', 'tem_cnpj', 'plano_ativo', 'operadora_atual', 'operadora_interesse',
                                    'plano_preferido', 'cobertura_desejada', 'copart_pref',
                                    'urgencia', 'saude', 'decisor', 'objecoes')}

    extracao = _montar_extracao(ex)
    tinha_chave_claude = bool(os.environ.get('ANTHROPIC_API_KEY', '').strip())
    ia = _analisar_com_claude(mensagens, extracao, sc['score_final'], sc['faixa'], imagens=imagens, documentos=documentos, links=links)
    # Distingue "IA não configurada" (esperado, silencioso) de "estava
    # configurada mas essa chamada falhou" (rate limit, timeout, chave
    # revogada etc.) — sem isso o consultor via a seção de IA sumir sem saber
    # se era por falta de chave ou por uma falha de verdade naquela análise.
    ia_falhou = tinha_chave_claude and not ia

    # O motor de regras só lê TEXTO — não enxerga imagem/PDF. Se a IA confirmou
    # dados concretos num anexo (cotação, carteirinha), valem mais que um regex
    # tentando adivinhar por texto solto (ex: "00 a 18" virando idade 18 errada),
    # então SUBSTITUEM os campos equivalentes — não só preenchem lacuna — antes
    # de recalcular o score final com o dado correto.
    dados_anexo = (ia or {}).get('dados_extraidos_anexos') or {}
    houve_enriquecimento_ia = False
    if dados_anexo.get('idades'):
        idades_validas = [i for i in dados_anexo['idades'] if isinstance(i, int) and 0 <= i <= 99]
        if idades_validas:
            ex['idades'] = idades_validas
            ex['faixa_etaria_texto'] = []
            ex['vidas'] = len(idades_validas)
            houve_enriquecimento_ia = True
    elif dados_anexo.get('faixas_etarias'):
        # Cotação por faixa etária (sem idade exata de cada um) — guarda a
        # faixa honestamente, nunca inventa um número exato de idade.
        faixas_validas = [str(f).strip() for f in dados_anexo['faixas_etarias'] if str(f).strip()]
        if faixas_validas:
            ex['faixa_etaria_texto'] = faixas_validas
            ex['vidas'] = len(faixas_validas)
            houve_enriquecimento_ia = True
    if dados_anexo.get('vidas'):
        vidas_num = int(re.sub(r'\D', '', str(dados_anexo['vidas'])) or 0)
        if vidas_num:
            # Reconcilia em vez de sobrescrever cego: se idades/faixas (acima)
            # já derivaram um vidas diferente, fica com o maior dos dois — ambos
            # vêm do mesmo anexo, então divergência é sinal de lista parcial,
            # não de dado errado; subestimar vidas é pior pro score que superestimar.
            ex['vidas'] = max(vidas_num, ex['vidas']) if ex['vidas'] else vidas_num
            houve_enriquecimento_ia = True
    if dados_anexo.get('cidade'):
        ex['cidade'] = dados_anexo['cidade'].strip().title()
        houve_enriquecimento_ia = True
    if dados_anexo.get('cnpj'):
        cnpj_digitos = re.sub(r'\D', '', dados_anexo['cnpj'])
        if len(cnpj_digitos) == 14:
            ex['cnpj'] = cnpj_digitos
            ex['tem_cnpj'] = True
            ex['tipo_contratacao'] = 'PJ'
            houve_enriquecimento_ia = True
    if dados_anexo.get('tipo_contratacao') in ('PF', 'ADESAO', 'PJ'):
        ex['tipo_contratacao'] = dados_anexo['tipo_contratacao']
        houve_enriquecimento_ia = True
    if dados_anexo.get('operadora_interesse'):
        ex['operadora_interesse'] = _wa_canonizar_operadora(dados_anexo['operadora_interesse'])
        houve_enriquecimento_ia = True
    if dados_anexo.get('plano_preferido'):
        ex['plano_preferido'] = dados_anexo['plano_preferido'].strip()
        houve_enriquecimento_ia = True
    # DATA DE NASCIMENTO dos DOCUMENTOS (RG/CNH) = idade EXATA de cada
    # beneficiário. É a fonte mais confiável que existe — vence o regex de texto
    # (que confundia "5 anos de plano" com uma vida de 5 anos) e a cotação por
    # faixa. Quando há documento pessoal com nascimento legível, as idades vêm
    # daí; vidas fica no maior entre o que já tínhamos e o nº de documentos (não
    # encolhe se só chegou parte dos documentos).
    idades_docs = []
    for p in ((ia or {}).get('documentos_pessoas') or []):
        idade_doc = _calcular_idade((p or {}).get('nascimento') or '')
        if idade_doc is not None and 0 <= idade_doc <= 120 and idade_doc not in idades_docs:
            idades_docs.append(idade_doc)
    if idades_docs:
        ex['idades'] = idades_docs
        ex['faixa_etaria_texto'] = []
        ex['vidas'] = max(ex.get('vidas') or 0, len(idades_docs))
        houve_enriquecimento_ia = True
    # Valor da cotação: não é campo de score, só passa direto pra quem chamou
    # preencher valor_estimado/observações do lead — não mexe em ex/score.
    valor_cotacao = None
    bruto_valor = str(dados_anexo.get('valor_cotacao') or '').strip()
    if bruto_valor:
        limpo = re.sub(r'[^\d,.]', '', bruto_valor)
        # Normaliza separador: "1.234,56" (BR) e "627.00" (US) os dois viram ponto decimal.
        if ',' in limpo and '.' in limpo:
            limpo = limpo.replace('.', '').replace(',', '.')
        elif ',' in limpo:
            limpo = limpo.replace(',', '.')
        try:
            v = float(limpo)
            if 0 < v < 1_000_000:
                valor_cotacao = round(v, 2)
        except ValueError:
            pass

    # A Claude é a ÚNICA camada capaz de reconhecer "lead perdido de verdade"
    # (disse explicitamente que não quer mais, fechou com concorrente etc.) —
    # o motor de regras não tem esse estado. Promove pro fase_funil oficial só
    # nesse caso específico (não sobrescreve os outros estados, que o motor
    # de regras já cobre melhor que uma leitura narrativa).
    if ia and ia.get('fase_funil') == 'PERDIDO' and ex['fase_funil'] != 'PERDIDO':
        ex['fase_funil'] = 'PERDIDO'
        houve_enriquecimento_ia = True

    if houve_enriquecimento_ia:
        sc = _wa_score_lead(ex, flags, mensagens, msgs_lead)
        extracao = _montar_extracao(ex)

    sugestoes = _wa_proximas_acoes(ex, flags, mensagens)
    followup = _wa_followup(ex, sc['score_final'])
    descricao = _wa_descricao(ex, mensagens, msgs_lead, sc['score_final'], sc['faixa'])
    tags = list(dict.fromkeys(ex['tags'] + [sc['faixa'].upper(), ex['fase_funil']]))

    # A IA lê a conversa COMO UM TODO. Se ela diz que isto não é uma negociação
    # real (conversa interna/pessoal/desconexa), o score cai — o regex vê
    # palavras-chave, a IA vê o contexto. Só derruba, nunca sobe (o teto de
    # confiança é sempre o menor entre motor e IA).
    if ia:
        rel = ia.get('relevancia_comercial')
        # Tetos suavizados (antes 250/550/700): um julgamento 'baixa' equivocado da
        # IA derrubava um lead real pela METADE (850 -> 550), gerando score que
        # oscilava toda hora pra mesma conversa. Agora derruba menos.
        teto = {'nenhuma': 300, 'baixa': 650, 'media': 800}.get(rel)
        # DOCUMENTO pessoal enviado (RG/CNH/comprovante) = fechamento REAL, sem
        # discussão: a IA às vezes lê a conversa como 'baixa' por engano e o cap
        # matava o score de quem já está fechando. Se há documento extraído, o cap
        # não desce abaixo de 700 (é 'bom' no mínimo).
        tem_documento = bool((ia.get('documentos_pessoas') or []))
        if tem_documento and teto is not None and teto < 700:
            teto = None
        if teto is not None and sc['score_final'] > teto:
            sc['cap'] = {'valor': teto, 'motivo': f'IA: relevância comercial {rel} (conversa não é negociação real)'}
            sc['score_final'] = teto
            sc['faixa'] = ('quente' if teto >= 850 else 'bom' if teto >= 700 else
                           'medio' if teto >= 550 else 'baixo' if teto >= 350 else 'improvavel')
            tags = list(dict.fromkeys([t for t in tags if t not in ('QUENTE', 'BOM', 'MEDIO', 'BAIXO', 'IMPROVAVEL')]
                                       + [sc['faixa'].upper(), 'RELEVANCIA_' + rel.upper()]))

    docs_extraidos = _formatar_docs_extraidos((ia or {}).get('documentos_pessoas'),
                                              (ia or {}).get('dados_empresa'))
    return {'extracao': extracao, 'fase_funil': ex['fase_funil'], 'tags': tags, **sc,
            'sugestoes': sugestoes, 'followup': followup, 'descricao': descricao, 'ia': ia,
            'ia_falhou': ia_falhou, 'valor_cotacao': valor_cotacao,
            'docs_extraidos': docs_extraidos}


def _wa_auth_ok():
    """Confere a chave da extensão (header X-Extension-Key vs env WHATSAPP_EXT_KEY).
    Se a env não estiver setada, recusa tudo (fail-closed) — nunca deixa o
    endpoint aberto sem chave."""
    esperada = os.environ.get('WHATSAPP_EXT_KEY', '').strip()
    recebida = request.headers.get('X-Extension-Key', '').strip()
    return bool(esperada) and recebida == esperada


def _wa_cors(resp):
    """CORS liberado só nesses endpoints — a extensão faz o fetch pelo service
    worker (host_permissions), mas deixamos CORS pronto caso um dia chame de
    outro contexto. Sem credenciais, só a chave no header."""
    resp.headers['Access-Control-Allow-Origin'] = '*'
    resp.headers['Access-Control-Allow-Headers'] = 'Content-Type, X-Extension-Key'
    resp.headers['Access-Control-Allow-Methods'] = 'GET, POST, OPTIONS'
    return resp


@app.route('/api/whatsapp/ping', methods=['GET', 'OPTIONS'])
def api_whatsapp_ping():
    """A extensão chama isso pra validar URL + chave na tela de configuração."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    return _wa_cors(jsonify({"ok": True, "sistema": "JOB Serenus", "versao_api": 1}))


@app.route('/api/whatsapp/versao', methods=['GET', 'OPTIONS'])
def api_whatsapp_versao():
    """Diz qual é a versão mais nova da extensão (a que está no deploy). A própria
    extensão compara com a sua (chrome.runtime.getManifest().version) e, se estiver
    atrasada, mostra o aviso de atualizar. Público (sem chave) de propósito: é só um
    número de versão e o aviso precisa aparecer mesmo antes de configurar a chave."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    return _wa_cors(jsonify({"ok": True, "versao": _extensao_versao()}))


@app.route('/api/whatsapp/erro', methods=['POST', 'OPTIONS'])
def api_whatsapp_erro():
    """A extensão reporta um erro JS (window.onerror/unhandledrejection) que
    aconteceu no navegador do consultor — sem isso, um bug só chegava até nós
    se o consultor reclamasse. Best-effort: nunca deve travar a extensão."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False})), 401
    d = request.get_json(silent=True) or {}
    mensagem = (d.get('mensagem') or '')[:2000]
    if not mensagem:
        return _wa_cors(jsonify({"ok": False}))
    conn = db()
    try:
        uid = int(d.get('usuario_id')) if d.get('usuario_id') else None
    except (TypeError, ValueError):
        uid = None
    conn.execute("""INSERT INTO extensao_erros (usuario_id, versao, mensagem, stack, url, criado_em)
        VALUES (?,?,?,?,?,?)""",
        (uid, (d.get('versao') or '')[:20], mensagem, (d.get('stack') or '')[:4000],
         (d.get('url') or '')[:300], _agora_sp()))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


@app.route('/extensao/erros')
@login_required
@admin_required
def extensao_erros():
    """Painel: erros JS reportados pela extensão nos navegadores dos
    consultores — visibilidade que antes só existia se alguém reclamasse."""
    conn = db()
    cutoff = (datetime.now(TZ_SP) - timedelta(days=14)).strftime('%Y-%m-%d %H:%M:%S')
    conn.execute("DELETE FROM extensao_erros WHERE criado_em < ?", (cutoff,))
    conn.commit()
    rows = conn.execute("""SELECT e.*, u.nome usuario_nome FROM extensao_erros e
        LEFT JOIN usuarios u ON u.id=e.usuario_id ORDER BY e.criado_em DESC LIMIT 200""").fetchall()
    close_db(conn)
    return render_template('extensao_erros.html', erros=[dict(r) for r in rows])


# Seletores DOM do WhatsApp Web usados pela extensão pra ler a tela (nome do
# contato aberto etc). Ficam em BANCO, não hardcoded — quando o WhatsApp muda
# o HTML dele (acontece direto) e algo para de funcionar, dá pra corrigir
# editando aqui, na hora, sem esperar deploy nem aprovação de loja nenhuma.
# Ideia vista investigando como o WaSpeed resolve o mesmo problema (config.json
# remoto deles) — mesmo princípio, hospedado no nosso próprio servidor.
# Cada chave é uma lista de seletores CSS candidatos (a extensão tenta o
# primeiro, cai pro próximo se não achar). Cobrem TODA a leitura de tela:
# cabeçalho da conversa, balões de mensagem, imagens, container rolável.
_SELETORES_DOM_PADRAO = {
    "headerContato": ["#main header"],
    "nomeContatoComTitulo": ["span[dir=\"auto\"][title]"],
    "nomeContatoSpan": ["span[dir=\"auto\"]"],
    "mainContainer": ["#main"],
    "mensagemComData": ["#main .copyable-text[data-pre-plain-text]"],
    "textoSelecionavel": ["span.selectable-text", ".selectable-text"],
    "linkNaMensagem": ["a[href^=\"http\"]"],
    "mensagensComDataId": ["#main [data-id]"],
    "imagensDaConversa": ["#main img"],
}
# Flags de comportamento ligáveis/desligáveis sem deploy — mesma ideia das
# feature flags que a ZapVoice usa (ex.: tratamento @lid). resolver_lid liga
# a tentativa de resolver o número real por trás de um @lid (privacy do
# WhatsApp 2025); se um dia isso passar a dar problema, desliga aqui na hora.
_FLAGS_PADRAO = {
    "resolver_lid": True,
}


def _config_remota_atual(conn):
    """Lê a config remota do banco (seletores + flags), caindo pros padrões
    quando não há linha ou o JSON está inválido. Sempre mescla com o padrão
    pra nunca faltar uma chave que o código espera."""
    row = conn.execute("SELECT valor FROM extensao_config WHERE chave='config_remota'").fetchone()
    seletores, flags = dict(_SELETORES_DOM_PADRAO), dict(_FLAGS_PADRAO)
    if row and row['valor']:
        try:
            d = json.loads(row['valor'])
            seletores.update(d.get('seletores') or {})
            flags.update(d.get('flags') or {})
        except (TypeError, ValueError, json.JSONDecodeError):
            pass
    return seletores, flags


@app.route('/api/whatsapp/config-remota', methods=['GET', 'OPTIONS'])
def api_whatsapp_config_remota():
    """Seletores DOM + flags de comportamento atuais — a extensão consulta a
    cada ~15min e usa esses valores em vez dos fixos no código. Público (sem
    chave) de propósito, igual /api/whatsapp/versao."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    conn = db()
    seletores, flags = _config_remota_atual(conn)
    close_db(conn)
    return _wa_cors(jsonify({"ok": True, "seletores": seletores, "flags": flags}))


@app.route('/extensao/config-remota', methods=['GET', 'POST'])
@login_required
@admin_required
def extensao_config_remota():
    """Edição direta da config remota (seletores DOM + flags) — pra corrigir na
    hora quando o WhatsApp muda o HTML e algo da extensão para de achar o
    elemento certo, ou pra ligar/desligar um comportamento (ex.: resolver @lid)."""
    conn = db()
    if request.method == 'POST':
        bruto = request.form.get('json', '').strip()
        try:
            parsed = json.loads(bruto)
            if not isinstance(parsed, dict) or 'seletores' not in parsed:
                raise ValueError("O JSON precisa ter a chave 'seletores' (e opcionalmente 'flags').")
        except (TypeError, ValueError, json.JSONDecodeError) as e:
            flash(f'JSON inválido: {e}')
            close_db(conn)
            return redirect(url_for('extensao_config_remota'))
        if DB_MODE == 'postgres':
            conn.execute("""INSERT INTO extensao_config (chave, valor, atualizado_em) VALUES ('config_remota', %s, %s)
                ON CONFLICT (chave) DO UPDATE SET valor=excluded.valor, atualizado_em=excluded.atualizado_em""",
                (bruto, _agora_sp()))
        else:
            conn.execute("INSERT OR REPLACE INTO extensao_config (chave, valor, atualizado_em) VALUES ('config_remota', ?, ?)",
                (bruto, _agora_sp()))
        conn.commit(); close_db(conn)
        flash('Config salva.')
        return redirect(url_for('extensao_config_remota'))
    row = conn.execute("SELECT valor, atualizado_em FROM extensao_config WHERE chave='config_remota'").fetchone()
    seletores, flags = _config_remota_atual(conn)
    close_db(conn)
    valor = row['valor'] if row and row['valor'] else json.dumps(
        {"seletores": seletores, "flags": flags}, indent=2, ensure_ascii=False)
    return render_template('extensao_config_remota.html', valor=valor,
                            atualizado_em=row['atualizado_em'] if row else None)


# Versão mínima da extensão pra PARTICIPAR do disparo com tudo (detectar resposta,
# auto-funil, popup de número). Abaixo disso ela até manda o "bom dia" (a fila é
# antiga), mas NÃO detecta resposta — quebra o "só continua com quem responde".
_EXT_VERSAO_MIN_DISPARO = '2.21.0'


def _cmp_versao(a, b):
    pa = [int(x) if x.isdigit() else 0 for x in str(a or '0').split('.')]
    pb = [int(x) if x.isdigit() else 0 for x in str(b or '0').split('.')]
    for i in range(max(len(pa), len(pb))):
        d = (pa[i] if i < len(pa) else 0) - (pb[i] if i < len(pb) else 0)
        if d:
            return -1 if d < 0 else 1
    return 0


@app.route('/api/whatsapp/presenca', methods=['POST', 'OPTIONS'])
def api_whatsapp_presenca():
    """A extensão bate ponto (a cada ~1min): informa versão, número do WhatsApp
    logado e se a wa-js está pronta. Alimenta o painel de aptidão do disparo."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False}))
    d = request.json or {}
    try:
        uid = int(d.get('usuario_id'))
    except (TypeError, ValueError):
        return _wa_cors(jsonify({"ok": False}))
    versao = str(d.get('versao') or '')[:20]
    numero = str(d.get('numero') or '')[:30]
    wpp_ok = 1 if d.get('wpp_ok') else 0
    agora = _agora_sp()
    conn = db()
    if DB_MODE == 'postgres':
        conn.execute("""INSERT INTO consultor_wpp_status (usuario_id, versao, numero, wpp_ok, visto_em)
            VALUES (%s,%s,%s,%s,%s) ON CONFLICT (usuario_id) DO UPDATE SET
            versao=excluded.versao, numero=excluded.numero, wpp_ok=excluded.wpp_ok, visto_em=excluded.visto_em""",
            (uid, versao, numero, wpp_ok, agora))
    else:
        conn.execute("""INSERT OR REPLACE INTO consultor_wpp_status (usuario_id, versao, numero, wpp_ok, visto_em)
            VALUES (?,?,?,?,?)""", (uid, versao, numero, wpp_ok, agora))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


@app.route('/api/whatsapp/inbox', methods=['GET', 'OPTIONS'])
def api_whatsapp_inbox():
    """Últimos 5 leads que CHEGARAM na coluna 'Lead Novo' (Kanban) deste consultor
    e ainda não foram atendidos — pra caixa de entrada na barra da extensão. É uma
    JANELA das 5 chegadas mais recentes (não os mais antigos da história); dentro
    dela, o mais parado esperando fica no topo. Só leitura, chave da extensão."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave inválida"})), 401
    uid = request.args.get('usuario_id', type=int)
    if not uid:
        return _wa_cors(jsonify({"ok": True, "leads": []}))
    conn = db()
    rows = conn.execute("""SELECT * FROM (
        SELECT id, nome, telefone, telefone_norm, criado_em, trafego
        FROM crm_leads
        WHERE responsavel_id=? AND atendido_em IS NULL
          AND etapa='lead_novo'
          AND COALESCE(telefone_norm,'')<>''
        ORDER BY criado_em DESC LIMIT 5
    ) x ORDER BY criado_em ASC""", (uid,)).fetchall()
    leads = [{"id": r['id'], "nome": r['nome'] or 'Lead', "telefone": r['telefone'] or r['telefone_norm'],
              "chat_id": _wa_chat_id(r['telefone_norm'] or r['telefone'] or ''),
              "criado_em": str(r['criado_em'] or ''), "pago": (r['trafego'] == 'Pago')}
             for r in rows]
    close_db(conn)
    return _wa_cors(jsonify({"ok": True, "leads": leads}))


@app.route('/api/whatsapp/inbox/atender', methods=['POST', 'OPTIONS'])
def api_whatsapp_inbox_atender():
    """'Atender agora' de verdade: dispara o funil de atendimento do consultor
    pro lead (com {nome} do CRM e {saudacao} pela hora certa) — não só marca
    como atendido. Sem funil configurado, ainda marca atendido (não trava o
    consultor) mas avisa que precisa configurar."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave inválida"})), 401
    d = request.json or {}
    lead_id = d.get('lead_id')
    try:
        usuario_id = int(d.get('usuario_id'))
    except (TypeError, ValueError):
        usuario_id = None
    if not lead_id:
        return _wa_cors(jsonify({"ok": False, "erro": "lead_id"})), 400
    conn = db()
    if usuario_id:
        resultado = _lead_atender_com_funil(conn, lead_id, usuario_id)
        if not resultado.get('ok'):
            # Sem funil/passos/telefone: ainda marca atendido (o consultor já
            # decidiu abrir a conversa) mas não inventa mensagem nenhuma.
            conn.execute("UPDATE crm_leads SET atendido_em=? WHERE id=? AND atendido_em IS NULL", (_agora_sp(), lead_id))
            conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                         (lead_id, 'Extensão WhatsApp', 'atendimento', 'Lead atendido pelo inbox da extensão (sem funil disparado: ' + str(resultado.get('erro')) + ').', _agora_sp()))
            conn.commit(); close_db(conn)
            return _wa_cors(jsonify(resultado))
        conn.commit(); close_db(conn)
        return _wa_cors(jsonify(resultado))
    conn.execute("UPDATE crm_leads SET atendido_em=? WHERE id=? AND atendido_em IS NULL", (_agora_sp(), lead_id))
    conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                 (lead_id, 'Extensão WhatsApp', 'atendimento', 'Lead atendido pelo inbox da extensão.', _agora_sp()))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


def _consultores_presenca(conn):
    """Aptidão de cada consultor ativo pro disparo: online (bateu ponto < 3min),
    versão OK (>= mínima), WhatsApp conectado. 'apto' = os três verdes."""
    stt = {r['usuario_id']: dict(r) for r in
           conn.execute("SELECT usuario_id, versao, numero, wpp_ok, visto_em FROM consultor_wpp_status").fetchall()}
    ver_atual = _extensao_versao()
    out = []
    for u in _campanha_consultores_ativos(conn):
        s = stt.get(u['id'])
        online = False
        if s and s.get('visto_em'):
            seg = _wa_segundos_desde(s['visto_em'])
            online = (seg is not None and seg < 180)
        versao = (s or {}).get('versao') or ''
        versao_ok = bool(versao) and _cmp_versao(versao, _EXT_VERSAO_MIN_DISPARO) >= 0
        atualizada = bool(versao) and _cmp_versao(versao, ver_atual) >= 0
        wpp_ok = bool((s or {}).get('wpp_ok'))
        out.append({
            'id': u['id'], 'nome': u['nome'],
            'online': online, 'versao': versao, 'versao_ok': versao_ok, 'atualizada': atualizada,
            'numero': (s or {}).get('numero') or '', 'wpp_ok': wpp_ok,
            'apto': bool(online and versao_ok and wpp_ok),
        })
    return out


