@app.route('/api/whatsapp/estado', methods=['GET', 'OPTIONS'])
def api_whatsapp_estado():
    """A extensão consulta ANTES de raspar a conversa: se já existe uma análise
    anterior pra esse telefone, devolve a hora da última mensagem conhecida
    (pra ler só o histórico novo, não o passado inteiro de novo) E um retrato
    COMPLETO da última análise — score, dados extraídos, leitura da IA em
    imagens/PDFs, sinais de atenção, próximas ações — pra o painel reabrir
    exatamente como ficou, mesmo depois de fechar e reabrir o Chrome, já que
    a extensão só guarda análises rodadas na sessão atual em memória (Map, não
    storage). Antes essa rota só devolvia score/faixa/resumo curto — o resto
    (sugestoes_json) já estava salvo no banco desde sempre, só não voltava."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    tel_norm = _normalizar_telefone(str(request.args.get('telefone') or ''))
    if not tel_norm:
        return _wa_cors(jsonify({"ok": True, "existe": False}))
    conn = db()
    row = conn.execute("""SELECT wa.id, wa.conversa_json, wa.score, wa.score_faixa, wa.resumo, wa.criado_em,
        wa.lead_id, wa.sugestoes_json, wa.duracao_segundos, l.nome AS lead_nome,
        l.responsavel_id AS lead_responsavel_id, ur.nome AS lead_responsavel_nome
        FROM whatsapp_analises wa LEFT JOIN crm_leads l ON l.id = wa.lead_id
        LEFT JOIN usuarios ur ON ur.id = l.responsavel_id
        WHERE wa.telefone_norm=? ORDER BY wa.id DESC LIMIT 1""", (tel_norm,)).fetchone()
    close_db(conn)
    if not row:
        return _wa_cors(jsonify({"ok": True, "existe": False}))
    row = dict(row)
    try:
        msgs = json.loads(row['conversa_json'] or '[]')
    except Exception:
        msgs = []
    if not msgs:
        return _wa_cors(jsonify({"ok": True, "existe": False}))
    try:
        diagnostico = json.loads(row['sugestoes_json'] or '{}')
    except Exception:
        diagnostico = {}
    return _wa_cors(jsonify({
        "ok": True, "existe": True, "ultima_hora": msgs[-1].get('hora'),
        "total_mensagens": len(msgs),
        "ultima_analise": {
            "id": row['id'], "score": row['score'], "score_bruto": diagnostico.get('score_bruto'),
            "faixa": row['score_faixa'], "fase_funil": diagnostico.get('fase_funil'),
            "tags": diagnostico.get('tags'), "extracao": diagnostico.get('extracao'),
            "breakdown": diagnostico.get('breakdown'),
            "categorias_consideradas": diagnostico.get('categorias_consideradas'),
            "categorias_totais": diagnostico.get('categorias_totais'),
            "penalidades": diagnostico.get('penalidades'), "cap": diagnostico.get('cap'),
            "sugestoes": diagnostico.get('sugestoes'), "followup": diagnostico.get('followup'),
            "resumo": row['resumo'], "ia": diagnostico.get('ia'),
            "docs_extraidos": diagnostico.get('docs_extraidos') or '',
            "transcricoes": diagnostico.get('transcricoes'),
            "duracao_segundos": row['duracao_segundos'],
            "criado_em": row['criado_em'], "lead_id": row['lead_id'],
            "lead": ({"id": row['lead_id'], "nome": row['lead_nome'],
                      "url": f"{_SITE_BASE_URL}/crm?lead={row['lead_id']}"} if row['lead_id'] else None),
            "lead_responsavel_id": row['lead_responsavel_id'],
            "lead_responsavel_nome": row['lead_responsavel_nome'],
            "lead_criado": False,
            "conversa_url": f"{_SITE_BASE_URL}/whatsapp-analises/{row['id']}/conversa",
        },
    }))


# ─── FILA DE ENVIO DA EXTENSÃO (Fase 1 — envio avulso de texto) ──────────────
# A extensão só consegue mandar mensagem de verdade enquanto o Chrome do
# consultor estiver aberto com o WhatsApp Web carregado (não é um gateway
# sempre ligado como o WaSpeed) — por isso o envio é assíncrono: o CRM
# enfileira, a extensão consulta periodicamente ("puxa" o trabalho, mesmo
# padrão do _importar_leads_automatico) e confirma depois de mandar.
_WA_FILA_GATE_SEGUNDOS = int(os.environ.get('WA_FILA_GATE_SEGUNDOS', '12'))
_WA_FILA_GATE_MAX = int(os.environ.get('WA_FILA_GATE_MAX', '45'))
_WA_FILA_RECLAIM_MINUTOS = 3
_WA_FILA_MAX_TENTATIVAS = 3


def _wa_gate_atual():
    """Intervalo mínimo ATÉ o próximo envio do mesmo consultor — sorteado a cada
    consulta entre GATE e GATE_MAX. Aleatório de propósito: envio de X em X segundos
    cravado é padrão de robô e queima número; intervalo quebrado parece humano."""
    import random as _rnd
    lo, hi = _WA_FILA_GATE_SEGUNDOS, max(_WA_FILA_GATE_SEGUNDOS, _WA_FILA_GATE_MAX)
    return _rnd.uniform(lo, hi)


def _wa_chat_id(telefone):
    """'55DDDNUMERO@c.us' — formato que a wa-js espera pra endereçar o chat.
    Reaproveita a mesma normalização já usada pro WaSpeed (garante '55')."""
    fone = _waspeed_normaliza_fone(telefone)
    return f"{fone}@c.us" if fone else ''


def _wa_segundos_desde(valor):
    """Segundos desde um timestamp do banco (PG datetime ou string SQLite),
    lidando com naive/aware igual _data_expirada. None se valor vazio/inválido."""
    dt = _parse_dt_seguro(valor)
    if not dt:
        return None
    agora = datetime.now(TZ_SP)
    if dt.tzinfo is None:
        agora = agora.replace(tzinfo=None)
    return (agora - dt).total_seconds()


@app.route('/crm/lead/<int:lid>/whatsapp-extensao/enfileirar', methods=['POST'])
@login_required
def crm_lead_whatsapp_extensao_enfileirar(lid):
    """Coloca uma mensagem de texto na fila pra extensão mandar assim que o
    WhatsApp Web daquele consultor estiver aberto. Nunca envia na hora."""
    conn = db()
    lead = conn.execute("SELECT id, telefone, responsavel_id FROM crm_leads WHERE id=?", (lid,)).fetchone()
    if not lead:
        close_db(conn); return jsonify({"ok": False, "erro": "Lead não encontrado"}), 404
    ld = dict(lead)
    if session.get('perfil') != 'admin' and ld['responsavel_id'] != session.get('user_id'):
        close_db(conn); return jsonify({"ok": False, "erro": "Sem permissão"}), 403
    if not ld['responsavel_id']:
        close_db(conn); return jsonify({"ok": False, "erro": "Lead sem responsável definido — defina antes de mandar mensagem"}), 400
    texto = (request.json or {}).get('texto', '').strip()[:4000]
    if not texto:
        close_db(conn); return jsonify({"ok": False, "erro": "Mensagem vazia"}), 400
    chat_id = _wa_chat_id(ld.get('telefone'))
    if not chat_id:
        close_db(conn); return jsonify({"ok": False, "erro": "Lead sem telefone válido"}), 400
    conn.execute("""INSERT INTO whatsapp_extensao_fila
        (lead_id, responsavel_id, telefone, chat_id, tipo, texto, origem, criado_por)
        VALUES (?,?,?,?,'texto',?,'crm_lead',?)""",
        (lid, ld['responsavel_id'], ld['telefone'], chat_id, texto, session.get('user_id')))
    fila_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
               else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "id": fila_id, "status": "pendente"})


@app.route('/crm/lead/<int:lid>/whatsapp-extensao/status', methods=['GET'])
@login_required
def crm_lead_whatsapp_extensao_status(lid):
    """Polling leve pro front saber se um item da fila já foi enviado."""
    fila_id = request.args.get('fila_id', type=int)
    if not fila_id:
        return jsonify({"ok": False, "erro": "fila_id obrigatório"}), 400
    conn = db()
    item = conn.execute("SELECT id, lead_id, status, erro FROM whatsapp_extensao_fila WHERE id=?", (fila_id,)).fetchone()
    close_db(conn)
    if not item or item['lead_id'] != lid:
        return jsonify({"ok": False, "erro": "Não encontrado"}), 404
    return jsonify({"ok": True, "status": item['status'], "erro": item['erro']})


@app.route('/api/whatsapp/fila/proximo', methods=['GET', 'OPTIONS'])
def api_whatsapp_fila_proximo():
    """A extensão consulta isso periodicamente perguntando se tem algo pra
    mandar. Claim atômico (mesmo padrão de _processar_fluxos_pendentes) pra
    nunca deixar duas abas do mesmo consultor pegarem o mesmo item. O limite
    de ritmo mora AQUI (servidor), não no client — nunca libera item novo
    pro mesmo responsavel_id antes de _WA_FILA_GATE_SEGUNDOS do último envio."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    usuario_id = request.args.get('usuario_id', type=int)
    if not usuario_id:
        return _wa_cors(jsonify({"ok": True, "item": None}))
    conn = db()
    ultimo = conn.execute("""SELECT MAX(enviado_em) m FROM whatsapp_extensao_fila
        WHERE responsavel_id=? AND status='enviado'""", (usuario_id,)).fetchone()
    if ultimo and ultimo['m']:
        decorrido = _wa_segundos_desde(ultimo['m'])
        if decorrido is not None and decorrido < _wa_gate_atual():
            close_db(conn)
            return _wa_cors(jsonify({"ok": True, "item": None}))
    agora = datetime.now(TZ_SP)
    agora_txt = agora.strftime('%Y-%m-%d %H:%M:%S')
    cutoff_reclaim = (agora - timedelta(minutes=_WA_FILA_RECLAIM_MINUTOS)).strftime('%Y-%m-%d %H:%M:%S')
    # liberar_em segura o item até a hora (delay proposital do auto-funil). Item
    # sem liberar_em (envio normal/opener) sai na hora.
    candidato = conn.execute("""
        SELECT id FROM whatsapp_extensao_fila
        WHERE responsavel_id=? AND (
            status='pendente' OR (status='enviando' AND claim_em < ?)
        ) AND (liberar_em IS NULL OR CAST(liberar_em AS TEXT) <= ?)
        ORDER BY criado_em ASC LIMIT 1
    """, (usuario_id, cutoff_reclaim, agora_txt)).fetchone()
    if not candidato:
        close_db(conn)
        return _wa_cors(jsonify({"ok": True, "item": None}))
    claim = conn.execute("""UPDATE whatsapp_extensao_fila SET status='enviando', claim_em=?
        WHERE id=? AND status IN ('pendente','enviando')""",
        (agora.strftime('%Y-%m-%d %H:%M:%S'), candidato['id']))
    if getattr(claim, 'rowcount', 1) == 0:
        conn.rollback(); close_db(conn)
        return _wa_cors(jsonify({"ok": True, "item": None}))
    conn.commit()
    item = conn.execute("SELECT * FROM whatsapp_extensao_fila WHERE id=?", (candidato['id'],)).fetchone()
    close_db(conn)
    if not item:
        return _wa_cors(jsonify({"ok": True, "item": None}))
    it = dict(item)
    midia_url = (f"{_SITE_BASE_URL}/crm/modelos/midia/{it['midia_arquivo']}"
                 if it.get('midia_arquivo') else None)
    return _wa_cors(jsonify({"ok": True, "item": {
        "id": it['id'], "chat_id": it['chat_id'], "tipo": it['tipo'], "texto": it['texto'],
        "midia_url": midia_url, "origem": it.get('origem') or '',
    }}))


@app.route('/api/whatsapp/fila/<int:fid>/confirmar', methods=['POST', 'OPTIONS'])
def api_whatsapp_fila_confirmar(fid):
    """A extensão chama depois de tentar mandar (sucesso ou falha). Sucesso
    grava em crm_atividades igual o botão de 1 clique já faz. Falha reenfileira
    até 3 tentativas, depois marca 'falhou' de vez (não fica tentando pra sempre)."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    d = request.json or {}
    conn = db()
    item = conn.execute("SELECT * FROM whatsapp_extensao_fila WHERE id=?", (fid,)).fetchone()
    if not item:
        close_db(conn); return _wa_cors(jsonify({"ok": False, "erro": "Não encontrado"})), 404
    it = dict(item)
    if bool(d.get('ok')):
        conn.execute("""UPDATE whatsapp_extensao_fila SET status='enviado', enviado_em=?, wpp_msg_id=? WHERE id=?""",
                     (_agora_sp(), str(d.get('wpp_msg_id') or '')[:100], fid))
        if it.get('origem') == 'campanha':
            conn.execute("UPDATE campanha_contato SET status='enviado', enviado_em=? WHERE fila_id=?",
                         (_agora_sp(), fid))
        if it['lead_id']:
            conn.execute("""INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em)
                            VALUES (?,?,?,?,?)""",
                         (it['lead_id'], 'Extensão WhatsApp', 'whatsapp',
                          f"WhatsApp enviado via extensão: {it['texto'][:200]}", _agora_sp()))
    else:
        tentativas = it['tentativas'] + 1
        erro = str(d.get('erro') or 'Falha ao enviar')[:300]
        if tentativas >= _WA_FILA_MAX_TENTATIVAS:
            conn.execute("UPDATE whatsapp_extensao_fila SET status='falhou', tentativas=?, erro=? WHERE id=?",
                         (tentativas, erro, fid))
        else:
            conn.execute("UPDATE whatsapp_extensao_fila SET status='pendente', tentativas=?, erro=? WHERE id=?",
                         (tentativas, erro, fid))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


@app.route('/api/whatsapp/chat-lead', methods=['GET', 'OPTIONS'])
def api_whatsapp_chat_lead():
    """A extensão pergunta ANTES de mostrar o popup manual: 'esse chat_id já tem
    telefone/nome conhecido?'. Memória fica NO SERVIDOR (não no navegador de um
    consultor só) — uma vez que QUALQUER consultor informou o número dessa
    conversa, ninguém mais precisa digitar de novo, mesmo trocando de PC."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave inválida"})), 401
    chat_id = (request.args.get('chat_id') or '').strip()[:100]
    if not chat_id:
        return _wa_cors(jsonify({"ok": True, "achou": False}))
    conn = db()
    r = conn.execute("SELECT lead_id, telefone, telefone_norm, nome FROM wa_chat_lead WHERE chat_id=?", (chat_id,)).fetchone()
    close_db(conn)
    if not r or not (r['telefone'] or r['telefone_norm']):
        return _wa_cors(jsonify({"ok": True, "achou": False}))
    return _wa_cors(jsonify({"ok": True, "achou": True, "telefone": r['telefone'] or r['telefone_norm'],
                             "nome": r['nome'] or '', "lead_id": r['lead_id']}))


@app.route('/api/whatsapp/enviar-direto', methods=['POST', 'OPTIONS'])
def api_whatsapp_enviar_direto():
    """Enfileira uma mensagem direto da conversa aberta no WhatsApp Web — pedido
    explícito do Guilherme pra extensão funcionar inteira ali, sem precisar
    abrir o site do JOB (igual WaSpeed/ZapVoice). Autenticado por chave de
    extensão (não sessão de login), casa ou cria o lead pelo telefone (mesma
    lógica de _wa_auth_ok/casamento usada em /api/whatsapp/analisar).
    responsavel_id da fila é SEMPRE o usuario_id de quem está usando a
    extensão agora — é o WhatsApp Web dessa pessoa que vai executar o envio,
    então tem que bater com o que /fila/proximo vai filtrar depois."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    d = request.json or {}
    telefone = str(d.get('telefone') or '').strip()
    nome = str(d.get('nome') or '').strip()[:200]
    texto = str(d.get('texto') or '').strip()[:4000]
    # Texto pode ser vazio SE for um modelo de mídia (áudio/imagem sem legenda) —
    # a validação de "mensagem vazia" pra texto puro acontece depois de resolver
    # o modelo (senão áudio/nota de voz sem legenda era barrado como vazio).
    tem_modelo = bool(str(d.get('modelo_id') or '').strip())
    if not texto and not tem_modelo:
        return _wa_cors(jsonify({"ok": False, "erro": "Mensagem vazia"})), 400
    # chat_id explícito (id serializado da conversa aberta, via wa-js) é o
    # caminho à prova de falha — funciona pra contato salvo e @lid, onde o
    # telefone não é lido. Se não veio, cai pro cálculo pelo telefone.
    chat_id = str(d.get('chat_id') or '').strip()[:100]
    if not chat_id:
        chat_id = _wa_chat_id(telefone)
    if not chat_id:
        return _wa_cors(jsonify({"ok": False, "erro": "Não consegui identificar a conversa (abra a conversa e tente de novo)"})), 400
    # Se o telefone não veio mas o chat_id é de contato normal (55...@c.us),
    # extrai os dígitos pra ainda tentar casar o lead.
    if not telefone and chat_id.endswith('@c.us'):
        telefone = chat_id.split('@')[0]
    usuario_id = None
    try:
        usuario_id = int(d.get('usuario_id'))
    except (TypeError, ValueError):
        pass
    conn = db()
    if usuario_id:
        u = conn.execute("SELECT id FROM usuarios WHERE id=? AND ativo=1", (usuario_id,)).fetchone()
        if not u:
            usuario_id = None
    if not usuario_id:
        close_db(conn)
        return _wa_cors(jsonify({"ok": False, "erro": "Selecione seu usuário no popup da extensão antes de mandar mensagem"})), 400

    _sem_numero_reportar = False
    tel_norm = _normalizar_telefone(telefone)
    lead = _buscar_lead_por_telefone(conn, tel_norm)
    if not lead and nome:
        # Casa por NOME (contatos @lid, sem número exposto). REAPROVEITA um lead que
        # já existe em vez de criar outro a cada envio — pega o melhor: do consultor
        # atual, de preferência já COM número, senão o mais antigo. Antes só casava
        # se houvesse exatamente um -> com duplicados ele desistia e criava mais um.
        cands = conn.execute(
            "SELECT id, nome, responsavel_id, telefone_norm FROM crm_leads WHERE LOWER(TRIM(nome))=?",
            (nome.strip().lower(),)).fetchall()
        if cands:
            meus = [c for c in cands if c['responsavel_id'] == usuario_id] or list(cands)
            meus.sort(key=lambda c: (0 if (c['telefone_norm'] or '').strip() else 1, c['id']))
            lead = meus[0]
    lead_id = lead['id'] if lead else None
    # Lead já existe e é de OUTRO consultor: não trava nada — a mensagem sai igual
    # e a atividade é registrada do mesmo jeito — só avisa os dois (quem está
    # conversando agora e o dono do lead no JOB), pra não passar batido.
    dono_diferente_id = lead['responsavel_id'] if (lead and lead['responsavel_id'] and lead['responsavel_id'] != usuario_id) else None
    nome_lead_atual = (lead['nome'] if lead else '') or nome or 'Lead'
    # Casou um lead sem número e AGORA temos: completa (deixa de ser órfão).
    if lead_id and tel_norm:
        conn.execute("""UPDATE crm_leads SET telefone=COALESCE(NULLIF(telefone,''),?),
            telefone_norm=COALESCE(NULLIF(telefone_norm,''),?) WHERE id=?""",
            (telefone, tel_norm, lead_id))
    if not lead_id and (tel_norm or nome):
        # Cria UMA vez. A partir daqui os próximos envios casam por número (se houver)
        # ou por nome (reaproveita) — não duplica mais. Sem número, avisa os admins.
        conn.execute("""INSERT INTO crm_leads
            (nome, telefone, telefone_norm, origem, etapa, responsavel_id, observacoes, criado_em)
            VALUES (?,?,?,?,?,?,?,?)""",
            (nome or telefone or 'Lead WhatsApp', telefone, tel_norm, 'WhatsApp (extensão)',
             'lead_novo', usuario_id, 'Criado automaticamente ao mandar mensagem pela extensão.', _agora_sp()))
        lead_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                   else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
        conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                     (lead_id, 'Extensão WhatsApp', 'criacao',
                      'Lead criado automaticamente ao mandar mensagem pela extensão.', _agora_sp()))
        if not tel_norm:
            _sem_numero_reportar = True  # nasceu sem número — pedir pra alguém completar

    # Se veio de um modelo salvo com MÍDIA (áudio/imagem), a fila manda a mídia
    # (item A) — texto vira legenda. Sem mídia, é texto puro como antes.
    tipo, midia_arquivo = 'texto', None
    modelo_id = None
    try:
        modelo_id = int(d.get('modelo_id'))
    except (TypeError, ValueError):
        modelo_id = None
    if modelo_id:
        mod = conn.execute("SELECT midia_arquivo, midia_tipo FROM modelos_conteudo WHERE id=? AND tipo='whatsapp'", (modelo_id,)).fetchone()
        if mod and mod['midia_arquivo'] and mod['midia_tipo'] in ('audio', 'imagem', 'video', 'documento'):
            tipo, midia_arquivo = mod['midia_tipo'], mod['midia_arquivo']
    # Agora sim: se acabou sendo texto puro (sem mídia) e o texto está vazio, barra.
    if tipo == 'texto' and not texto:
        close_db(conn)
        return _wa_cors(jsonify({"ok": False, "erro": "Mensagem vazia"})), 400
    conn.execute("""INSERT INTO whatsapp_extensao_fila
        (lead_id, responsavel_id, telefone, chat_id, tipo, texto, midia_arquivo, origem, criado_por)
        VALUES (?,?,?,?,?,?,?,'extensao_direto',?)""",
        (lead_id, usuario_id, telefone, chat_id, tipo, texto, midia_arquivo, usuario_id))
    fila_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
               else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    # Contabiliza uso do modelo (pra "mais usadas" na biblioteca).
    if modelo_id:
        conn.execute("UPDATE modelos_conteudo SET vezes_usado = COALESCE(vezes_usado,0) + 1 WHERE id=? AND tipo='whatsapp'", (modelo_id,))
    # Guarda chat_id -> lead/telefone/nome NO SERVIDOR (não só no navegador do
    # consultor) — assim, na próxima vez que QUALQUER extensão perguntar por essa
    # conversa, o JOB já responde sem precisar abrir o popup de novo.
    if chat_id and (lead_id or telefone or nome):
        if DB_MODE == 'postgres':
            conn.execute("""INSERT INTO wa_chat_lead (chat_id, lead_id, telefone, telefone_norm, nome, atualizado_em)
                VALUES (%s,%s,%s,%s,%s,%s) ON CONFLICT (chat_id) DO UPDATE SET
                lead_id=excluded.lead_id, telefone=excluded.telefone, telefone_norm=excluded.telefone_norm,
                nome=excluded.nome, atualizado_em=excluded.atualizado_em""",
                (chat_id, lead_id, telefone, tel_norm, nome, _agora_sp()))
        else:
            conn.execute("""INSERT OR REPLACE INTO wa_chat_lead (chat_id, lead_id, telefone, telefone_norm, nome, atualizado_em)
                VALUES (?,?,?,?,?,?)""", (chat_id, lead_id, telefone, tel_norm, nome, _agora_sp()))
    conn.commit(); close_db(conn)
    if _sem_numero_reportar:
        # Reporta 1x pros admins: contato sem número exposto, ninguém foi cadastrado.
        try:
            _notificar_admins('lead_sem_numero', 'Contato de WhatsApp sem número',
                f'{nome or "Contato"} recebeu mensagem pela extensão, mas o WhatsApp não expôs o número '
                '(conta business/privacidade). O lead NÃO foi cadastrado — peça o número ao cliente.', '/crm')
        except Exception:
            pass
    if dono_diferente_id and lead_id:
        # Throttle: não avisa de novo se já avisou nos últimos 30min pra esse
        # par lead+consultor (conversa ativa não pode virar spam de notificação).
        try:
            conn2 = db()
            cutoff = (datetime.now(TZ_SP) - timedelta(minutes=30)).strftime('%Y-%m-%d %H:%M:%S')
            ja_avisou = conn2.execute("""SELECT 1 FROM notificacoes WHERE tipo='lead_outro_consultor'
                AND link=? AND criado_em>? LIMIT 1""", (f'/crm/lead/{lead_id}', cutoff)).fetchone()
            if not ja_avisou:
                quem_conversa = conn2.execute("SELECT nome FROM usuarios WHERE id=?", (usuario_id,)).fetchone()
                quem_conversa_nome = quem_conversa['nome'] if quem_conversa else 'Um consultor'
                dono_nome_row = conn2.execute("SELECT nome FROM usuarios WHERE id=?", (dono_diferente_id,)).fetchone()
                dono_nome = dono_nome_row['nome'] if dono_nome_row else 'outro consultor'
                _notificar(dono_diferente_id, 'lead_outro_consultor', 'Seu lead está sendo atendido por outro consultor',
                           f'{quem_conversa_nome} está conversando com {nome_lead_atual} no WhatsApp — esse lead é seu no JOB.',
                           f'/crm/lead/{lead_id}')
                _notificar(usuario_id, 'lead_outro_consultor', 'Esse lead já é de outro consultor',
                           f'{nome_lead_atual} já é atendido por {dono_nome} no JOB. Sua mensagem foi enviada normalmente — '
                           'combine com ele antes de seguir a conversa.', f'/crm/lead/{lead_id}')
            close_db(conn2)
        except Exception:
            pass
    return _wa_cors(jsonify({"ok": True, "id": fila_id, "lead_id": lead_id,
                             "precisa_numero": _sem_numero_reportar,
                             "dono_diferente": bool(dono_diferente_id)}))


@app.route('/api/whatsapp/extensao/modelos', methods=['GET', 'OPTIONS'])
def api_whatsapp_extensao_modelos():
    """Lista os modelos de mensagem de WhatsApp ativos pra extensão mostrar na
    seção Mensagens do painel. Monta a URL de mídia pronta pra extensão não
    precisar saber o padrão de rota.

    Com ?usuario_id=N, devolve só a pasta DAQUELE consultor (dono_consultor_id=N)
    + itens de pasta compartilhada/sem pasta (dono_consultor_id NULL = material
    da corretora, visível a todos). Pedido do Guilherme: cada consultora vê os
    áudios da própria voz + o material compartilhado, não a biblioteca de todo
    mundo — filtra por dono_consultor_id (organização por pasta), não mais por
    criado_por (que só registrava quem CADASTROU, sem relação com de quem é o
    conteúdo — os 641 modelos importados em massa tinham todos criado_por do
    admin que rodou a importação). ATENÇÃO: isso é organização, NÃO segurança —
    a chave da extensão é única/compartilhada, então qualquer portador dela
    pode pedir o usuario_id que quiser. Segurança real = chave por usuário
    (item futuro)."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    try:
        uid = int(request.args.get('usuario_id') or 0)
    except (TypeError, ValueError):
        uid = 0
    conn = db()
    # Gestor (admin/supervisor/gestor_vendedor) enxerga a biblioteca de TODO
    # mundo, organizada por dono — pra supervisionar. Consultor continua vendo
    # só a pasta dele + o compartilhado. Pedido do Guilherme: "eu como gestor
    # quero ter acesso às mensagens e funis de todos, em pasta, organizado".
    perfil = None
    if uid:
        prow = conn.execute("SELECT perfil FROM usuarios WHERE id=?", (uid,)).fetchone()
        perfil = prow['perfil'] if prow else None
    eh_gestor = perfil in ('admin', 'supervisor', 'gestor_vendedor')
    where = "m.tipo='whatsapp' AND m.ativo=1"
    params = []
    if uid and not eh_gestor:
        where += " AND (m.dono_consultor_id = ? OR m.dono_consultor_id IS NULL)"
        params.append(uid)
    rows = conn.execute(f"""SELECT m.id, m.nome, m.corpo_texto, m.variante, m.midia_arquivo, m.midia_tipo,
        m.categoria, m.favorito, m.vezes_usado, m.dono_consultor_id, u.nome AS dono_nome
        FROM modelos_conteudo m LEFT JOIN usuarios u ON u.id = m.dono_consultor_id
        WHERE {where}
        ORDER BY favorito DESC, (u.nome IS NULL), u.nome, (m.categoria IS NULL), m.categoria, m.nome""", params).fetchall()
    close_db(conn)
    modelos = []
    for m in rows:
        md = dict(m)
        modelos.append({
            "id": md['id'], "nome": md['nome'], "texto": md['corpo_texto'] or '',
            "variante": md['variante'], "midia_tipo": md['midia_tipo'],
            "categoria": md.get('categoria') or '', "favorito": bool(md.get('favorito')),
            "vezes_usado": md.get('vezes_usado') or 0,
            "dono_nome": md.get('dono_nome') or 'Compartilhado',
            "midia_url": (f"{_SITE_BASE_URL}/crm/modelos/midia/{md['midia_arquivo']}" if md['midia_arquivo'] else None),
        })
    return _wa_cors(jsonify({"ok": True, "gestor": eh_gestor, "modelos": modelos}))


@app.route('/api/whatsapp/extensao/modelos/novo', methods=['POST', 'OPTIONS'])
def api_whatsapp_extensao_modelo_novo():
    """Cria um modelo de mensagem de WhatsApp DIRETO da extensão (texto sempre;
    mídia opcional — áudio gravado na hora, áudio pronto ou imagem). Autenticado
    por chave de extensão (não sessão) — decisão explícita do Guilherme de poder
    montar a biblioteca inteira sem sair do WhatsApp, igual WaSpeed/ZapVoice.
    criado_por = usuario_id escolhido no popup (pra saber quem cadastrou)."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    nome = (request.form.get('nome') or '').strip()
    texto = (request.form.get('texto') or '').strip()
    if not nome or not texto:
        return _wa_cors(jsonify({"ok": False, "erro": "Nome e texto são obrigatórios"})), 400
    if len(texto) > 4000:
        return _wa_cors(jsonify({"ok": False, "erro": "Texto longo demais (máx. 4000 caracteres)"})), 400
    criado_por = None
    try:
        criado_por = int(request.form.get('usuario_id'))
    except (TypeError, ValueError):
        pass
    # dono_consultor_id = quem gravou (mesmo usuario_id) — sem isso, o próprio
    # áudio que a consultora acabou de gravar sumiria da lista dela assim que
    # a extensão passasse a filtrar por dono_consultor_id em vez de criado_por.
    dono_consultor_id = criado_por

    midia_arquivo, midia_tipo = None, None
    f = request.files.get('arquivo_midia')
    if f and f.filename:
        ext = os.path.splitext(f.filename)[1].lower()
        midia_tipo = _midia_tipo_por_ext(ext)
        if not midia_tipo:
            return _wa_cors(jsonify({"ok": False, "erro": f"Formato não aceito: {ext}"})), 400
        f.stream.seek(0, os.SEEK_END)
        tamanho = f.stream.tell()
        f.stream.seek(0)
        if tamanho > 16_000_000:
            return _wa_cors(jsonify({"ok": False, "erro": "Arquivo grande demais (máx. 16MB)"})), 400
        nome_arquivo = f"MODELO_WPP_{datetime.now(TZ_SP).strftime('%Y%m%d%H%M%S')}_{_sanitizar_filename(f.filename)}"
        resultado = upload_arquivo_r2(f.stream, f"modelos/{nome_arquivo}")
        if not resultado.get('ok'):
            return _wa_cors(jsonify({"ok": False, "erro": "Erro ao salvar mídia"})), 500
        midia_arquivo = nome_arquivo

    categoria = (request.form.get('categoria') or '').strip()[:80] or None
    conn = db()
    conn.execute("""INSERT INTO modelos_conteudo
                    (tipo, nome, corpo_texto, ativo, criado_por, midia_arquivo, midia_tipo, categoria, dono_consultor_id)
                    VALUES ('whatsapp',?,?,1,?,?,?,?,?)""",
                 (nome, texto, criado_por, midia_arquivo, midia_tipo, categoria, dono_consultor_id))
    mid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
           else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True, "id": mid}))


