@app.route('/api/whatsapp/extensao/funis', methods=['GET', 'OPTIONS'])
def api_whatsapp_extensao_funis():
    """Lista os funis (sequências de disparo) ativos, cada um com seus passos já
    resolvidos (texto/mídia + delay) — a extensão precisa de tudo pronto pra
    TOCAR a sequência na conversa aberta (envia passo, espera o delay, próximo),
    sem ida-e-volta por passo. O disparo é sempre uma ação explícita do consultor
    na conversa que está na tela — nunca em massa/automático."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    # Mesmo filtro por consultor dos modelos: ?usuario_id=N → funis da pasta
    # DELA (dono_consultor_id=N) + funis de pasta compartilhada/sem pasta
    # (NULL = da corretora). Organização, não segurança — ver comentário em
    # api_whatsapp_extensao_modelos.
    try:
        uid = int(request.args.get('usuario_id') or 0)
    except (TypeError, ValueError):
        uid = 0
    conn = db()
    # Gestor vê os funis de todo mundo (organizado por dono); consultor vê só o
    # dele + compartilhado — mesma regra dos modelos.
    perfil = None
    if uid:
        prow = conn.execute("SELECT perfil FROM usuarios WHERE id=?", (uid,)).fetchone()
        perfil = prow['perfil'] if prow else None
    eh_gestor = perfil in ('admin', 'supervisor', 'gestor_vendedor')
    where_f = "f.ativo=1"
    params_f = []
    if uid and not eh_gestor:
        where_f += " AND (f.dono_consultor_id = ? OR f.dono_consultor_id IS NULL)"
        params_f.append(uid)
    funis = conn.execute(f"""SELECT f.id, f.nome, f.categoria, f.favorito, f.vezes_disparado,
            f.dono_consultor_id, u.nome AS dono_nome
        FROM whatsapp_funis f LEFT JOIN usuarios u ON u.id = f.dono_consultor_id
        WHERE {where_f}
        ORDER BY favorito DESC, (u.nome IS NULL), u.nome, (f.categoria IS NULL), f.categoria, f.nome""", params_f).fetchall()
    # Puxa TODOS os passos de uma vez (join com o modelo) e agrupa por funil —
    # evita N+1 e mantém a ordem definida no builder.
    passos = conn.execute("""SELECT p.id AS passo_id, p.funil_id, p.ordem, p.delay_segundos,
            m.id AS modelo_id, m.nome, m.corpo_texto, m.midia_arquivo, m.midia_tipo
        FROM whatsapp_funil_passos p
        JOIN modelos_conteudo m ON m.id = p.modelo_id AND m.tipo='whatsapp' AND m.ativo=1
        ORDER BY p.funil_id, p.ordem, p.id""").fetchall()
    close_db(conn)
    por_funil = {}
    for p in passos:
        pd = dict(p)
        por_funil.setdefault(pd['funil_id'], []).append({
            "passo_id": pd['passo_id'],
            "modelo_id": pd['modelo_id'],
            "nome": pd['nome'],
            "texto": pd['corpo_texto'] or '',
            "delay_segundos": pd['delay_segundos'] or 0,
            "tipo": (pd['midia_tipo'] if pd['midia_tipo'] in ('audio', 'imagem', 'video', 'documento') else 'texto'),
            "midia_url": (f"{_SITE_BASE_URL}/crm/modelos/midia/{pd['midia_arquivo']}" if pd['midia_arquivo'] else None),
        })
    out = []
    for f in funis:
        fd = dict(f)
        out.append({
            "id": fd['id'], "nome": fd['nome'],
            "categoria": fd.get('categoria') or '', "favorito": bool(fd.get('favorito')),
            "vezes_disparado": fd.get('vezes_disparado') or 0,
            "dono_nome": fd.get('dono_nome') or 'Compartilhado',
            "passos": por_funil.get(fd['id'], []),
        })
    return _wa_cors(jsonify({"ok": True, "gestor": eh_gestor, "funis": out}))


@app.route('/api/whatsapp/extensao/funis/<int:fid>/disparado', methods=['POST', 'OPTIONS'])
def api_whatsapp_extensao_funil_disparado(fid):
    """A extensão avisa que terminou de tocar um funil numa conversa — só pra
    contabilizar (vezes_disparado) e registrar no lead, se casou pelo telefone.
    O envio em si aconteceu client-side pela wa-js; aqui é só o registro."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401
    d = request.get_json(silent=True) or {}
    conn = db()
    f = conn.execute("SELECT nome FROM whatsapp_funis WHERE id=?", (fid,)).fetchone()
    if not f:
        close_db(conn); return _wa_cors(jsonify({"ok": False, "erro": "Funil não encontrado"})), 404
    conn.execute("UPDATE whatsapp_funis SET vezes_disparado = COALESCE(vezes_disparado,0) + 1 WHERE id=?", (fid,))
    # Casa com o lead pelo telefone (best-effort) só pra deixar rastro na timeline.
    tel = re.sub(r'\D', '', str(d.get('telefone') or ''))
    enviados = 0
    try:
        enviados = int(d.get('enviados') or 0)
    except (TypeError, ValueError):
        enviados = 0
    if tel:
        tel_norm = _normalizar_telefone(tel)
        lead = conn.execute("SELECT id FROM crm_leads WHERE telefone_norm=? ORDER BY id DESC LIMIT 1", (tel_norm,)).fetchone()
        if lead:
            conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                         (lead['id'], 'Extensão WhatsApp', 'mensagem',
                          f"Funil \"{f['nome']}\" disparado ({enviados} passo(s)).", _agora_sp()))
    # Fecha a execução ao vivo (se existir) — some do painel de acompanhamento.
    # job_uid identifica ESSA execução específica (um consultor pode ter várias
    # rodando ao mesmo tempo, pra leads diferentes).
    job_uid = d.get('job_uid')
    if job_uid:
        conn.execute("DELETE FROM funil_execucao WHERE job_uid=?", (str(job_uid),))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


@app.route('/api/whatsapp/funil/progresso', methods=['POST', 'OPTIONS'])
def api_whatsapp_funil_progresso():
    """A extensão reporta CADA passo de cada funil manual rodando (disparado
    direto de uma conversa) — alimenta o painel 'Acompanhamento de funis' no
    site: quem está disparando, pra quem, em qual passo, quanto falta. Upsert
    por job_uid (um consultor pode ter VÁRIAS execuções simultâneas, uma por
    lead/conversa — cada disparo na extensão gera seu próprio job_uid)."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False}))
    d = request.json or {}
    try:
        uid = int(d.get('usuario_id'))
    except (TypeError, ValueError):
        return _wa_cors(jsonify({"ok": False}))
    job_uid = str(d.get('job_uid') or uid)  # fallback pra extensões antigas sem job_uid
    status = (d.get('status') or 'rodando').strip()
    agora = _agora_sp()
    conn = db()
    if status in ('concluido', 'cancelado', 'erro'):
        conn.execute("DELETE FROM funil_execucao WHERE job_uid=?", (job_uid,))
        conn.commit(); close_db(conn)
        return _wa_cors(jsonify({"ok": True}))
    try:
        passo_atual = int(d.get('passo_atual') or 0)
    except (TypeError, ValueError):
        passo_atual = 0
    try:
        total_passos = int(d.get('total_passos') or 0)
    except (TypeError, ValueError):
        total_passos = 0
    try:
        seg = int(d.get('segundos_restantes') or 0)
    except (TypeError, ValueError):
        seg = 0
    ja_existe = conn.execute("SELECT job_uid FROM funil_execucao WHERE job_uid=?", (job_uid,)).fetchone()
    if DB_MODE == 'postgres':
        conn.execute("""INSERT INTO funil_execucao
            (job_uid, usuario_id, funil_id, funil_nome, contato_nome, telefone, passo_atual, total_passos, segundos_restantes, status, iniciado_em, atualizado_em)
            VALUES (%s,%s,%s,%s,%s,%s,%s,%s,%s,'rodando',%s,%s)
            ON CONFLICT (job_uid) DO UPDATE SET
            funil_id=excluded.funil_id, funil_nome=excluded.funil_nome, contato_nome=excluded.contato_nome,
            telefone=excluded.telefone, passo_atual=excluded.passo_atual, total_passos=excluded.total_passos,
            segundos_restantes=excluded.segundos_restantes, status='rodando', atualizado_em=excluded.atualizado_em""",
            (job_uid, uid, d.get('funil_id'), d.get('funil_nome') or '', d.get('nome') or '', d.get('telefone') or '',
             passo_atual, total_passos, seg, agora, agora))
    else:
        iniciado = agora if not ja_existe else conn.execute(
            "SELECT iniciado_em FROM funil_execucao WHERE job_uid=?", (job_uid,)).fetchone()['iniciado_em']
        if ja_existe:
            conn.execute("""UPDATE funil_execucao SET
                usuario_id=?, funil_id=?, funil_nome=?, contato_nome=?, telefone=?,
                passo_atual=?, total_passos=?, segundos_restantes=?, status='rodando', atualizado_em=?
                WHERE job_uid=?""",
                (uid, d.get('funil_id'), d.get('funil_nome') or '', d.get('nome') or '', d.get('telefone') or '',
                 passo_atual, total_passos, seg, agora, job_uid))
        else:
            conn.execute("""INSERT INTO funil_execucao
                (job_uid, usuario_id, funil_id, funil_nome, contato_nome, telefone, passo_atual, total_passos, segundos_restantes, status, iniciado_em, atualizado_em)
                VALUES (?,?,?,?,?,?,?,?,?,'rodando',?,?)""",
                (job_uid, uid, d.get('funil_id'), d.get('funil_nome') or '', d.get('nome') or '', d.get('telefone') or '',
                 passo_atual, total_passos, seg, iniciado, agora))
    conn.commit(); close_db(conn)
    return _wa_cors(jsonify({"ok": True}))


@app.route('/funis/acompanhamento')
@login_required
@admin_required
def funis_acompanhamento():
    """Painel: quais disparos de funil manual estão rodando agora — quem, pra
    quem, em qual passo, quanto falta. Some sozinho quando o consultor termina/
    fecha (a extensão limpa a linha) ou depois de 15min sem report (travado)."""
    conn = db()
    cutoff = (datetime.now(TZ_SP) - timedelta(minutes=15)).strftime('%Y-%m-%d %H:%M:%S')
    conn.execute("DELETE FROM funil_execucao WHERE atualizado_em < ?", (cutoff,))
    conn.commit()
    rows = conn.execute("""SELECT fe.*, u.nome usuario_nome FROM funil_execucao fe
        LEFT JOIN usuarios u ON u.id=fe.usuario_id ORDER BY fe.atualizado_em DESC""").fetchall()
    close_db(conn)
    return render_template('funis_acompanhamento.html', execucoes=[dict(r) for r in rows])


