def _wa_extracao_para_qualificacao(ex):
    """Mapeia o dict de extração da conversa (_wa_extrair_lead) pros campos
    qual_* do CRM. Só preenche o que dá pra inferir com confiança direto da
    conversa — nunca inventa (mesma regra da extração em si). qual_tipo_plano
    (Titular/Familiar/Funcionário) e qual_estagio2 (critérios específicos) não
    são preenchidos automaticamente por serem ambíguos/curados manualmente."""
    q = {}
    if ex.get('cidade'):
        q['qual_cidade'] = ex['cidade']
    if ex.get('idades'):
        idades_fmt = ', '.join(str(i) for i in sorted(ex['idades']))
        q['qual_idade'] = f"{idades_fmt} anos"
    elif ex.get('faixa_etaria_texto'):
        q['qual_idade'] = 'Faixa(s): ' + ', '.join(ex['faixa_etaria_texto'])
    if ex.get('cnpj'):
        c = ex['cnpj']
        q['qual_cnpj'] = f"{c[:2]}.{c[2:5]}.{c[5:8]}/{c[8:12]}-{c[12:14]}" if len(c) == 14 else c
    elif ex.get('tem_cnpj') is False:
        q['qual_cnpj'] = 'Não possui'
    if ex.get('plano_ativo') == 'ATIVO' and ex.get('operadora_atual'):
        q['qual_plano_atual'] = ex['operadora_atual'].title()
    elif ex.get('plano_ativo') == 'SEM_PLANO':
        q['qual_plano_atual'] = 'Não possui'
    elif ex.get('plano_ativo') == 'CANCELADO_RECENTE':
        op = f" ({ex['operadora_atual'].title()})" if ex.get('operadora_atual') else ''
        q['qual_plano_atual'] = f"Cancelado recentemente{op}"
    if ex.get('operadora_interesse'):
        q['qual_operadora_interesse'] = ex['operadora_interesse']
        if ex.get('plano_preferido'):
            q['qual_operadora_interesse'] += f" — {ex['plano_preferido']}"
    if ex.get('tipo_contratacao'):
        q['qual_tipo_contratacao'] = {'PJ': 'CNPJ / empresarial', 'ADESAO': 'Adesão (PF)',
                                       'PF': 'Pessoa física'}.get(ex['tipo_contratacao'], ex['tipo_contratacao'])
    return q


@app.route('/api/whatsapp/analisar', methods=['POST', 'OPTIONS'])
def api_whatsapp_analisar():
    """Recebe a conversa raspada pela extensão e devolve score + sugestões.
    Payload: {telefone, nome, mensagens:[{de:'lead'|'consultor', texto, hora}]}.
    Casa com o lead por telefone_norm (se existir), grava a análise e, quando
    achou o lead, registra uma atividade no CRM com o score."""
    if request.method == 'OPTIONS':
        return _wa_cors(Response(status=204))
    if not _wa_auth_ok():
        return _wa_cors(jsonify({"ok": False, "erro": "Chave da extensão inválida"})), 401

    t_inicio = time.monotonic()
    d = request.json or {}
    mensagens = d.get('mensagens') or []
    # A conversa pode legitimamente não ter NENHUM texto (ex: lead cujo primeiro
    # contato foi só um áudio, ou só mandou uma foto de cotação sem escrever
    # nada) — só rejeita de cara se não veio absolutamente nada em lugar nenhum.
    if not any([mensagens, d.get('imagens'), d.get('documentos'), d.get('links'), d.get('audios')]):
        return _wa_cors(jsonify({"ok": False, "erro": "Conversa vazia"})), 400
    # Sanidade: normaliza cada mensagem e corta tamanho absurdo (proteção).
    limpa = []
    for m in (mensagens if isinstance(mensagens, list) else [])[:2000]:
        if not isinstance(m, dict):
            continue
        de = 'lead' if m.get('de') == 'lead' else 'consultor'
        txt = str(m.get('texto') or '')[:4000]
        limpa.append({'de': de, 'texto': txt, 'hora': str(m.get('hora') or '')[:40]})

    # Imagens (base64) raspadas da conversa — opcional. Teto de tamanho por imagem
    # (~7MB de base64 ≈ 5MB de arquivo) e de quantidade, pra proteger o payload.
    imagens = []
    for img in (d.get('imagens') or [])[:_CLAUDE_MAX_IMAGENS]:
        if not isinstance(img, dict):
            continue
        b64 = str(img.get('base64') or '')
        if not b64 or len(b64) > 7_500_000:
            continue
        imagens.append({'de': 'lead' if img.get('de') == 'lead' else 'consultor',
                        'base64': b64, 'mime': str(img.get('mime') or 'image/jpeg')[:30],
                        'hora': str(img.get('hora') or '')[:40]})

    # Documentos PDF (base64) raspados da conversa — opcional (Fase 3). Teto de
    # tamanho por arquivo (~20MB de base64 ≈ 15MB de arquivo) e de quantidade.
    documentos = []
    for doc in (d.get('documentos') or [])[:_CLAUDE_MAX_DOCUMENTOS]:
        if not isinstance(doc, dict):
            continue
        b64 = str(doc.get('base64') or '')
        if not b64 or len(b64) > 20_000_000:
            continue
        documentos.append({'de': 'lead' if doc.get('de') == 'lead' else 'consultor',
                           'base64': b64, 'nome': str(doc.get('nome') or 'documento.pdf')[:200],
                           'hora': str(doc.get('hora') or '')[:40],
                           'msg_id': str(doc.get('msg_id') or '').strip()[:100] or None})
    # A extensão manda quantos PDFs EXISTIAM na conversa; se baixou menos (mídia
    # não sincronizada, download falhou), o painel avisa em vez de fingir que
    # leu tudo — antes um PDF sumia em silêncio e a extração vinha capenga.
    try:
        docs_encontrados = int(d.get('documentos_encontrados') or 0)
    except (TypeError, ValueError):
        docs_encontrados = 0
    documentos_falha = max(0, docs_encontrados - len(documentos))

    # Links (URL + prévia de texto) raspados da conversa — Fase 4. Só texto,
    # nunca abrimos/buscamos o link no servidor.
    links = []
    for lk in (d.get('links') or [])[:15]:
        if not isinstance(lk, dict):
            continue
        url = str(lk.get('url') or '').strip()
        if not url or len(url) > 2000:
            continue
        links.append({'de': 'lead' if lk.get('de') == 'lead' else 'consultor',
                      'url': url, 'preview': str(lk.get('preview') or '')[:300],
                      'hora': str(lk.get('hora') or '')[:40]})

    conn = db()

    # Áudios (base64 OGG) — transcreve cada um e injeta como mensagem na conversa,
    # em ordem cronológica, pra o áudio entrar no Score e na leitura da IA.
    # Cache por msg_id (id estável da wa-js, ver _wa_transcricao_cache_buscar):
    # todo áudio que a extensão manda SEMPRE entra na conversa — o cache só
    # evita pagar de novo pela transcrição de um áudio que a gente já tem,
    # nunca decide deixar um áudio de fora. Isso é diferente (e seguro) da
    # marca d'água que foi revertida antes: aqui nunca se pula considerar um
    # áudio, só se evita RETRABALHO numa chamada cara já feita com sucesso.
    transcricoes = []
    audio_msgs = []
    custo_transcricao_usd = 0.0
    audio_segundos_total = 0.0
    audios_validos = 0
    audios_do_cache = 0
    tinha_chave_transcricao = bool(os.environ.get('OPENAI_API_KEY', '').strip() or os.environ.get('GROQ_API_KEY', '').strip())
    for a in (d.get('audios') or [])[:12]:
        if not isinstance(a, dict):
            continue
        b64 = str(a.get('base64') or '')
        if not b64 or len(b64) > 40_000_000:
            continue
        audios_validos += 1
        msg_id = str(a.get('msg_id') or '').strip()[:100] or None
        cache = _wa_transcricao_cache_buscar(conn, msg_id)
        if cache:
            texto = cache['texto']
            audio_segundos_total += cache.get('segundos') or 0
            audios_do_cache += 1
        else:
            transc = _transcrever_audio(b64, str(a.get('mime') or 'audio/ogg'))
            if not transc:
                continue
            texto = transc['texto']
            custo_transcricao_usd += transc.get('custo_usd') or 0
            audio_segundos_total += transc.get('segundos') or 0
            _wa_transcricao_cache_salvar(conn, msg_id, texto, transc.get('segundos'), transc.get('custo_usd'))
        de = 'lead' if a.get('de') == 'lead' else 'consultor'
        hora = str(a.get('hora') or '')[:40]
        audio_msgs.append({'de': de, 'texto': '🎤 ' + texto[:4000], 'hora': hora})
        transcricoes.append({'de': de, 'hora': hora, 'texto': texto[:600]})
    if audio_msgs:
        combinado = limpa + audio_msgs
        combinado.sort(key=lambda m: _wa_parse_hora(m.get('hora') or '') or datetime.min)
        limpa = combinado

    # Depois de processar tudo (texto + áudio transcrito), se não sobrou nada
    # utilizável (ex: só vieram áudios e todos falharam na transcrição, sem
    # imagem/PDF/link), aí sim não tem o que analisar.
    if not limpa and not imagens and not documentos and not links:
        close_db(conn)
        return _wa_cors(jsonify({"ok": False, "erro": "Não consegui extrair nada útil desta conversa (sem texto, e áudio/imagem/PDF não deu certo)."})), 400

    telefone = str(d.get('telefone') or '').strip()
    nome = str(d.get('nome') or '').strip()[:200]
    tel_norm = _normalizar_telefone(telefone)

    # Busca a conversa salva anterior UMA VEZ — usada tanto pro merge
    # incremental de texto/áudio (abaixo) quanto pro dedup de mídia (a seguir):
    # sem isso, cada reanálise re-subiria a MESMA imagem/PDF que já está salva
    # (a extensão manda de novo tudo que ainda está visível na tela, não só o
    # que é novo), duplicando arquivo em storage a cada rodada.
    msgs_antigas = []
    if tel_norm:
        anterior = conn.execute("""SELECT conversa_json FROM whatsapp_analises
            WHERE telefone_norm=? ORDER BY id DESC LIMIT 1""", (tel_norm,)).fetchone()
        if anterior:
            try:
                msgs_antigas = json.loads(anterior['conversa_json'] or '[]')
            except Exception:
                msgs_antigas = []

    # ── Mídia: imagem/PDF/link viviam só na memória da requisição (a IA lia e
    # esquecia) — por isso nunca apareciam de novo na conversa salva. Agora
    # persistem via a mesma infra de anexo já usada pros comprovantes (local +
    # R2 best-effort), como mensagens no histórico. Identidade estável (msg_id
    # do PDF, hash do conteúdo pra imagem, a própria URL pro link) evita
    # duplicar o mesmo arquivo a cada reanálise. ──
    ja_salvo = set()
    for m in msgs_antigas:
        if m.get('tipo') == 'imagem':
            ja_salvo.add(('imagem', m.get('hash')))
        elif m.get('tipo') == 'documento':
            ja_salvo.add(('documento', m.get('msg_id') or m.get('hash')))
        elif m.get('tipo') == 'link':
            ja_salvo.add(('link', m.get('url')))

    midia_msgs = []
    if imagens or documentos or links:
        import base64 as _b64_mod, io as _io_mod
        for img in imagens:
            h = hashlib.sha1(img['base64'][:20000].encode('ascii', 'ignore')).hexdigest()[:24]
            if ('imagem', h) in ja_salvo:
                continue
            try:
                ext = '.png' if 'png' in (img.get('mime') or '') else '.jpg'
                nome_arq = f"WA_ANALISE_{secrets.token_hex(8)}{ext}"
                upload_arquivo_r2(_io_mod.BytesIO(_b64_mod.b64decode(img['base64'])), f"whatsapp-analises/{nome_arq}")
                midia_msgs.append({'de': img['de'], 'tipo': 'imagem', 'arquivo': nome_arq, 'hash': h, 'hora': img['hora']})
                ja_salvo.add(('imagem', h))
            except Exception as e:
                app.logger.warning(f"[WA-ANALISE] falha ao salvar imagem: {e}")
        for doc in documentos:
            msg_id = str(doc.get('msg_id') or '').strip()[:100] or None
            ident = msg_id or hashlib.sha1(doc['base64'][:20000].encode('ascii', 'ignore')).hexdigest()[:24]
            if ('documento', ident) in ja_salvo:
                continue
            try:
                nome_arq = f"WA_ANALISE_{secrets.token_hex(8)}.pdf"
                upload_arquivo_r2(_io_mod.BytesIO(_b64_mod.b64decode(doc['base64'])), f"whatsapp-analises/{nome_arq}")
                midia_msgs.append({'de': doc['de'], 'tipo': 'documento', 'arquivo': nome_arq,
                                   'msg_id': msg_id, 'hash': (None if msg_id else ident),
                                   'nome_original': doc.get('nome'), 'hora': doc['hora']})
                ja_salvo.add(('documento', ident))
            except Exception as e:
                app.logger.warning(f"[WA-ANALISE] falha ao salvar documento: {e}")
        for lk in links:
            if ('link', lk['url']) in ja_salvo:
                continue
            midia_msgs.append({'de': lk['de'], 'tipo': 'link', 'url': lk['url'],
                               'preview': lk['preview'], 'hora': lk['hora']})
            ja_salvo.add(('link', lk['url']))
    if midia_msgs:
        combinado = limpa + midia_msgs
        combinado.sort(key=lambda m: _wa_parse_hora(m.get('hora') or '') or datetime.min)
        limpa = combinado

    # ── Modo incremental: funde a conversa nova (que a extensão pode ter
    # mandado só a partir de onde parou, pra ser mais rápida) com a conversa já
    # conhecida (msgs_antigas, buscada acima). O score e a IA sempre trabalham
    # em cima do histórico COMPLETO fundido, nunca só do pedaço novo — senão o
    # contexto acumulado se perde a cada rodada.
    if msgs_antigas:
        # Ordena ANTES de deduplicar, e compara só com a mensagem anterior
        # (igual ao dedup do client) — um set() global sobre a lista inteira
        # derrubava mensagem repetida de verdade (ex: lead manda "Sim" duas
        # vezes em momentos diferentes) só porque data-pre-plain-text do
        # WhatsApp só tem precisão de minuto. Áudio/mídia usam chave própria
        # (identidade estável, não o hora/texto) — senão o mesmo áudio/imagem
        # duplicava na conversa fundida, ou pior, uma imagem diferente enviada
        # no mesmo minuto era descartada por engano.
        def _wa_chave_dedup(m):
            tipo = m.get('tipo')
            if tipo == 'imagem':
                return ('MIDIA', 'imagem', m.get('hash'))
            if tipo == 'documento':
                return ('MIDIA', 'documento', m.get('msg_id') or m.get('hash'))
            if tipo == 'link':
                return ('MIDIA', 'link', m.get('url'))
            texto = m.get('texto') or ''
            if texto.startswith('🎤'):
                return (m.get('de'), 'AUDIO', m.get('hora'))
            return (m.get('de'), texto, m.get('hora'))
        bruto = sorted(msgs_antigas + limpa,
                        key=lambda m: _wa_parse_hora(m.get('hora') or '') or datetime.min)
        fundido = []
        chave_anterior = None
        for m in bruto:
            chave = _wa_chave_dedup(m)
            if chave != chave_anterior:
                fundido.append(m)
            chave_anterior = chave
        limpa = fundido

    an = _wa_analisar_conversa(limpa, nome_contato=nome, imagens=imagens, documentos=documentos, links=links)
    an['audios_transcritos'] = len(transcricoes)
    an['audios_do_cache'] = audios_do_cache
    an['transcricoes'] = transcricoes
    # Só é "falha" de verdade se a chave estava configurada e mesmo assim
    # sobrou áudio sem transcrever — sem chave, o esperado é 0 mesmo (silencioso).
    an['audios_falha'] = (audios_validos - len(transcricoes)) if tinha_chave_transcricao else 0
    score, faixa = an['score_final'], an['faixa']

    # Resolve o usuário que está rodando a extensão uma vez só — usado tanto
    # pra desambiguar homônimo no fallback por nome quanto pra atribuir o
    # responsável de um lead criado agora.
    # PRIORIDADE: o NÚMERO do WhatsApp logado na aba (detectado via wa-js e
    # casado com o telefone cadastrado em /usuarios) manda; o consultor escolhido
    # no popup é só fallback. O popup é manual e vive esquecido — análise saía no
    # nome de outro consultor (pedido do Guilherme, 14/07). Casamento pelos
    # últimos 8 dígitos, mesmo critério do _buscar_lead_por_telefone (9º dígito).
    responsavel_extensao = None
    consultor_nome = None
    aviso_consultor = None
    usuario_zap = None
    zap_consultor = _normalizar_telefone(str(d.get('whatsapp_consultor') or ''))
    if zap_consultor and len(zap_consultor) >= 8:
        suf_zap = zap_consultor[-8:]
        for u in conn.execute("SELECT id, nome, telefone FROM usuarios WHERE ativo=1").fetchall():
            tel_u = _normalizar_telefone(str(u['telefone'] or ''))
            if tel_u and len(tel_u) >= 8 and tel_u[-8:] == suf_zap:
                usuario_zap = u
                break
    usuario_popup = None
    usuario_id_raw = d.get('usuario_id')
    if usuario_id_raw:
        try:
            u = conn.execute("SELECT id, nome FROM usuarios WHERE id=? AND ativo=1",
                             (int(usuario_id_raw),)).fetchone()
            if u:
                usuario_popup = u
        except (TypeError, ValueError):
            pass
    if usuario_zap:
        responsavel_extensao = usuario_zap['id']
        consultor_nome = usuario_zap['nome']
        if usuario_popup and usuario_popup['id'] != usuario_zap['id']:
            aviso_consultor = (f"Este WhatsApp é de {usuario_zap['nome']}, mas a extensão está configurada "
                               f"como {usuario_popup['nome']} — o lead fica com {usuario_zap['nome']}. "
                               "Ajuste o consultor no popup da extensão.")
    elif usuario_popup:
        responsavel_extensao = usuario_popup['id']
        consultor_nome = usuario_popup['nome']
        if zap_consultor:
            aviso_consultor = (f"O número deste WhatsApp não está cadastrado em nenhum consultor — usando "
                               f"{usuario_popup['nome']} (escolhido no popup). Cadastre o telefone do consultor "
                               "em Usuários no JOB pra atribuição automática.")

    lead = _buscar_lead_por_telefone(conn, tel_norm)
    # Fallback por NOME: contato salvo no WhatsApp não expõe o telefone no DOM
    # novo, então a extensão manda só o nome. Casa por nome exato (case-insensitive)
    # — MAS se houver homônimo (nome comum, tipo "Maria Silva"), NÃO adivinha:
    # dado de saúde é sensível demais pra arriscar grudar na pessoa errada.
    # Só desambigua se um único candidato bater com o responsável da extensão;
    # caso contrário segue como "não encontrado" (cria um lead novo).
    if not lead and nome:
        candidatos = conn.execute("SELECT id, nome, responsavel_id FROM crm_leads WHERE LOWER(TRIM(nome))=?",
                                  (nome.strip().lower(),)).fetchall()
        if len(candidatos) == 1:
            lead = candidatos[0]
        elif len(candidatos) > 1 and responsavel_extensao:
            so_meus = [c for c in candidatos if c['responsavel_id'] == responsavel_extensao]
            if len(so_meus) == 1:
                lead = so_meus[0]
    lead_id = lead['id'] if lead else None
    lead_criado = False
    responsavel_lead_criado = None

    # ── Não achou lead: cria automaticamente (pedido explícito — a análise não
    # pode ficar só "solta" no painel da extensão, tem que virar lead no CRM) ──
    if not lead_id and (tel_norm or nome):
        conn.execute("""INSERT INTO crm_leads
            (nome, telefone, telefone_norm, origem, etapa, responsavel_id, observacoes, criado_em)
            VALUES (?,?,?,?,?,?,?,?)""",
            (nome or telefone or 'Lead WhatsApp', telefone, tel_norm, 'WhatsApp (extensão)',
             'lead_novo', responsavel_extensao, 'Criado automaticamente pela extensão de WhatsApp.', _agora_sp()))
        lead_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                   else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
        conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                     (lead_id, 'Extensão WhatsApp', 'criacao',
                      'Lead criado automaticamente a partir da análise de uma conversa no WhatsApp.', _agora_sp()))
        lead_criado = True
        responsavel_lead_criado = responsavel_extensao

    # Dono do lead — o painel avisa o consultor: "já está no seu cadastro",
    # "está com OUTRO consultor (Fulano)" ou pra quem o lead novo foi atribuído.
    lead_resp_id = responsavel_lead_criado if lead_criado else (lead['responsavel_id'] if lead else None)
    lead_resp_nome = None
    if lead_id and lead_resp_id:
        _rn = conn.execute("SELECT nome FROM usuarios WHERE id=?", (lead_resp_id,)).fetchone()
        lead_resp_nome = _rn['nome'] if _rn else None

    # ── Sobe pro CRM o que deu pra extrair da conversa (qual_*), sem sobrescrever
    # o que o consultor já preencheu manualmente (só entra no que estiver vazio) ──
    if lead_id:
        qual = _wa_extracao_para_qualificacao(an['extracao'])
        if qual:
            sets = ', '.join(f"{col} = COALESCE(NULLIF({col}, ''), ?)" for col in qual)
            conn.execute(f"UPDATE crm_leads SET {sets}, atualizado_em=? WHERE id=?",
                         (*qual.values(), _agora_sp(), lead_id))

    # ── Valor da cotação (pedido explícito do Guilherme): quando a IA acha um
    # valor claro num anexo/texto, preenche o campo estruturado valor_estimado
    # (só se ainda estiver vazio — nunca pisa em cima do que o consultor já
    # colocou) E deixa um registro em observações, com a operadora se souber.
    # Dedup por conteúdo: reanálise da mesma conversa com o MESMO valor não
    # empilha a nota de novo (a extensão manda tudo de novo a cada rodada). ──
    if lead_id and an.get('valor_cotacao'):
        vc = an['valor_cotacao']
        operadora = (an.get('extracao') or {}).get('operadora_interesse') or ''
        nota = f"Cotação identificada pela IA: R$ {vc:.2f}".replace('.', ',')
        if operadora:
            nota += f" ({operadora})"
        atual = conn.execute("SELECT valor_estimado, observacoes FROM crm_leads WHERE id=?", (lead_id,)).fetchone()
        atual = dict(atual) if atual else {}
        if nota not in (atual.get('observacoes') or ''):
            obs_nova = ((atual.get('observacoes') or '').rstrip() + f"\n{nota}").strip()
            conn.execute("""UPDATE crm_leads SET
                valor_estimado = COALESCE(valor_estimado, ?),
                observacoes = ?, atualizado_em = ? WHERE id=?""",
                (vc, obs_nova, _agora_sp(), lead_id))

    # ── Score Lead move o lead pra Topo do Funil na primeira triagem real —
    # regra combinada com o Guilherme: score>=550 (medio/bom/quente) tira da
    # pilha de Lead Novo pra Topo; abaixo disso fica parado (humano decide se
    # continua nutrindo ou descarta). SÓ mexe se o lead AINDA estiver em
    # 'lead_novo' — o WHERE na etapa é o que impede sobrescrever qualquer
    # movimentação manual já feita (Transferência, Meio, Fundo...). Nunca
    # progride Topo→Meio→Fundo sozinho (depende de coisa que o score não vê —
    # documentação, negociação) e nunca toca Ganho/Perdido — decisão humana.
    if lead_id and score is not None and score >= 550:
        moveu = conn.execute("""UPDATE crm_leads SET etapa='topo', atualizado_em=?
            WHERE id=? AND etapa='lead_novo'""", (_agora_sp(), lead_id)).rowcount
        if moveu:
            conn.execute("""INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em)
                VALUES (?,?,?,?,?)""",
                (lead_id, 'Score Lead', 'etapa',
                 f'Movido automaticamente de Lead Novo pra Topo do Funil (score {score}/1000, {faixa}).', _agora_sp()))

    # sugestoes_json guarda o diagnóstico completo (dá pra reprocessar/auditar depois)
    diagnostico = {k: an[k] for k in ('sugestoes', 'tags', 'fase_funil', 'extracao', 'breakdown',
                                       'penalidades', 'cap', 'followup', 'descricao',
                                       'score_bruto', 'categorias_consideradas', 'categorias_totais')}
    diagnostico['ia'] = an.get('ia')
    diagnostico['transcricoes'] = an.get('transcricoes')
    diagnostico['docs_extraidos'] = an.get('docs_extraidos') or ''

    ia_info = an.get('ia') or {}
    custo_claude_usd = ia_info.get('custo_usd') or 0
    tokens_entrada = ia_info.get('tokens_entrada') or 0
    tokens_saida = ia_info.get('tokens_saida') or 0
    duracao_segundos = round(time.monotonic() - t_inicio, 2)

    conn.execute("""INSERT INTO whatsapp_analises
        (lead_id, telefone, telefone_norm, nome_contato, total_mensagens, conversa_json,
         score, score_faixa, sugestoes_json, resumo, criado_por, criado_em,
         custo_claude_usd, custo_transcricao_usd, tokens_entrada, tokens_saida, audio_segundos,
         duracao_segundos)
        VALUES (?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?,?)""",
        (lead_id, telefone, tel_norm, nome, len(limpa), json.dumps(limpa, ensure_ascii=False),
         score, faixa, json.dumps(diagnostico, ensure_ascii=False), an['descricao'],
         d.get('usuario_id'), _agora_sp(),
         custo_claude_usd, custo_transcricao_usd, tokens_entrada, tokens_saida, audio_segundos_total,
         duracao_segundos))
    analise_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                  else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])

    if lead_id:
        conn.execute("""INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em)
                        VALUES (?,?,?,?,?)""",
                     (lead_id, 'Extensão WhatsApp', 'analise',
                      f'Score Lead {score}/1000 ({faixa}) · fase {an["fase_funil"]} · {len(limpa)} mensagens analisadas.',
                      _agora_sp()))
    conn.commit(); close_db(conn)

    if lead_criado:
        # Avisa quem for responsável (ou os admins, se ficou órfão) — a criação
        # é automática e silenciosa na extensão, então precisa aparecer no sino
        # do JOB pra não passar batido. Só depois do commit: _notificar abre a
        # própria conexão, e no SQLite local isso trava se ainda tiver uma
        # transação aberta na mesma base.
        _notificar(responsavel_lead_criado, 'lead',
                   'Lead criado pela extensão de WhatsApp',
                   f'{nome or telefone} entrou no CRM automaticamente a partir de uma conversa analisada.',
                   f'/crm?lead={lead_id}')

    return _wa_cors(jsonify({
        "ok": True,
        "analise_id": analise_id,
        "score": score,
        "score_bruto": an['score_bruto'],
        "faixa": faixa,
        "fase_funil": an['fase_funil'],
        "tags": an['tags'],
        "extracao": an['extracao'],
        "breakdown": an['breakdown'],
        "categorias_consideradas": an['categorias_consideradas'],
        "categorias_totais": an['categorias_totais'],
        "penalidades": an['penalidades'],
        "cap": an['cap'],
        "sugestoes": an['sugestoes'],
        "followup": an['followup'],
        "resumo": an['descricao'],
        "ia": an.get('ia'),
        "docs_extraidos": an.get('docs_extraidos') or '',
        "ia_falhou": an.get('ia_falhou', False),
        "audios_transcritos": an.get('audios_transcritos', 0),
        "audios_do_cache": an.get('audios_do_cache', 0),
        "audios_falha": an.get('audios_falha', 0),
        "documentos_falha": documentos_falha,
        "transcricoes": an.get('transcricoes', []),
        "lead": ({"id": lead_id, "nome": (lead['nome'] if lead else nome),
                  "url": f"{_SITE_BASE_URL}/crm?lead={lead_id}"} if lead_id else None),
        "lead_encontrado": bool(lead_id) and not lead_criado,
        "lead_criado": lead_criado,
        "consultor_nome": consultor_nome,
        "aviso_consultor": aviso_consultor,
        "lead_responsavel_id": lead_resp_id,
        "lead_responsavel_nome": lead_resp_nome,
        "lead_e_do_consultor": bool(lead_id and responsavel_extensao and lead_resp_id == responsavel_extensao),
        "custo_usd": round(custo_claude_usd + custo_transcricao_usd, 6),
        "duracao_segundos": duracao_segundos,
    }))


def _wa_custo_resumo(conn, uid=None):
    """Soma o custo estimado da IA por período — hoje, semana, mês, ano e
    total — separando Claude (leitura/análise) de transcrição de áudio
    (OpenAI Whisper ou Groq, dependendo de qual chave está configurada), e
    convertendo pra R$ (câmbio fixo configurável, não é cotação em tempo
    real). É estimativa a partir do preço USD/token e USD/min configurados
    via env — não é a fatura real dos provedores."""
    agora = datetime.now(TZ_SP)
    cortes = {
        'hoje': agora.strftime('%Y-%m-%d') + ' 00:00:00',
        'semana': (agora - timedelta(days=agora.weekday())).strftime('%Y-%m-%d') + ' 00:00:00',
        'mes': agora.strftime('%Y-%m-01') + ' 00:00:00',
        'ano': agora.strftime('%Y-01-01') + ' 00:00:00',
    }

    def periodo(desde):
        q = ("SELECT COALESCE(SUM(COALESCE(custo_claude_usd,0)),0) c_claude, "
             "COALESCE(SUM(COALESCE(custo_transcricao_usd,0)),0) c_transc, COUNT(*) n "
             "FROM whatsapp_analises")
        cond, params = [], []
        if desde:
            cond.append("criado_em >= ?"); params.append(desde)
        if uid:
            cond.append("criado_por=?"); params.append(uid)
        if cond:
            q += " WHERE " + " AND ".join(cond)
        r = conn.execute(q, params).fetchone()
        claude = round(r['c_claude'] or 0, 4)
        transc = round(r['c_transc'] or 0, 4)
        total_usd = round(claude + transc, 4)
        return {'claude_usd': claude, 'transcricao_usd': transc, 'custo_usd': total_usd,
                'custo_brl': round(total_usd * _USD_BRL_TAXA, 2), 'total_analises': r['n']}

    resumo = {k: periodo(v) for k, v in cortes.items()}
    resumo['total'] = periodo(None)
    resumo['taxa_usd_brl'] = _USD_BRL_TAXA
    return resumo


def _wa_calibracao(conn, uid=None):
    """Compara a faixa de score dada pela extensão contra o desfecho REAL do lead
    no CRM (ganho/perdido). Usa só a análise mais recente de cada lead (evita
    contar o mesmo lead 2x quando ele foi reanalisado). Só entra na conta quem
    já chegou numa etapa final — lead ainda em aberto não conta pra nenhum lado,
    porque ainda pode virar qualquer um dos dois."""
    q = """SELECT wa.score_faixa, e.tipo AS etapa_tipo
           FROM whatsapp_analises wa
           JOIN crm_leads l ON l.id = wa.lead_id
           JOIN crm_etapas e ON e.slug = l.etapa
           WHERE wa.lead_id IS NOT NULL AND e.tipo IN ('ganho','perdido')
             AND wa.id = (SELECT MAX(wa2.id) FROM whatsapp_analises wa2 WHERE wa2.lead_id = wa.lead_id)"""
    params = []
    if uid:
        q += " AND l.responsavel_id=?"
        params.append(uid)
    rows = conn.execute(q, params).fetchall()
    faixas = {'quente': {'ganho': 0, 'perdido': 0}, 'bom': {'ganho': 0, 'perdido': 0},
              'medio': {'ganho': 0, 'perdido': 0}, 'baixo': {'ganho': 0, 'perdido': 0},
              'improvavel': {'ganho': 0, 'perdido': 0}}
    for r in rows:
        f = r['score_faixa']
        if f in faixas:
            faixas[f][r['etapa_tipo']] += 1
    ordem = ['quente', 'bom', 'medio', 'baixo', 'improvavel']
    resultado = []
    for f in ordem:
        d = faixas[f]
        total = d['ganho'] + d['perdido']
        taxa = round(100 * d['ganho'] / total, 1) if total else None
        resultado.append({'faixa': f, 'ganho': d['ganho'], 'perdido': d['perdido'],
                           'total': total, 'taxa_conversao': taxa})
    return resultado


@app.route('/whatsapp-analises')
@login_required
def whatsapp_analises_pagina():
    """Lista as análises de conversa feitas pela extensão + o comparativo score
    x desfecho real dos leads (calibração). Admin vê tudo; consultor só o que é
    seu (mesma regra de visibilidade do CRM)."""
    eh_admin = session.get('perfil') == 'admin'
    uid = session['user_id']
    # Filtro por consultor: só faz sentido pro admin (consultor não-admin já só
    # vê as próprias, filtrar de novo por si mesmo não muda nada) — quem rodou
    # a análise (criado_por = usuário escolhido no popup da extensão na hora),
    # não o responsável do lead — é "análise de quem", não "lead de quem".
    f_consultor = request.args.get('consultor', '').strip() if eh_admin else ''
    conn = db()
    calibracao = _wa_calibracao(conn, None if eh_admin else uid)
    custo = _wa_custo_resumo(conn, None if eh_admin else uid)

    q = """SELECT wa.id, wa.nome_contato, wa.telefone, wa.score, wa.score_faixa,
                  wa.total_mensagens, wa.criado_em, wa.lead_id, wa.duracao_segundos, wa.criado_por,
                  COALESCE(wa.custo_claude_usd,0) + COALESCE(wa.custo_transcricao_usd,0) AS custo_usd,
                  l.nome AS lead_nome, l.etapa AS lead_etapa, e.nome AS etapa_nome, e.tipo AS etapa_tipo,
                  u.nome AS consultor_nome
           FROM whatsapp_analises wa
           LEFT JOIN crm_leads l ON l.id = wa.lead_id
           LEFT JOIN crm_etapas e ON e.slug = l.etapa
           LEFT JOIN usuarios u ON u.id = wa.criado_por"""
    condicoes, params = [], []
    if not eh_admin:
        condicoes.append("l.responsavel_id=?")
        params.append(uid)
    if f_consultor:
        condicoes.append("wa.criado_por=?")
        params.append(f_consultor)
    if condicoes:
        q += " WHERE " + " AND ".join(condicoes)
    q += " ORDER BY wa.criado_em DESC LIMIT 200"
    analises = conn.execute(q, params).fetchall()
    # Lista de consultores pra montar o filtro — só quem já tem alguma análise
    # (não adianta mostrar opção vazia), só visível pro admin.
    consultores = []
    if eh_admin:
        consultores = conn.execute("""SELECT DISTINCT u.id, u.nome FROM whatsapp_analises wa
            JOIN usuarios u ON u.id = wa.criado_por ORDER BY u.nome""").fetchall()
    close_db(conn)
    return render_template('whatsapp_analises.html', analises=analises, calibracao=calibracao,
                           custo=custo, taxa_usd_brl=_USD_BRL_TAXA, eh_admin=eh_admin,
                           consultores=consultores, f_consultor=f_consultor)


@app.route('/whatsapp-analises/<int:aid>/conversa')
@login_required
def whatsapp_analise_conversa(aid):
    """Mostra a conversa salva de uma análise (conversa_json) em formato de
    chat. É o registro da ÚLTIMA conversa conhecida do lead — cada análise
    guarda o histórico completo fundido até aquele momento, então a mais
    recente é sempre a foto mais atual. Consultor só vê conversa de lead dele
    (mesma regra do CRM); admin vê tudo."""
    conn = db()
    a = conn.execute("""SELECT wa.*, l.nome AS lead_nome, l.responsavel_id
        FROM whatsapp_analises wa LEFT JOIN crm_leads l ON l.id = wa.lead_id
        WHERE wa.id=?""", (aid,)).fetchone()
    close_db(conn)
    if not a:
        abort(404)
    a = dict(a)
    if session.get('perfil') != 'admin' and a.get('responsavel_id') not in (None, session.get('user_id')):
        abort(403)
    try:
        mensagens = json.loads(a.get('conversa_json') or '[]')
    except Exception:
        mensagens = []
    # sugestoes_json guarda o diagnóstico completo da IA (leitura de imagens/PDF,
    # dados extraídos dos documentos, próximas ações, follow-up, transcrições).
    # A página só mostrava a transcrição da conversa e o score — a leitura da IA
    # ficava salva mas invisível. Aqui ela volta pra tela, no mesmo formato da
    # extensão, pra o registro no JOB bater com o que a IA analisou.
    try:
        diag = json.loads(a.get('sugestoes_json') or '{}')
    except Exception:
        diag = {}
    if not isinstance(diag, dict):
        diag = {}
    return render_template('whatsapp_conversa.html', a=a, mensagens=mensagens,
                           diag=diag, ia=(diag.get('ia') or {}),
                           extracao=(diag.get('extracao') or {}))


# ─── CRM ─────────────────────────────────────────────────────────────────────────
def carregar_etapas_crm(conn=None):
    """Lê as etapas do funil do banco, ordenadas. Cria conexão própria se não receber uma."""
    fechar = False
    if conn is None:
        conn = db(); fechar = True
    try:
        rows = conn.execute(
            "SELECT slug, nome, cor, ordem, tipo FROM crm_etapas WHERE ativo=1 ORDER BY ordem, id"
        ).fetchall()
        etapas = [{'id': r['slug'], 'slug': r['slug'], 'nome': r['nome'],
                   'cor': r['cor'], 'ordem': r['ordem'], 'tipo': r['tipo']} for r in rows]
    except Exception:
        etapas = []
    finally:
        if fechar:
            close_db(conn)
    # Fallback: se a tabela ainda não existir/estiver vazia, usa as etapas padrão
    if not etapas:
        etapas = [
            {'id': 'topo', 'slug': 'topo', 'nome': 'Topo do Funil', 'cor': '#3b82f6', 'ordem': 1, 'tipo': 'normal'},
            {'id': 'meio', 'slug': 'meio', 'nome': 'Meio do Funil', 'cor': '#f59e0b', 'ordem': 2, 'tipo': 'normal'},
            {'id': 'fim', 'slug': 'fim', 'nome': 'Fundo do Funil', 'cor': '#10b981', 'ordem': 3, 'tipo': 'normal'},
            {'id': 'ganho', 'slug': 'ganho', 'nome': 'Ganho', 'cor': '#1fd8a4', 'ordem': 4, 'tipo': 'ganho'},
            {'id': 'perdido', 'slug': 'perdido', 'nome': 'Perdido', 'cor': '#ef4444', 'ordem': 5, 'tipo': 'perdido'},
        ]
    return etapas


def carregar_status_crm(conn=None):
    """Lê as opções de status (sub-status do card) do banco, ordenadas. Cria conexão própria se não receber uma."""
    fechar = False
    if conn is None:
        conn = db(); fechar = True
    try:
        rows = conn.execute(
            "SELECT id, nome, ordem FROM crm_status_opcoes WHERE ativo=1 ORDER BY ordem, id"
        ).fetchall()
        status = [{'id': r['id'], 'nome': r['nome'], 'ordem': r['ordem']} for r in rows]
    except Exception:
        status = []
    finally:
        if fechar:
            close_db(conn)
    if not status:
        status = [
            {'id': None, 'nome': 'Follow up 1', 'ordem': 1},
            {'id': None, 'nome': 'Follow up 2', 'ordem': 2},
            {'id': None, 'nome': 'Follow up 3+', 'ordem': 3},
            {'id': None, 'nome': 'Aguardando resposta', 'ordem': 4},
            {'id': None, 'nome': 'Sem interesse no momento', 'ordem': 5},
        ]
    return status

@app.route('/crm')
@login_required
def crm():
    conn = db()
    uid = session['user_id']
    eh_admin = session.get('perfil') == 'admin'

    # ── Filtros ──
    f_etapa     = request.args.get('etapa', '').strip()
    f_consultor = request.args.get('consultor', '').strip()  # id do responsável
    f_origem    = request.args.get('origem', '').strip()
    f_data_de   = request.args.get('data_de', '').strip()     # YYYY-MM-DD
    f_data_ate  = request.args.get('data_ate', '').strip()    # YYYY-MM-DD
    f_busca     = request.args.get('q', '').strip()
    f_externo   = request.args.get('externo', '').strip()  # consultor externo (não cadastrado)
    f_sub_status = request.args.get('sub_status', '').strip()
    # Deep-link pra abrir uma ficha específica ao carregar a página (notificação
    # do sino, WhatsApp, agenda, etc. montam /crm?lead=<id> — antes esse parâmetro
    # era lido em vários lugares mas NUNCA consumido aqui nem no JS, então todo
    # link "específico" caía no quadro geral). Só o id (int), nunca entra no
    # WHERE do kanban — o JS busca a ficha via fetch('/crm/lead/<id>') direto,
    # funciona mesmo se o card não estiver renderizado na coluna/página atual.
    try:
        f_lead = int(request.args.get('lead', '') or 0) or None
    except (TypeError, ValueError):
        f_lead = None

    # Lista de consultores para o filtro (admin vê todos os usuários ativos)
    responsaveis = []
    consultores_externos = []
    if eh_admin:
        responsaveis = conn.execute(
            "SELECT id, nome, perfil FROM usuarios WHERE ativo=1 ORDER BY nome"
        ).fetchall()
        # Consultores externos que aparecem na planilha mas não são usuários
        try:
            ext = conn.execute("""
                SELECT DISTINCT consultor_externo FROM crm_leads
                WHERE consultor_externo IS NOT NULL AND consultor_externo != ''
                ORDER BY consultor_externo
            """).fetchall()
            consultores_externos = [r['consultor_externo'] if hasattr(r,'keys') else r[0] for r in ext]
        except Exception:
            pass

    # Monta query
    q = """SELECT l.*, u.nome as responsavel_nome
           FROM crm_leads l
           LEFT JOIN usuarios u ON u.id = l.responsavel_id
           WHERE 1=1 """
    params = []

    # Consultor só vê os próprios; admin pode filtrar por consultor
    if not eh_admin:
        q += " AND l.responsavel_id=?"
        params.append(uid)
    elif f_consultor:
        if f_consultor == 'sem':
            q += " AND l.responsavel_id IS NULL AND (l.consultor_externo IS NULL OR l.consultor_externo='')"
        elif f_consultor == 'externo':
            q += " AND l.consultor_externo IS NOT NULL AND l.consultor_externo != ''"
        elif f_consultor.startswith('externo:'):
            q += " AND l.consultor_externo=?"
            params.append(f_consultor[len('externo:'):])
        else:
            q += " AND l.responsavel_id=?"
            params.append(int(f_consultor))

    # Filtro por consultor externo específico
    if f_externo:
        q += " AND LOWER(l.consultor_externo) LIKE LOWER(?)"
        params.append(f'%{f_externo}%')

    if f_etapa:
        q += " AND l.etapa=?"
        params.append(f_etapa)

    if f_sub_status:
        if f_sub_status == 'sem':
            q += " AND (l.sub_status IS NULL OR l.sub_status='')"
        else:
            q += " AND l.sub_status=?"
            params.append(f_sub_status)

    if f_origem:
        q += " AND l.origem LIKE ?"
        params.append(f'%{f_origem}%')

    # Filtro de data sobre criado_em (data do lead)
    if f_data_de:
        q += " AND DATE(l.criado_em) >= ?"
        params.append(f_data_de)
    if f_data_ate:
        q += " AND DATE(l.criado_em) <= ?"
        params.append(f_data_ate)

    if f_busca:
        q += " AND (LOWER(l.nome) LIKE ? OR l.telefone LIKE ? OR LOWER(l.email) LIKE ? OR LOWER(COALESCE(l.consultor_externo,'')) LIKE ?)"
        like = f'%{f_busca.lower()}%'
        params.extend([like, f'%{f_busca}%', like, like])

    q += " ORDER BY l.atualizado_em DESC"
    leads = conn.execute(q, params).fetchall()

    # Etapas dinâmicas do banco
    etapas = carregar_etapas_crm(conn)

    # Agrupa por etapa. CARDS_POR_COLUNA limita quantos cards viram DOM de fato —
    # colunas como "Topo do Funil" acumulam milhares de leads históricos (~4500
    # numa delas em produção) e renderizar tudo de uma vez travava o CRM inteiro.
    # Total e valor somado continuam contando TODOS os leads da coluna (não só os
    # renderizados) — só o card em si é que fica limitado, filtros continuam
    # funcionando sobre a base inteira.
    CARDS_POR_COLUNA = 60
    kanban = {e['id']: [] for e in etapas}
    kanban_total = {e['id']: 0 for e in etapas}
    kanban_valor = {e['id']: 0 for e in etapas}
    primeira = etapas[0]['id'] if etapas else 'topo'
    for lead in leads:
        etapa = lead['etapa'] or primeira
        alvo = etapa if etapa in kanban else primeira
        kanban_total[alvo] += 1
        kanban_valor[alvo] += lead['valor_estimado'] or 0
        if len(kanban[alvo]) < CARDS_POR_COLUNA:
            kanban[alvo].append(lead)

    total = len(leads)

    # Filtros ativos para repassar ao template
    filtros_ativos = {
        'etapa': f_etapa, 'consultor': f_consultor, 'origem': f_origem,
        'data_de': f_data_de, 'data_ate': f_data_ate, 'q': f_busca,
        'externo': f_externo, 'sub_status': f_sub_status
    }

    sub_status_opcoes = _sub_status_opcoes_nomes(conn)
    close_db(conn)
    return render_template('crm.html', kanban=kanban, kanban_total=kanban_total,
                           kanban_valor=kanban_valor, cards_por_coluna=CARDS_POR_COLUNA,
                           etapas=etapas, total=total, responsaveis=responsaveis, eh_admin=eh_admin,
                           filtros=filtros_ativos, consultores_externos=consultores_externos,
                           sub_status_opcoes=sub_status_opcoes, lead_focus=f_lead)


@app.route('/crm/lead/novo', methods=['POST'])
@login_required
def crm_lead_novo():
    d = request.json or request.form
    uid = session['user_id']
    eh_admin = session.get('perfil') == 'admin'
    resp_id = int(d.get('responsavel_id') or uid) if eh_admin else uid
    conn = db()
    conn.execute("""INSERT INTO crm_leads (nome, telefone, email, empresa, origem,
                    etapa, responsavel_id, valor_estimado, observacoes)
                    VALUES (?,?,?,?,?,?,?,?,?)""",
        (d.get('nome'), d.get('telefone'), d.get('email'), d.get('empresa'),
         d.get('origem', 'manual'), d.get('etapa', 'topo'), resp_id,
         float(d.get('valor_estimado') or 0) or None, d.get('observacoes')))
    lead_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE=="postgres" else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao) VALUES (?,?,?,?)",
                 (lead_id, session.get('nome'), 'criacao', 'Lead criado'))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "id": lead_id})


@app.route('/crm/lead/<int:lid>')
@login_required
def crm_lead_detalhe(lid):
    conn = db()
    lead = conn.execute("""SELECT l.*, u.nome as responsavel_nome
        FROM crm_leads l LEFT JOIN usuarios u ON u.id=l.responsavel_id
        WHERE l.id=?""", (lid,)).fetchone()
    if not lead:
        close_db(conn); return jsonify({"ok": False}), 404
    if session.get('perfil') != 'admin' and lead['responsavel_id'] != session['user_id']:
        close_db(conn); return jsonify({"ok": False, "erro": "Acesso negado"}), 403
    atividades = conn.execute(
        "SELECT * FROM crm_atividades WHERE lead_id=? ORDER BY id DESC", (lid,)).fetchall()
    # Usuários disponíveis para atribuição (admin vê todos)
    usuarios = []
    if session.get('perfil') == 'admin':
        usuarios = [dict(u) for u in conn.execute(
            "SELECT id, nome, perfil FROM usuarios WHERE ativo=1 ORDER BY nome").fetchall()]
    etapas = [dict(e) for e in carregar_etapas_crm(conn)]
    fluxos_disponiveis = [dict(f) for f in conn.execute(
        "SELECT id, nome FROM fluxos WHERE ativo=1 ORDER BY nome").fetchall()]
    fluxos_ativos = [dict(i) for i in conn.execute("""
        SELECT fi.id, fi.passo_atual, fi.proximo_envio_em, f.nome AS fluxo_nome,
               (SELECT COUNT(*) FROM fluxo_passos WHERE fluxo_id=f.id) AS total_passos
        FROM fluxo_inscricoes fi JOIN fluxos f ON f.id = fi.fluxo_id
        WHERE fi.lead_id=? AND fi.status='ativo' ORDER BY fi.id DESC
    """, (lid,)).fetchall()]
    close_db(conn)
    return jsonify({
        "lead": dict(lead),
        "atividades": [dict(a) for a in atividades],
        "usuarios": usuarios,
        "etapas": etapas,
        "fluxos_disponiveis": fluxos_disponiveis,
        "fluxos_ativos": fluxos_ativos
    })


