def _notificar_leads_parados():
    """Diário: avisa cada consultor dos leads ativos sem atividade há 7+ dias."""
    try:
        conn = db()
        limite = (datetime.now(TZ_SP) - timedelta(days=7)).strftime('%Y-%m-%d %H:%M:%S')
        rows = conn.execute("""
            SELECT l.responsavel_id, COUNT(*) qtd
            FROM crm_leads l
            WHERE l.responsavel_id IS NOT NULL
              AND l.etapa NOT IN (SELECT slug FROM crm_etapas WHERE tipo IN ('ganho','perdido'))
              AND COALESCE((SELECT MAX(a.criado_em) FROM crm_atividades a WHERE a.lead_id = l.id),
                           l.atualizado_em, l.criado_em) <= ?
            GROUP BY l.responsavel_id""", (limite,)).fetchall()
        close_db(conn)
        for r in rows:
            rd = dict(r)
            if rd.get('qtd'):
                _notificar(rd['responsavel_id'], 'lead', 'Leads parados',
                           f"{rd['qtd']} lead(s) sem atividade há mais de 7 dias", '/crm')
    except Exception as e:
        try: app.logger.warning(f"[LEADS-PARADOS] {e}")
        except Exception: pass


def _enviar_lembretes_agenda():
    """Roda no scheduler: notifica (sino + WhatsApp) atividades que vencem nos
    próximos 30 min ou já venceram sem lembrete. Marca para não repetir."""
    try:
        conn = db()
        limite = (datetime.now(TZ_SP) + timedelta(minutes=30)).strftime('%Y-%m-%d %H:%M')
        rows = conn.execute("""SELECT a.*, l.nome lead_nome, l.telefone lead_tel FROM crm_agenda a
            JOIN crm_leads l ON l.id=a.lead_id
            WHERE a.status='pendente' AND COALESCE(a.lembrete_enviado,0)=0 AND a.data_hora <= ?""",
            (limite,)).fetchall()
        for r in rows:
            d = dict(r)
            token = d.get('confirmar_token') or secrets.token_urlsafe(9)
            conn.execute("UPDATE crm_agenda SET lembrete_enviado=1, confirmar_token=? WHERE id=?", (token, d['id']))
            conn.commit()
            app.logger.info(f"[AGENDA] disparando lembrete id={d['id']} usuario_id={d.get('usuario_id')} assunto={d.get('assunto')!r}")
            try:
                partes = [f"Lead: {d.get('lead_nome')}", f"Quando: {_fmt_datahora_br(d.get('data_hora'))}"]
                if d.get('lead_tel'):
                    partes.append(f"Telefone: {d.get('lead_tel')}")
                if d.get('descricao'):
                    partes.append(f"Detalhes: {d.get('descricao')}")
                partes.append(f"\nJá vi e vou executar: {_SITE_BASE_URL}/a/{token}")
                _notificar(d.get('usuario_id'), 'lead', f"Lembrete: {d.get('assunto')}",
                           '\n'.join(partes), f"/crm?lead={d['lead_id']}")
            except Exception as e:
                app.logger.warning(f"[AGENDA] falha ao notificar lembrete id={d['id']}: {e}")
        close_db(conn)
    except Exception as e:
        try: app.logger.warning(f"[AGENDA] lembretes: {e}")
        except Exception: pass


@app.route('/cotacao/salvas')
@login_required
def cotacao_salvas():
    """Lista de cotações salvas (histórico), por cliente e corretor, com busca."""
    conn = db()
    eh_admin = session.get('perfil') == 'admin'
    q = (request.args.get('q') or '').strip()
    base = "SELECT * FROM cotacao_salva WHERE 1=1"
    params = []
    if not eh_admin:
        base += " AND corretor_id=?"; params.append(session.get('user_id'))
    if q:
        base += " AND (LOWER(cliente_nome) LIKE ? OR LOWER(titulo) LIKE ? OR cliente_telefone LIKE ?)"
        like = f"%{q.lower()}%"
        params.extend([like, like, f"%{q}%"])
    base += " ORDER BY id DESC"
    rows = conn.execute(base, params).fetchall()
    total = conn.execute(
        "SELECT COUNT(*) c FROM cotacao_salva" + ("" if eh_admin else " WHERE corretor_id=?"),
        ([] if eh_admin else [session.get('user_id')])).fetchone()['c']
    close_db(conn)
    return render_template('cotacao_salvas.html', cotacoes=rows, eh_admin=eh_admin, q=q, total=total)


