@app.route('/webhook/sheets', methods=['POST'])
def webhook_sheets():
    """
    Recebe leads do Google Sheets via Apps Script.
    Payload esperado:
    {
      "token": "SEU_TOKEN_AQUI",
      "origem": "Facebook" | "Google" | "MedSenior",
      "leads": [
        {
          "data_hora": "28/05/2026 10:35",
          "consultor": "DANILO",
          "nome": "Fulano",
          "telefone": "19999999999",
          "email": "fulano@gmail.com",
          "cidade": "Campinas",
          "tipo": "PF",
          "num_pessoas": "1"
        }, ...
      ]
    }
    """
    try:
        data = request.get_json(force=True) or {}

        # Validar token
        token_esperado = os.environ.get('SHEETS_WEBHOOK_TOKEN', 'serenus_sheets_2026')
        token_recebido = data.get('token', '')
        if token_recebido != token_esperado:
            app.logger.warning(f"[WEBHOOK_SHEETS] Token inválido: '{token_recebido}'")
            return jsonify({"ok": False, "erro": "Token inválido"}), 401

        origem = data.get('origem', 'Sheets')
        leads_raw = data.get('leads', [])
        modo = data.get('modo', 'normal')  # 'normal' reativa leads; 'historico' não reativa

        if not leads_raw:
            app.logger.info(f"[WEBHOOK_SHEETS] {origem}: nenhum lead enviado")
            return jsonify({"ok": True, "importados": 0, "msg": "Nenhum lead enviado"}), 200

        app.logger.info(f"[WEBHOOK_SHEETS] {origem}: recebidos {len(leads_raw)} leads brutos")

        conn = db()
        importados = 0
        duplicados = 0
        ignorados = 0

        for lead in leads_raw:
            nome     = (lead.get('nome') or '').strip()
            telefone_raw = (lead.get('telefone') or '').strip()
            email    = (lead.get('email') or '').strip()
            cidade   = (lead.get('cidade') or '').strip()
            tipo     = (lead.get('tipo') or 'PF').strip()
            num_pess = (lead.get('num_pessoas') or '').strip()
            # Consultor: SEMPRE só a coluna "Consultor" (nunca "Consultor 2" como fallback —
            # pedido explícito do Guilherme, "Consultor 2" não é confiável pra atribuição)
            cons_raw = (lead.get('consultor') or '').strip()
            # Data: aceita 'data_hora' ou 'data'
            data_hora_raw = (lead.get('data_hora') or lead.get('data') or '').strip()

            # DEBUG: primeiros 3 leads de cada origem, log a data
            if importados + duplicados + ignorados < 3:
                app.logger.info(f"[WEBHOOK_SHEETS] DEBUG {origem} lead {importados+duplicados+ignorados}: data_hora_raw='{data_hora_raw}' | nome='{nome[:30]}'")

            # Telefone: formata bonito p/ exibição + normaliza p/ dedup
            telefone = _formatar_telefone(telefone_raw)   # (19) 99104-6030
            telefone_norm = _normalizar_telefone(telefone_raw)  # 19991046030

            # Filtro: "teste" no nome ou email
            if nome and 'teste' in nome.lower():
                ignorados += 1; continue
            if email and 'teste' in email.lower():
                ignorados += 1; continue
            if not nome:
                app.logger.warning(f"[WEBHOOK_SHEETS] {origem}: lead ignorado (nome vazio) | telefone={telefone_raw} email={email}")
                ignorados += 1; continue

            # Normalizar consultor + busca FLEXÍVEL do responsável.
            # Planilha sem Consultor preenchido → fica SEM responsável (nunca chuta
            # 'Guilherme' por padrão — isso mascarava leads órfãos como se fossem dele).
            consultor = _normalizar_consultor(cons_raw)
            responsavel_id = _buscar_responsavel_id(conn, consultor) if consultor else None
            # Se não achou no banco, guarda o nome original como externo
            consultor_externo = cons_raw if (cons_raw and not responsavel_id) else None

            # Data do lead (vinda da planilha)
            data_lead = _parse_data_lead(data_hora_raw)
            data_str = data_lead.strftime('%d/%m/%Y') if data_lead else _fmt_data_br(datetime.now(TZ_SP))

            # DEBUG: log para diagnosticar parsing de datas
            if not data_lead:
                app.logger.warning(f"[WEBHOOK_SHEETS] Data não parseada: '{data_hora_raw}' | nome={nome} | origem={origem}")

            obs = f"Tipo: {tipo}"
            if num_pess:
                obs += f" | Pessoas: {num_pess}"

            # UTM/click (mesma lógica de _processar_lead) — o Apps Script pode mandar
            # esses campos junto do lead; se não mandar, fica vazio (sem quebrar nada).
            utm_medium = (lead.get('utm_medium') or '').strip()
            gclid = (lead.get('gclid') or '').strip()
            _med = utm_medium.lower()
            if _med in ('cpc', 'ppc', 'paid', 'paidsearch', 'paid_search', 'paid-search', 'display', 'cpm'):
                trafego = 'Pago'
            elif utm_medium or (lead.get('utm_source') or '').strip() or (lead.get('utm_campaign') or '').strip():
                trafego = 'Orgânico'
            else:
                trafego = None
            click = {k: (lead.get(k) or '').strip() for k in
                     ('utm_source', 'utm_medium', 'utm_campaign', 'utm_term', 'utm_content', 'gclid', 'landing_url')}
            click = {k: v for k, v in click.items() if v}
            dados_extras_wh = json.dumps({'click': click}, ensure_ascii=False) if click else None

            # ── Verificar se lead já existe (por telefone OU email) ──
            # Usa telefone_norm (só dígitos) comparado contra telefone_norm do banco
            lead_existente = None
            if telefone_norm:
                lead_existente = conn.execute(
                    "SELECT id, etapa, nome, criado_em FROM crm_leads WHERE telefone_norm = ?",
                    (telefone_norm,)
                ).fetchone()
            # Fallback: compara só dígitos do telefone bruto armazenado
            if not lead_existente and telefone_norm and len(telefone_norm) >= 8:
                lead_existente = conn.execute(
                    "SELECT id, etapa, nome, criado_em FROM crm_leads WHERE REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(telefone,'-',''),' ',''),'(',''),')',''),'+','') LIKE ?",
                    (f'%{telefone_norm[-8:]}',)
                ).fetchone()
            if not lead_existente and email:
                lead_existente = conn.execute(
                    "SELECT id, etapa, nome, criado_em FROM crm_leads WHERE LOWER(email) = LOWER(?)",
                    (email,)
                ).fetchone()

            if lead_existente:
                lid = lead_existente['id'] if hasattr(lead_existente, 'keys') else lead_existente[0]
                etapa_anterior = lead_existente['etapa'] if hasattr(lead_existente, 'keys') else lead_existente[1]
                criado_existente = lead_existente['criado_em'] if hasattr(lead_existente, 'keys') else lead_existente[3]

                # Converte criado_existente para date para comparar
                data_criacao_banco = _parse_data_lead(str(criado_existente)) if criado_existente else None

                # ── PREENCHER RESPONSÁVEL SE ÓRFÃO ──
                # Lead da Meta muitas vezes entra sem consultor (coluna B vazia na hora)
                # e o nome é preenchido depois na planilha. Quando o Apps Script reenvia
                # e agora vem consultor reconhecido, preenche o responsável SÓ SE estiver
                # NULL. Nunca sobrescreve atribuição existente → protege transferências
                # manuais (Danilo/Bianca/Gabriel/Guilherme → Prisciele/Jenifer/Juliana).
                if responsavel_id:
                    r_atual = conn.execute("SELECT responsavel_id FROM crm_leads WHERE id=?", (lid,)).fetchone()
                    r_atual_val = (r_atual['responsavel_id'] if hasattr(r_atual, 'keys') else r_atual[0]) if r_atual else None
                    if r_atual_val is None:
                        conn.execute("UPDATE crm_leads SET responsavel_id=?, consultor_externo=NULL, atualizado_em=? WHERE id=? AND responsavel_id IS NULL",
                                     (responsavel_id, _agora_sp(), lid))
                        conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                                     (lid, consultor or 'Sistema', 'movimentacao',
                                      f'Consultor {consultor} atribuído da planilha (lead estava sem responsável)', _agora_sp()))

                # ── DECISÃO: reativar ou apenas atualizar? ──
                # Reativa SOMENTE se a nova solicitação for MAIS RECENTE que a criação
                # do lead E o modo não for 'historico'. Isso evita que reimportação
                # de histórico mova todos os leads para "lead_novo".
                eh_nova_solicitacao = (
                    modo != 'historico'
                    and data_lead is not None
                    and data_criacao_banco is not None
                    and data_lead > data_criacao_banco
                    and etapa_anterior != 'lead_novo'
                )

                if eh_nova_solicitacao:
                    # Lead voltou a solicitar de verdade → move para lead_novo
                    conn.execute("""
                        UPDATE crm_leads SET
                            nome = COALESCE(NULLIF(?, ''), nome),
                            email = COALESCE(NULLIF(?, ''), email),
                            empresa = COALESCE(NULLIF(?, ''), empresa),
                            origem = ?,
                            etapa = 'lead_novo',
                            atualizado_em = ?
                        WHERE id = ?
                    """, (nome, email, cidade, origem, _agora_sp(), lid))
                    conn.execute("""
                        INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao)
                        VALUES (?, ?, 'movimentacao', ?)
                    """, (lid, consultor or 'Sistema',
                          f'Nova solicitação em {data_str} via {origem} — retornou de "{etapa_anterior}" para Lead Novo'))
                    importados += 1
                else:
                    # É reimportação OU registro antigo/duplicado.
                    # Apenas corrige a data de criação se a do banco estiver errada
                    # (importada com data do dia) e tivermos uma data real da planilha.
                    if data_lead and criado_existente:
                        criado_str = str(criado_existente)
                        if ('2026-06-22' in criado_str or '2026-06-23' in criado_str or '2026-06-24' in criado_str):
                            conn.execute(
                                "UPDATE crm_leads SET criado_em=? WHERE id=?",
                                (data_lead.strftime('%Y-%m-%d 12:00:00'), lid)
                            )
                    duplicados += 1
                continue

            # ── NOVO LEAD: não existe no banco ──
            # SEMPRE usa data_lead se disponível, senão usa hoje
            data_criacao = data_lead.strftime('%Y-%m-%d 12:00:00') if data_lead else datetime.now(TZ_SP).strftime('%Y-%m-%d %H:%M:%S')

            conn.execute("""
                INSERT INTO crm_leads
                    (nome, telefone, telefone_norm, email, empresa, origem, etapa, responsavel_id, observacoes, criado_em, consultor_externo, trafego, gclid, dados_extras)
                    VALUES (?, ?, ?, ?, ?, ?, 'lead_novo', ?, ?, ?, ?, ?, ?, ?)
            """, (nome, telefone, telefone_norm, email, cidade, origem, responsavel_id, obs,
                  data_criacao, consultor_externo, trafego, gclid or None, dados_extras_wh))

            lead_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE=="postgres" else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
            conn.execute("""
                INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao)
                VALUES (?, ?, 'criacao', ?)
            """, (lead_id, consultor or 'Sistema', f'Lead importado via {origem} em {data_str}'))
            # Webhook = tempo real (o Apps Script empurra na hora, sem esperar o pull de
            # 15min). É aqui que o atendimento imediato do lead PAGO fica de fato instantâneo.
            try:
                _atender_lead_pago_auto(conn, lead_id)
            except Exception:
                pass

            importados += 1

        try:
            conn.commit()
        except Exception as ec:
            app.logger.error(f"[WEBHOOK_SHEETS] Erro ao fazer commit: {ec}")
            try:
                conn.rollback()
            except:
                pass
        finally:
            close_db(conn)

        app.logger.info(f"[WEBHOOK_SHEETS] {origem}: importados={importados} duplicados={duplicados} ignorados={ignorados}")
        return jsonify({
            "ok": True,
            "importados": importados,
            "duplicados": duplicados,
            "ignorados": ignorados
        }), 200

    except Exception as e:
        import traceback as _tb2
        tb = _tb2.format_exc()
        app.logger.error(f"[WEBHOOK_SHEETS] Erro crítico: {e}\n{tb}")
        return jsonify({"ok": False, "erro": str(e)[:200]}), 500


# ─── INTEGRAÇÃO WHATSAPP (WaSpeed / Wascript) ────────────────────────────────────
# Doc: https://api-whatsapp.wascript.com.br/api-docs/
# Cada gestor pode ter seu próprio token (coluna usuarios.waspeed_token).
# Fallback: variável de ambiente WASPEED_TOKEN.
WASPEED_BASE = 'https://api-whatsapp.wascript.com.br'

def _waspeed_token_do_usuario(conn, uid):
    """Retorna o token WaSpeed do usuário, ou o global (env), ou None."""
    try:
        row = conn.execute("SELECT waspeed_token FROM usuarios WHERE id=?", (uid,)).fetchone()
        if row:
            tk = row['waspeed_token'] if hasattr(row, 'keys') else row[0]
            if tk:
                return tk
    except Exception:
        pass
    return os.environ.get('WASPEED_TOKEN', '') or None

def _waspeed_normaliza_fone(telefone):
    """Garante formato 55DDDNUMERO (só dígitos)."""
    import re as _re
    n = _re.sub(r'\D', '', telefone or '')
    if not n:
        return ''
    # Se não começa com 55 e tem 10-11 dígitos (DDD+numero), prefixa 55
    if not n.startswith('55') and len(n) in (10, 11):
        n = '55' + n
    return n


def _enviar_whatsapp_waspeed(token, fone, mensagem):
    """Envia texto via WaSpeed. token: usuarios.waspeed_token ou env WASPEED_TOKEN.
    Retorna (ok: bool, erro: str|None). Nunca lança exceção."""
    if not token:
        return False, "Token WaSpeed não configurado"
    fone_norm = _waspeed_normaliza_fone(fone)
    if not fone_norm:
        return False, "Telefone inválido"
    try:
        import requests as _rq
        r = _rq.post(f"{WASPEED_BASE}/api/enviar-texto/{token}",
                      json={"phone": fone_norm, "message": mensagem}, timeout=20)
        try:
            j = r.json()
        except Exception:
            return False, r.text[:200]
        if j.get('success'):
            return True, None
        return False, f"WaSpeed: {j.get('message', 'erro desconhecido')}"
    except Exception as e:
        return False, f"Falha ao enviar WhatsApp: {e}"


# WhatsApp da corretora (BootConversa + API oficial Meta) — usado pelas 3 consultoras
# de retrabalho. Os demais consultores usam o próprio WhatsApp pessoal (usuarios.telefone).
NUMERO_WHATSAPP_SERENUS = '5519936196877'
CONSULTORAS_BOOTCONVERSA = ('Prisciele Azevedo', 'Juliana Azevedo', 'Jenifer Aparecida Lobregat dos Santos')

# ID de "manager" (atendente) de cada menina dentro do BotConversa — usado pra
# reatribuir a titularidade da conversa quando o lead é transferido pra elas
# no JOB. Descoberto via GET /managers/ da API do BotConversa (não muda
# sozinho, só se a conta de alguma delas for recriada lá).
BOTCONVERSA_MANAGER_IDS = {
    'Prisciele Azevedo': 603923,
    'Juliana Azevedo': 599938,
    'Jenifer Aparecida Lobregat dos Santos': 603922,
}
BOTCONVERSA_API_BASE = 'https://backend.botconversa.com.br/api/v1/webhook'


def _botconversa_transferir_titularidade(telefone, menina_nome):
    """Reatribui a conversa do lead (por telefone) pro atendente certo no
    BotConversa, quando o responsável no JOB vira uma das 3 meninas — a
    titularidade muda nos dois sistemas ao mesmo tempo, não só no JOB.
    Nunca lança exceção (best-effort — se o BotConversa falhar, a transferência
    no JOB já aconteceu e continua valendo; só não sincroniza lá).
    Retorna (ok: bool, msg: str)."""
    api_key = os.environ.get('BOTCONVERSA_API_KEY', '').strip()
    if not api_key:
        return False, 'BOTCONVERSA_API_KEY não configurada'
    manager_id = BOTCONVERSA_MANAGER_IDS.get(menina_nome)
    if not manager_id:
        return False, f'"{menina_nome}" não é uma consultora do BotConversa'
    digitos = re.sub(r'\D', '', telefone or '')
    if not digitos:
        return False, 'Lead sem telefone'
    if len(digitos) <= 11:
        digitos = '55' + digitos
    try:
        import requests as _rq
        headers = {'API-KEY': api_key}
        r = _rq.get(f'{BOTCONVERSA_API_BASE}/subscriber/get_by_phone/{digitos}/', headers=headers, timeout=15)
        if r.status_code == 404:
            return False, 'Lead não tem conversa no BotConversa (nunca escreveu pelo WhatsApp oficial)'
        if r.status_code != 200:
            return False, f'BotConversa: erro {r.status_code} ao buscar assinante'
        subscriber_id = r.json().get('id')
        if not subscriber_id:
            return False, 'BotConversa: assinante sem id na resposta'
        r2 = _rq.post(f'{BOTCONVERSA_API_BASE}/subscriber/{subscriber_id}/change_conversation_status/',
                       headers={**headers, 'Content-Type': 'application/json'},
                       json={'open_conversation': True, 'manager': manager_id}, timeout=15)
        if r2.status_code not in (200, 201, 204):
            return False, f'BotConversa: erro {r2.status_code} ao reatribuir'
        return True, f'Conversa reatribuída a {menina_nome} no BotConversa'
    except Exception as e:
        return False, f'Falha ao falar com o BotConversa: {e}'


def _whatsapp_do_consultor(conn, responsavel_id):
    """Retorna o número (só dígitos, com 55) que o LEAD deve chamar pra falar com
    o consultor responsável. Prisciele/Juliana/Jenifer usam o WhatsApp oficial da
    Serenus via BootConversa (número fixo); os demais usam o WhatsApp pessoal deles."""
    if responsavel_id:
        row = conn.execute("SELECT nome, telefone FROM usuarios WHERE id=?", (responsavel_id,)).fetchone()
        if row:
            rd = dict(row)
            if rd['nome'] in CONSULTORAS_BOOTCONVERSA:
                return NUMERO_WHATSAPP_SERENUS
            fone = _waspeed_normaliza_fone(rd.get('telefone') or '')
            if fone:
                return fone
    return NUMERO_WHATSAPP_SERENUS


