def _fluxo_inscrever(conn, fluxo_id, lead_id, etapa_origem=None, iniciado_por=None):
    """Cria uma inscrição ativa (se ainda não houver uma ativa pro mesmo lead+fluxo).
    Respeita o delay do 1º passo: delay 0 sai na próxima rodada do motor."""
    ja = conn.execute(
        "SELECT id FROM fluxo_inscricoes WHERE fluxo_id=? AND lead_id=? AND status='ativo'",
        (fluxo_id, lead_id)).fetchone()
    if ja:
        return None
    p0 = conn.execute(
        "SELECT delay_dias FROM fluxo_passos WHERE fluxo_id=? ORDER BY ordem LIMIT 1", (fluxo_id,)).fetchone()
    delay0 = (p0['delay_dias'] if p0 else 0) or 0
    envio = (datetime.now(TZ_SP) + timedelta(days=delay0)).strftime('%Y-%m-%d %H:%M:%S')
    conn.execute("""INSERT INTO fluxo_inscricoes
        (fluxo_id, lead_id, etapa_origem, status, passo_atual, proximo_envio_em, iniciado_por)
        VALUES (?,?,?,'ativo',0,?,?)""",
        (fluxo_id, lead_id, etapa_origem, envio, iniciado_por))
    return (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
            else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])


def _fluxo_cancelar_por_etapa(conn, lead_id, nova_etapa):
    """Cancela inscrições ativas cujo fluxo está preso a uma etapa (gatilho_etapa)
    diferente da nova etapa do lead. Fluxos iniciados manualmente (sem gatilho_etapa)
    não são afetados por mudança de etapa — só cancelamento manual os para."""
    ativas = conn.execute("""
        SELECT fi.id FROM fluxo_inscricoes fi JOIN fluxos f ON f.id = fi.fluxo_id
        WHERE fi.lead_id=? AND fi.status='ativo' AND f.gatilho_etapa IS NOT NULL AND f.gatilho_etapa <> ?
    """, (lead_id, nova_etapa)).fetchall()
    for row in ativas:
        conn.execute("UPDATE fluxo_inscricoes SET status='cancelado', finalizado_em=? WHERE id=?",
                     (_agora_sp(), row['id']))


def _fluxo_autoiniciar_por_etapa(conn, lead_id, nova_etapa):
    """Inscreve o lead em qualquer fluxo ativo cujo gatilho_etapa bate com a etapa nova."""
    fluxos = conn.execute("SELECT id FROM fluxos WHERE ativo=1 AND gatilho_etapa=?", (nova_etapa,)).fetchall()
    for f in fluxos:
        _fluxo_inscrever(conn, f['id'], lead_id, etapa_origem=nova_etapa)


_FLUXO_MAX_POR_RODADA = 50
FLUXO_CANAIS = ('email', 'sms', 'whatsapp', 'botconversa')


def _renderizar_modelo_html(html, nome_lead):
    """Substitui os placeholders de nome no HTML enviado pelo admin. Cobre tanto
    {{nome}} (convenção do JOB) quanto {{ contact.FIRSTNAME }} (tag nativa do
    Brevo) — como o envio é pela API transacional, não pela automação do Brevo,
    essa segunda tag nunca seria substituída sozinha; sem isso o e-mail chegaria
    com "{{ contact.FIRSTNAME }}" literal no texto."""
    primeiro = (nome_lead or '').strip().split(' ')[0].title() if nome_lead else 'tudo bem'
    out = html or ''
    for token in ('{{nome}}', '{{ nome }}', '{{contact.FIRSTNAME}}', '{{ contact.FIRSTNAME }}'):
        out = out.replace(token, primeiro)
    return out


def _fluxo_executar_passo(conn, passo, lead):
    """Executa 1 passo do fluxo pra 1 lead. Retorna (ok, erro, modelo_id).
    Conteúdo do passo: personalizado (JSON gravado pelo editor), modelo pronto
    do catálogo embutido (FLUXO_TEMPLATES/SMS_TEMPLATES_LEAD), ou modelo
    enviado pelo admin (tabela modelos_conteudo, chave 'upload_<id>')."""
    template_key = passo['template'] or ''
    modelo_id = None
    tpl = None

    if template_key.startswith('upload_'):
        try:
            modelo_id = int(template_key.split('_', 1)[1])
        except (ValueError, IndexError):
            modelo_id = None
        modelo = conn.execute("SELECT * FROM modelos_conteudo WHERE id=? AND ativo=1", (modelo_id,)).fetchone() if modelo_id else None
        if not modelo:
            return False, f"Modelo enviado #{modelo_id} não existe mais ou foi desativado", modelo_id
        modelo = dict(modelo)
        tpl = {'assunto': modelo.get('assunto') or '', 'corpo_html': modelo.get('corpo_html'),
               'corpo_texto': modelo.get('corpo_texto')}
    elif passo.get('conteudo'):
        try:
            tpl = json.loads(passo['conteudo']) if isinstance(passo['conteudo'], str) else dict(passo['conteudo'])
        except Exception:
            tpl = None
    if tpl is None and not template_key.startswith('upload_'):
        tpl = FLUXO_TEMPLATES.get(template_key)

    urow = conn.execute("SELECT id, nome, foto FROM usuarios WHERE id=?",
                         (lead.get('responsavel_id'),)).fetchone()
    consultor_nome = (urow['nome'] if urow else None) or 'Serenus'
    foto_url = f"{_SITE_BASE_URL}/avatar/{urow['id']}" if urow and urow['foto'] else None
    primeiro = (lead.get('nome') or '').strip().split(' ')[0].title()
    link_wpp = f"https://wa.me/{_whatsapp_do_consultor(conn, lead.get('responsavel_id'))}"
    canal = passo['canal']

    if canal == 'email':
        email_lead = (lead.get('email') or '').strip()
        if not email_lead or '@' not in email_lead:
            return False, 'Lead sem e-mail válido', modelo_id
        if modelo_id is not None:
            if not tpl.get('corpo_html'):
                return False, f"Modelo enviado #{modelo_id} está sem HTML", modelo_id
            assunto = _renderizar_modelo_html(tpl.get('assunto') or 'Serenus Corretora', lead.get('nome'))
            corpo = _renderizar_modelo_html(tpl['corpo_html'], lead.get('nome'))
            ok = _enviar_email(email_lead, assunto, corpo, remetente_nome='Cotação de Plano de Saúde')
            return ok, (None if ok else (getattr(_enviar_email, 'ultimo_erro', None) or 'Falha ao enviar e-mail')), modelo_id
        if not tpl or not tpl.get('paragrafos'):
            return False, f"Passo de e-mail sem conteúdo (template: {template_key})", modelo_id
        assunto = _fluxo_render_texto(tpl.get('assunto') or 'Serenus Corretora',
                                       nome=primeiro or 'tudo bem', consultor=consultor_nome)
        corpo = _corpo_email_fluxo(tpl, lead.get('nome'), consultor_nome, link_wpp, foto_url)
        ok = _enviar_email(email_lead, assunto, corpo, remetente_nome='Cotação de Plano de Saúde')
        return ok, (None if ok else (getattr(_enviar_email, 'ultimo_erro', None) or 'Falha ao enviar e-mail')), modelo_id

    if not lead.get('telefone'):
        return False, 'Lead sem telefone', modelo_id

    if modelo_id is not None and canal == 'sms':
        mensagem = _renderizar_modelo_html(tpl.get('corpo_texto') or '', lead.get('nome')).strip()
        if not mensagem:
            return False, f"Modelo enviado #{modelo_id} está sem texto", modelo_id
        ok, erro = _enviar_sms(lead['telefone'], mensagem)
        return ok, erro, modelo_id

    if canal == 'sms':
        if passo['template'] in SMS_TEMPLATES_LEAD:
            # Modelo aprovado na operadora: monta EXATAMENTE como no envio manual
            # (link wa.me do consultor, nunca truncar nome) — ver _texto_sms_lead.
            # split() em nome vazio devolve [] — o "or ['']" evita IndexError.
            nome_lead = ((lead.get('nome') or '').split() or [''])[0]
            consultor_primeiro = ((consultor_nome or '').split() or ['Serenus'])[0]
            mensagem, _n = _texto_sms_lead(passo['template'], consultor_primeiro, link_wpp, nome_lead)
        else:
            mensagem = _fluxo_render_texto((tpl or {}).get('texto'),
                                            nome=primeiro, consultor=consultor_nome, link=link_wpp).strip()
        if not mensagem:
            return False, 'Passo de SMS sem texto', modelo_id
        ok, erro = _enviar_sms(lead['telefone'], mensagem)
        return ok, erro, modelo_id

    texto = _fluxo_render_texto((tpl or {}).get('texto') or '\n\n'.join((tpl or {}).get('paragrafos') or []),
                                 nome=primeiro, consultor=consultor_nome, link=link_wpp).strip()
    if not texto:
        return False, f'Passo de {canal} sem texto', modelo_id
    if canal == 'whatsapp':
        token = _waspeed_token_do_usuario(conn, lead.get('responsavel_id'))
        ok, erro = _enviar_whatsapp_waspeed(token, lead.get('telefone'), texto)
        return ok, erro, modelo_id
    if canal == 'botconversa':
        ok, erro = _enviar_botconversa_texto(lead.get('telefone'), texto)
        return ok, erro, modelo_id
    return False, f'Canal desconhecido: {canal}', modelo_id


def _processar_fluxos_pendentes():
    """Motor de disparo: roda 1x/dia (+ fallback por request) e envia o passo
    pendente de cada inscrição ativa cujo proximo_envio_em já chegou.
    delay_dias de cada passo = dias de espera após o passo anterior."""
    try:
        conn = db()
        agora = datetime.now(TZ_SP)
        agora_str = _agora_sp()
        pendentes = conn.execute("""
            SELECT fi.*, f.nome AS fluxo_nome FROM fluxo_inscricoes fi
            JOIN fluxos f ON f.id = fi.fluxo_id
            WHERE fi.status='ativo' AND f.ativo=1 AND fi.proximo_envio_em <= ?
            ORDER BY fi.proximo_envio_em ASC LIMIT ?
        """, (agora_str, _FLUXO_MAX_POR_RODADA)).fetchall()
        enviados = 0
        for insc in pendentes:
            insc = dict(insc)
            # "Claim" atômico: empurra proximo_envio_em 15 min pra frente ANTES de
            # enviar e comita na hora. O gunicorn roda 3 workers, cada um com seu
            # scheduler — sem isso, os 3 leriam as mesmas inscrições às 08:00 e o
            # lead receberia cada passo em triplicata. Só quem ganha o UPDATE
            # (rowcount 1) processa; os outros veem 0 e pulam.
            claim = conn.execute(
                "UPDATE fluxo_inscricoes SET proximo_envio_em=? WHERE id=? AND status='ativo' AND proximo_envio_em<=?",
                ((agora + timedelta(minutes=15)).strftime('%Y-%m-%d %H:%M:%S'), insc['id'], agora_str))
            if getattr(claim, 'rowcount', 1) == 0:
                continue
            conn.commit()
            try:
                passos = [dict(p) for p in conn.execute(
                    "SELECT * FROM fluxo_passos WHERE fluxo_id=? ORDER BY ordem", (insc['fluxo_id'],)).fetchall()]
                passo_idx = insc['passo_atual']
                if passo_idx >= len(passos):
                    conn.execute("UPDATE fluxo_inscricoes SET status='concluido', finalizado_em=? WHERE id=?",
                                 (_agora_sp(), insc['id']))
                    conn.commit()
                    continue
                passo = passos[passo_idx]
                lead = conn.execute("SELECT * FROM crm_leads WHERE id=?", (insc['lead_id'],)).fetchone()
                if lead:
                    ok, erro, modelo_id = _fluxo_executar_passo(conn, passo, dict(lead))
                else:
                    ok, erro, modelo_id = False, 'Lead não encontrado', None
                conn.execute("INSERT INTO fluxo_envio_log (inscricao_id, passo_id, canal, ok, erro, modelo_id) VALUES (?,?,?,?,?,?)",
                             (insc['id'], passo['id'], passo['canal'], 1 if ok else 0, erro, modelo_id))
                proximo_passo_idx = passo_idx + 1
                if proximo_passo_idx >= len(passos):
                    conn.execute("UPDATE fluxo_inscricoes SET status='concluido', passo_atual=?, finalizado_em=? WHERE id=?",
                                 (proximo_passo_idx, _agora_sp(), insc['id']))
                else:
                    delay_prox = passos[proximo_passo_idx]['delay_dias'] or 0
                    proximo_envio = agora + timedelta(days=delay_prox)
                    conn.execute("UPDATE fluxo_inscricoes SET passo_atual=?, proximo_envio_em=? WHERE id=?",
                                 (proximo_passo_idx, proximo_envio.strftime('%Y-%m-%d %H:%M:%S'), insc['id']))
                conn.commit()
                if ok:
                    enviados += 1
            except Exception as e:
                # Uma inscrição com dado ruim NUNCA pode envenenar a rodada inteira
                # (travaria todos os fluxos pra sempre, sempre na mesma inscrição).
                # Rollback + reagenda pra amanhã e segue pras próximas.
                try:
                    conn.rollback()
                except Exception:
                    pass
                app.logger.error(f"[FLUXOS] Erro na inscrição {insc['id']} (lead {insc.get('lead_id')}): {e}")
                try:
                    conn.execute("UPDATE fluxo_inscricoes SET proximo_envio_em=? WHERE id=?",
                                 ((agora + timedelta(days=1)).strftime('%Y-%m-%d %H:%M:%S'), insc['id']))
                    conn.commit()
                except Exception:
                    pass
        close_db(conn)
        if enviados:
            app.logger.info(f"[FLUXOS] {enviados}/{len(pendentes)} passo(s) enviados")
    except Exception as e:
        app.logger.error(f"[FLUXOS] Erro no motor: {e}")
        try:
            close_db(conn)
        except Exception:
            pass


@app.route('/crm/fluxos')
@login_required
@admin_required
def crm_fluxos():
    conn = db()
    fluxos = [dict(f) for f in conn.execute("SELECT * FROM fluxos ORDER BY id").fetchall()]
    for f in fluxos:
        f['passos'] = [dict(p) for p in conn.execute(
            "SELECT * FROM fluxo_passos WHERE fluxo_id=? ORDER BY ordem", (f['id'],)).fetchall()]
        f['ativos'] = conn.execute(
            "SELECT COUNT(*) c FROM fluxo_inscricoes WHERE fluxo_id=? AND status='ativo'", (f['id'],)).fetchone()['c']
        f['concluidos'] = conn.execute(
            "SELECT COUNT(*) c FROM fluxo_inscricoes WHERE fluxo_id=? AND status='concluido'", (f['id'],)).fetchone()['c']
    etapas = [dict(e) for e in carregar_etapas_crm(conn)]
    close_db(conn)
    return render_template('crm_fluxos.html', fluxos=fluxos, etapas=etapas)


@app.route('/crm/fluxos/<int:fid>/toggle', methods=['POST'])
@login_required
@admin_required
def crm_fluxo_toggle(fid):
    conn = db()
    f = conn.execute("SELECT ativo FROM fluxos WHERE id=?", (fid,)).fetchone()
    if not f:
        close_db(conn); return jsonify({"ok": False, "erro": "Fluxo não encontrado"}), 404
    novo = 0 if f['ativo'] else 1
    conn.execute("UPDATE fluxos SET ativo=? WHERE id=?", (novo, fid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "ativo": bool(novo)})


@app.route('/crm/fluxos/<int:fid>/gatilho', methods=['POST'])
@login_required
@admin_required
def crm_fluxo_gatilho(fid):
    """Define (ou remove) a etapa do funil que dispara este fluxo automaticamente."""
    d = request.json or {}
    gatilho = (d.get('gatilho_etapa') or '').strip() or None
    conn = db()
    f = conn.execute("SELECT id FROM fluxos WHERE id=?", (fid,)).fetchone()
    if not f:
        close_db(conn); return jsonify({"ok": False, "erro": "Fluxo não encontrado"}), 404
    conn.execute("UPDATE fluxos SET gatilho_etapa=? WHERE id=?", (gatilho, fid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


@app.route('/crm/fluxos/novo', methods=['POST'])
@login_required
@admin_required
def crm_fluxo_novo():
    d = request.json or {}
    nome = (d.get('nome') or '').strip()
    if not nome:
        return jsonify({"ok": False, "erro": "Digite o nome do fluxo"}), 400
