_MODELO_WPP_EXTS_IMG = ('.jpg', '.jpeg', '.png', '.webp', '.gif')
_MODELO_WPP_EXTS_AUDIO = ('.mp3', '.ogg', '.oga', '.m4a', '.opus', '.wav')
_MODELO_WPP_EXTS_VIDEO = ('.mp4', '.mov', '.m4v', '.3gp')
_MODELO_WPP_EXTS_DOC = ('.pdf',)


def _midia_tipo_por_ext(ext):
    """Extensão -> tipo de mídia do modelo (imagem/audio/video/documento) ou None."""
    ext = (ext or '').lower()
    if ext in _MODELO_WPP_EXTS_IMG: return 'imagem'
    if ext in _MODELO_WPP_EXTS_AUDIO or ext == '.webm': return 'audio'
    if ext in _MODELO_WPP_EXTS_VIDEO: return 'video'
    if ext in _MODELO_WPP_EXTS_DOC: return 'documento'
    return None


# Teto por tipo (vídeo/PDF são maiores; WhatsApp aguenta ~16MB de vídeo).
_MODELO_WPP_LIMITE = {'imagem': 8_000_000, 'audio': 16_000_000, 'video': 16_000_000, 'documento': 16_000_000}


@app.route('/crm/modelos/whatsapp/novo', methods=['POST'])
@login_required
@admin_required
def crm_modelo_whatsapp_novo():
    """Modelo de mensagem de WhatsApp — base da biblioteca reutilizável (pedido
    explícito do Guilherme, pra depois virar funil). Texto sempre obrigatório;
    mídia é opcional e SÓ áudio OU imagem, nunca as duas (mantém simples e
    compatível com como wa-js manda cada tipo — decisão registrada no plano).
    Autoria fica só aqui (site, admin) — a extensão só lê e manda o texto pela
    fila que já existe; ela nunca cria/edita modelo (chave de extensão é
    única e compartilhada entre consultores, não é identidade individual)."""
    nome = (request.form.get('nome') or '').strip()
    texto = (request.form.get('texto') or '').strip()
    variante = (request.form.get('variante') or '').strip() or None
    if not nome or not texto:
        return jsonify({"ok": False, "erro": "Nome e texto da mensagem são obrigatórios"}), 400
    if len(texto) > 4000:
        return jsonify({"ok": False, "erro": "Texto longo demais (máx. 4000 caracteres)"}), 400

    midia_arquivo, midia_tipo = None, None
    f = request.files.get('arquivo_midia')
    if f and f.filename:
        ext = os.path.splitext(f.filename)[1].lower()
        midia_tipo = _midia_tipo_por_ext(ext)
        if not midia_tipo:
            return jsonify({"ok": False, "erro": f"Formato não aceito: {ext} (imagem, áudio, vídeo mp4/mov, ou PDF)"}), 400
        f.stream.seek(0, os.SEEK_END)
        tamanho = f.stream.tell()
        f.stream.seek(0)
        limite = _MODELO_WPP_LIMITE.get(midia_tipo, 8_000_000)
        if tamanho > limite:
            return jsonify({"ok": False, "erro": f"Arquivo grande demais (máx. {limite // 1_000_000}MB)"}), 400
        nome_arquivo = f"MODELO_WPP_{datetime.now(TZ_SP).strftime('%Y%m%d%H%M%S')}_{_sanitizar_filename(f.filename)}"
        resultado = upload_arquivo_r2(f.stream, f"modelos/{nome_arquivo}")
        if not resultado.get('ok'):
            return jsonify({"ok": False, "erro": f"Erro ao salvar mídia: {resultado.get('erro', 'desconhecido')}"}), 500
        midia_arquivo = nome_arquivo

    categoria = (request.form.get('categoria') or '').strip()[:80] or None
    conn = db()
    conn.execute("""INSERT INTO modelos_conteudo (tipo, nome, corpo_texto, variante, ativo, criado_por, midia_arquivo, midia_tipo, categoria)
                    VALUES ('whatsapp',?,?,?,1,?,?,?,?)""",
                 (nome, texto, variante, session.get('user_id'), midia_arquivo, midia_tipo, categoria))
    mid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
           else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "id": mid})


def _zv_categoria_do_nome(nome):
    """Deriva categoria do nome no padrão ZapVoice ("... - GNDI" -> "GNDI")."""
    if nome and ' - ' in nome:
        cand = nome.rsplit(' - ', 1)[-1].strip()
        if 1 <= len(cand) <= 40:
            return cand
    return None


@app.route('/crm/modelos/importar-zapvoice', methods=['POST'])
@login_required
@admin_required
def crm_importar_zapvoice():
    """Importa um backup do ZapVoice (JSON) pra biblioteca de WhatsApp do JOB.
    Formato: arrays de metadados (audios/messages/medias/docs, cada item com
    id/name/isFavorite) + objectsList (id -> data: texto puro ou data:URI
    base64). Streaming com ijson pra aguentar backups grandes sem estourar a
    memória. Dedup por nome (re-subir não duplica). Mídia é salva via
    upload_arquivo_r2 e importada como modelo com midia_arquivo/midia_tipo —
    o envio de mídia em si é fase à parte, mas o item já fica na biblioteca."""
    import ijson, io as _io, base64 as _b64, tempfile as _tmp
    f = request.files.get('arquivo')
    if not f or not f.filename:
        return jsonify({"ok": False, "erro": "Envie o arquivo .json do backup"}), 400
    tmp = _tmp.NamedTemporaryFile(delete=False, suffix='.json')
    try:
        f.save(tmp.name)
        tmp.close()
        # Passo 1: metadados (id -> nome, favorito). Pequeno, cabe na memória.
        meta = {}
        for kind in ('audios', 'messages', 'medias', 'docs'):
            with open(tmp.name, 'rb') as fh:
                for it in ijson.items(fh, f'{kind}.item'):
                    if it.get('id'):
                        meta[it['id']] = {'nome': (it.get('name') or 'Sem nome').strip()[:200],
                                          'fav': 1 if it.get('isFavorite') else 0}
        conn = db()
        existentes = {r['nome'] for r in conn.execute(
            "SELECT nome FROM modelos_conteudo WHERE tipo='whatsapp'").fetchall()}
        criado_por = session.get('user_id')
        contagem = {'texto': 0, 'audio': 0, 'imagem': 0, 'documento': 0, 'video': 0, 'pulados': 0, 'erros': 0}
        # Passo 2: objectsList, um item por vez (blob grande decodificado e
        # descartado na hora — memória fica limitada).
        with open(tmp.name, 'rb') as fh:
            for obj in ijson.items(fh, 'objectsList.item'):
                oid = obj.get('id')
                m = meta.get(oid)
                if not m:
                    continue
                nome = m['nome']
                if nome in existentes:
                    contagem['pulados'] += 1
                    continue
                cat = _zv_categoria_do_nome(nome)
                data = obj.get('data')
                try:
                    if isinstance(data, str) and data.startswith('data:'):
                        header, b64data = data.split(',', 1)
                        mime = header[5:header.find(';')] if ';' in header else 'application/octet-stream'
                        if mime.startswith('audio'):
                            midia_tipo, ext = 'audio', ('.ogg' if 'ogg' in mime else ('.mp3' if 'mpeg' in mime else '.m4a'))
                        elif mime.startswith('image'):
                            midia_tipo, ext = 'imagem', ('.png' if 'png' in mime else '.jpg')
                        elif 'pdf' in mime:
                            midia_tipo, ext = 'documento', '.pdf'
                        elif mime.startswith('video'):
                            midia_tipo, ext = 'video', '.mp4'
                        else:
                            midia_tipo, ext = 'documento', '.bin'
                        raw = _b64.b64decode(b64data)
                        nome_arq = f"MODELO_WPP_ZV_{_sanitizar_filename(oid)}{ext}"
                        upload_arquivo_r2(_io.BytesIO(raw), f"modelos/{nome_arq}")
                        conn.execute("""INSERT INTO modelos_conteudo
                            (tipo, nome, corpo_texto, ativo, criado_por, midia_arquivo, midia_tipo, categoria, favorito)
                            VALUES ('whatsapp',?,?,1,?,?,?,?,?)""",
                            (nome, nome, criado_por, nome_arq, midia_tipo, cat, m['fav']))
                        contagem[midia_tipo] += 1
                    else:
                        texto = (data or '').strip()[:4000]
                        if not texto:
                            contagem['pulados'] += 1
                            continue
                        conn.execute("""INSERT INTO modelos_conteudo
                            (tipo, nome, corpo_texto, ativo, criado_por, categoria, favorito)
                            VALUES ('whatsapp',?,?,1,?,?,?)""",
                            (nome, texto, criado_por, cat, m['fav']))
                        contagem['texto'] += 1
                    existentes.add(nome)
                    conn.commit()
                except Exception as e:
                    contagem['erros'] += 1
                    app.logger.warning(f"[IMPORT-ZV] falhou item {oid}: {e}")
        close_db(conn)
        return jsonify({"ok": True, "contagem": contagem})
    finally:
        try:
            os.unlink(tmp.name)
        except Exception:
            pass


@app.route('/crm/modelos/importar-botconversa', methods=['POST'])
@login_required
@admin_required
def crm_importar_botconversa():
    """Importa fluxos extraídos do BotConversa pra biblioteca de WhatsApp do
    JOB. Cada fluxo do BotConversa vira um whatsapp_funis; cada passo (texto
    ou mídia) do fluxo vira um modelos_conteudo, ligado em ordem via
    whatsapp_funil_passos — mesmo padrão da importação do ZapVoice, mas
    reconstruindo também a sequência (funil), não só a biblioteca solta de
    mensagens.
    Aceita dois formatos de entrada:
    1) multipart/form-data com campo 'arquivo' = .zip (manifest.json + pasta
       media/ com os binários já baixados) — feito por
       scripts/botconversa_extract.py, que roda na máquina de quem tem
       acesso ao BotConversa.
    2) JSON puro (Content-Type: application/json) com a lista de fluxos
       direto — cada passo de mídia leva uma 'url' pública (o BotConversa
       guarda mídia em S3 sem exigir login pra baixar) em vez de
       'arquivo_local'; o próprio servidor busca o binário. Evita ter que
       fazer upload de um zip grande pelo navegador — só texto (o manifest é
       leve), o download pesado roda direto no servidor pra R2.
    Dedup por nome de funil — re-subir o mesmo zip/manifest não duplica.
    Dedup também de mídia dentro da mesma importação (por hash do
    arquivo_local OU pela própria url) — o mesmo binário (ex.: PDF de rede
    de atendimento reaproveitado em vários fluxos parecidos) é enviado pro
    storage uma única vez, mesmo se vier em lotes/requisições separadas,
    porque o nome final no storage é sempre determinístico."""
    import io as _io
    import hashlib as _hashlib
    from urllib.parse import urlparse

    zf = None
    tmp_path = None
    if request.files.get('arquivo'):
        import zipfile as _zip, tempfile as _tmp
        f = request.files['arquivo']
        tmp = _tmp.NamedTemporaryFile(delete=False, suffix='.zip')
        f.save(tmp.name)
        tmp.close()
        tmp_path = tmp.name
        try:
            zf = _zip.ZipFile(tmp_path)
            manifesto = json.loads(zf.read('manifest.json'))
        except KeyError:
            zf.close(); os.unlink(tmp_path)
            return jsonify({"ok": False, "erro": "Zip inválido: falta manifest.json"}), 400
        except Exception as e:
            if zf: zf.close()
            os.unlink(tmp_path)
            return jsonify({"ok": False, "erro": f"Zip inválido: {e}"}), 400
    else:
        manifesto = request.get_json(silent=True)
        if manifesto is None:
            return jsonify({"ok": False, "erro": "Envie o .zip exportado ou um JSON com a lista de fluxos"}), 400
        if isinstance(manifesto, dict):
            manifesto = manifesto.get('fluxos') or []

    def _obter_bytes(passo):
        arq_local = passo.get('arquivo_local')
        if arq_local and zf:
            try:
                return zf.read(f'media/{arq_local}')
            except KeyError:
                return None
        url = passo.get('url')
        if url:
            try:
                r = _requests.get(url, timeout=30)
                r.raise_for_status()
                return r.content
            except Exception as e:
                app.logger.warning(f"[IMPORT-BC] falhou baixar mídia {url}: {e}")
                return None
        return None

    try:
        conn = db()
        existentes = {r['nome'] for r in conn.execute("SELECT nome FROM whatsapp_funis").fetchall()}
        criado_por = session.get('user_id')
        contagem = {'funis': 0, 'modelos': 0, 'pulados': 0, 'erros': 0}
        cache_midia = {}  # identidade da mídia (arquivo_local ou url) -> nome_arq já subido
        for fluxo in manifesto:
            nome_funil = (fluxo.get('nome') or '').strip()[:200]
            if not nome_funil or nome_funil in existentes:
                contagem['pulados'] += 1
                continue
            try:
                categoria = (fluxo.get('categoria') or '').strip()[:120] or None
                conn.execute("INSERT INTO whatsapp_funis (nome, categoria, ativo, criado_por) VALUES (?,?,1,?)",
                             (nome_funil, categoria, criado_por))
                fid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                       else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
                ordem = 0
                for passo in (fluxo.get('passos') or []):
                    tipo = passo.get('tipo')
                    if tipo == 'texto':
                        texto = (passo.get('texto') or '').strip()
                        if not texto:
                            continue
                        ordem += 1
                        conn.execute("""INSERT INTO modelos_conteudo
                            (tipo, nome, corpo_texto, ativo, criado_por, categoria) VALUES ('whatsapp',?,?,1,?,?)""",
                            (f"{nome_funil} #{ordem}"[:200], texto[:4000], criado_por, categoria))
                    elif tipo in ('imagem', 'video', 'audio', 'documento'):
                        identidade = passo.get('arquivo_local') or passo.get('url')
                        if not identidade:
                            continue
                        ordem += 1
                        nome_arq = cache_midia.get(identidade)
                        if not nome_arq:
                            # nome determinístico (hash da identidade — arquivo_local do
                            # script já é nomeado pelo hash do conteúdo; url vira hash
                            # aqui) — mesmo binário reaproveitado em fluxos diferentes
                            # sobe uma vez só, mesmo em importações/lotes separados,
                            # porque o nome final é sempre o mesmo.
                            ext = os.path.splitext(urlparse(identidade).path if identidade.startswith('http') else identidade)[1] or '.bin'
                            h = _hashlib.sha1(identidade.encode('utf-8')).hexdigest()[:20]
                            nome_arq = f"MODELO_WPP_BC_{h}{ext}"[:120]
                            if not os.path.exists(os.path.join(UPLOAD_FOLDER, nome_arq)):
                                dados_bin = _obter_bytes(passo)
                                if not dados_bin:
                                    contagem['erros'] += 1
                                    continue
                                upload_arquivo_r2(_io.BytesIO(dados_bin), f"modelos/{nome_arq}")
                            cache_midia[identidade] = nome_arq
                        conn.execute("""INSERT INTO modelos_conteudo
                            (tipo, nome, ativo, criado_por, midia_arquivo, midia_tipo, categoria) VALUES ('whatsapp',?,1,?,?,?,?)""",
                            (f"{nome_funil} #{ordem}"[:200], criado_por, nome_arq, tipo, categoria))
                    else:
                        continue
                    mid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                           else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
                    conn.execute("INSERT INTO whatsapp_funil_passos (funil_id, ordem, modelo_id, delay_segundos) VALUES (?,?,?,?)",
                                 (fid, ordem, mid, 5))
                    contagem['modelos'] += 1
                existentes.add(nome_funil)
                contagem['funis'] += 1
                conn.commit()
            except Exception as e:
                contagem['erros'] += 1
                app.logger.warning(f"[IMPORT-BC] falhou fluxo \"{fluxo.get('nome')}\": {e}")
        close_db(conn)
        return jsonify({"ok": True, "contagem": contagem})
    finally:
        if zf:
            zf.close()
        if tmp_path:
            try:
                os.unlink(tmp_path)
            except Exception:
                pass


