@app.route('/crm/funis/<int:fid>/mover-pasta', methods=['POST'])
@login_required
@admin_required
def crm_funil_mover_pasta(fid):
    d = request.json or {}
    pasta_id = d.get('pasta_id')
    conn = db()
    if not conn.execute("SELECT id FROM whatsapp_funis WHERE id=?", (fid,)).fetchone():
        close_db(conn); return jsonify({"ok": False, "erro": "Funil não encontrado"}), 404
    dono = None
    if pasta_id:
        if not conn.execute("SELECT id FROM pastas WHERE id=?", (pasta_id,)).fetchone():
            close_db(conn); return jsonify({"ok": False, "erro": "Pasta não encontrada"}), 400
        dono = _pasta_dono(conn, pasta_id)
    conn.execute("UPDATE whatsapp_funis SET pasta_id=?, dono_consultor_id=? WHERE id=?", (pasta_id or None, dono, fid))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True})


@app.route('/crm/pastas/backfill-automatico', methods=['POST'])
@login_required
@admin_required
def crm_pastas_backfill_automatico():
    """Cria as 5 pastas raiz (Compartilhado, A organizar, uma por consultor
    real) e classifica os modelos/funis a partir da categoria solta.

    Classificação ESPERTA (a 1a versão era ingênua — virava 109 pastas de
    lixo porque tratava cada string de categoria como pasta):
    - "FLUXOS <consultor>" → pasta pessoal do consultor.
    - Categoria que casa com uma OPERADORA conhecida (por palavra-chave —
      "amil", "amil (1)", "amil (2)" → AMIL; "vera cruz"/"VERA CRUZ" → VERA
      CRUZ) → uma única subpasta da operadora dentro de Compartilhado. Isso
      consolida as 192 categorias de Vera Cruz numa pasta só, etc.
    - Qualquer outra coisa (categoria vazia, data, nome de arquivo, nota
      solta) → "A organizar", SEM criar subpasta. O gestor arruma depois.

    ?reset=1 (ou {"reset": true}): apaga TODAS as pastas e zera pasta_id de
    tudo antes de reclassificar do zero — pra corrigir uma classificação
    ruim anterior. Sem reset, só mexe em item ainda sem pasta_id (não
    atropela organização manual). Idempotente nos dois modos."""
    reset = bool((request.json or {}).get('reset')) or request.args.get('reset') == '1'
    conn = db()
    if reset:
        conn.execute("UPDATE modelos_conteudo SET pasta_id=NULL, dono_consultor_id=NULL")
        conn.execute("UPDATE whatsapp_funis SET pasta_id=NULL, dono_consultor_id=NULL")
        conn.execute("DELETE FROM pastas")

    # Operadoras canônicas por palavra-chave (ordem importa: mais específico
    # primeiro — "beneficência" antes de "bene"; nome normalizado sem acento).
    _OPERADORAS_KW = [
        ('VERA CRUZ', ['vera cruz', 'vera prata', 'vera ouro', 'vera adesao', 'vera empresarial',
                       'vera confort', 'coparticipacao vera', 'portal vera', 'vera (', 'vera adesão']),
        ('MEDSENIOR', ['medsenior', 'med senior']),
        ('SAUDE BENEFICENCIA', ['beneficencia']),
        ('SULAMERICA', ['sulamerica', 'sul america']),
        ('BRADESCO', ['bradesco']),
        ('AMIL', ['amil']),
        ('PORTO SAUDE', ['porto']),
        ('UNIMED', ['unimed']),
        ('NOTREDAME / GNDI / HAPVIDA', ['gndi', 'notredame', 'notre dame', 'notrelife',
                                        'intermedica', 'hapvida']),
        ('SAO BERNARDO / SAMP', ['sao bernardo', 'bernardo samp', ' samp']),
        ('SANTA TEREZA', ['santa tereza']),
        ('UNICA SAUDE', ['unica saude', 'unica ']),
        ('EVA SAUDE', ['eva saude']),
        ('ABRAMGE', ['abramge']),
        ('AMHE', ['amhe']),
        ('BENE', ['bene']),
        ('OMINT', ['omint']),
        ('CARE PLUS', ['care plus']),
        ('GOCARE', ['gocare', 'go care']),
        ('PROASA', ['proasa']),
        ('SALUSMED', ['salusmed', 'salus med']),
        ('LEADER', ['leader']),
        ('DONA SAUDE', ['dona saude']),
    ]

    def _operadora_de(categoria):
        k = _norm_txt(categoria or '')  # minúsculo, sem acento
        if not k.strip():
            return None
        for nome, kws in _OPERADORAS_KW:
            for kw in kws:
                if _norm_txt(kw) in k:
                    return nome
        return None

    def _achar_ou_criar_raiz(nome, consultor_id):
        r = conn.execute(
            "SELECT id FROM pastas WHERE parent_id IS NULL AND nome=? AND COALESCE(consultor_id,0)=COALESCE(?,0)",
            (nome, consultor_id)).fetchone()
        if r:
            return r['id']
        conn.execute("INSERT INTO pastas (nome, parent_id, consultor_id) VALUES (?,NULL,?)", (nome, consultor_id))
        return (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])

    def _achar_ou_criar_sub(nome, parent_id):
        r = conn.execute("SELECT id FROM pastas WHERE parent_id=? AND nome=?", (parent_id, nome)).fetchone()
        if r:
            return r['id']
        conn.execute("INSERT INTO pastas (nome, parent_id, consultor_id) VALUES (?,?,NULL)", (nome, parent_id))
        return (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])

    raiz_compartilhado = _achar_ou_criar_raiz('Compartilhado', None)
    raiz_organizar = _achar_ou_criar_raiz('A organizar', None)

    consultores = {r['nome']: r['id'] for r in conn.execute(
        "SELECT id, nome FROM usuarios WHERE perfil='consultor' AND ativo=1").fetchall()}
    # Mapeamento explícito (não fuzzy) do apelido usado nas categorias antigas
    # pro nome completo cadastrado em usuarios — só essas 3 existem hoje.
    APELIDO_CONSULTOR = {'JENI': 'Jenifer Aparecida Lobregat dos Santos',
                          'JULIANA': 'Juliana Azevedo', 'PRI': 'Prisciele Azevedo'}
    raiz_consultor = {}
    for apelido, nome_completo in APELIDO_CONSULTOR.items():
        uid = consultores.get(nome_completo)
        if uid:
            raiz_consultor[apelido] = _achar_ou_criar_raiz(nome_completo, uid)

    cache = {}

    def _resolver_pasta(categoria):
        chave = (categoria or '').strip()
        if chave in cache:
            return cache[chave]
        m = re.match(r'^FLUXOS\s+(\w+)', chave, re.IGNORECASE)
        apelido = m.group(1).upper() if m else None
        if apelido and apelido in raiz_consultor:
            uid = consultores[APELIDO_CONSULTOR[apelido]]
            resultado = (_achar_ou_criar_sub(chave, raiz_consultor[apelido]), uid)
        else:
            op = _operadora_de(chave)
            if op:
                resultado = (_achar_ou_criar_sub(op, raiz_compartilhado), None)
            else:
                # categoria vazia, data, nome de arquivo, nota solta → "A
                # organizar" sem virar pasta (o gestor arruma depois).
                resultado = (raiz_organizar, None)
        cache[chave] = resultado
        return resultado

    contagem = {'modelos_classificados': 0, 'funis_classificados': 0}
    pastas_usadas = set()
    for row in conn.execute("SELECT id, categoria FROM modelos_conteudo WHERE pasta_id IS NULL").fetchall():
        pasta_id, dono = _resolver_pasta(row['categoria'])
        conn.execute("UPDATE modelos_conteudo SET pasta_id=?, dono_consultor_id=? WHERE id=?", (pasta_id, dono, row['id']))
        pastas_usadas.add(pasta_id)
        contagem['modelos_classificados'] += 1
    for row in conn.execute("SELECT id, categoria FROM whatsapp_funis WHERE pasta_id IS NULL").fetchall():
        pasta_id, dono = _resolver_pasta(row['categoria'])
        conn.execute("UPDATE whatsapp_funis SET pasta_id=?, dono_consultor_id=? WHERE id=?", (pasta_id, dono, row['id']))
        pastas_usadas.add(pasta_id)
        contagem['funis_classificados'] += 1
    contagem['total_pastas'] = conn.execute("SELECT COUNT(*) n FROM pastas").fetchone()['n']
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "contagem": contagem})


# ─── Funis de WhatsApp (sequências de disparo) ──────────────────────────────
# Um funil é uma sequência ordenada de passos; cada passo aponta pra um modelo
# da biblioteca (texto/áudio/imagem/PDF) + um delay antes de mandar. A extensão
# TOCA a sequência na conversa aberta. Isto é SEPARADO dos "fluxos" do CRM
# (tabela fluxos) — por decisão do Guilherme; casar os dois é passo futuro.

def _funil_num(v, padrao, minimo, maximo):
    try:
        n = int(v)
    except (TypeError, ValueError):
        return padrao
    return max(minimo, min(maximo, n))


@app.route('/crm/funis')
@login_required
@admin_required
def crm_funis():
    conn = db()
    funis = [dict(f) for f in conn.execute(
        "SELECT * FROM whatsapp_funis WHERE ativo=1 ORDER BY favorito DESC, (categoria IS NULL), categoria, nome").fetchall()]
    passos = [dict(p) for p in conn.execute("""
        SELECT p.id, p.funil_id, p.ordem, p.delay_segundos,
               m.id AS modelo_id, m.nome AS modelo_nome, m.midia_tipo, m.corpo_texto
        FROM whatsapp_funil_passos p
        JOIN modelos_conteudo m ON m.id = p.modelo_id
        ORDER BY p.funil_id, p.ordem, p.id""").fetchall()]
    # Biblioteca de modelos pra montar os passos (só WhatsApp ativos).
    modelos = [dict(m) for m in conn.execute("""
        SELECT id, nome, midia_tipo, categoria, corpo_texto FROM modelos_conteudo
        WHERE tipo='whatsapp' AND ativo=1
        ORDER BY (categoria IS NULL), categoria, nome""").fetchall()]
    arvore_pastas = _construir_arvore_pastas(conn)
    close_db(conn)
    por_funil = {}
    for p in passos:
        p['tipo'] = p['midia_tipo'] if p['midia_tipo'] in ('audio', 'imagem', 'video', 'documento') else 'texto'
        por_funil.setdefault(p['funil_id'], []).append(p)
    for f in funis:
        f['passos'] = por_funil.get(f['id'], [])
        f['total_delay'] = sum((p['delay_segundos'] or 0) for p in f['passos'])
    return render_template('crm_funis.html', funis=funis, modelos=modelos, arvore_pastas=arvore_pastas)


