# ── Auto-pull de leads disparado por requisição (independe do APScheduler) ──
# Garante que os leads cheguem "a todo momento" mesmo que o agendador em
# background morra após restart/deploy no Railway. Throttle: no máximo 1x a
# cada 10 min por processo. Roda em thread daemon: nunca bloqueia/derruba a página.
_ULTIMO_AUTO_PULL = 0.0
_AUTO_PULL_LOCK = threading.Lock()
_AUTO_PULL_INTERVALO = 600  # segundos

_ULTIMO_FIXO_AUTO = 0.0


def _gerar_fixo_automatico():
    """Fixo mensal SEM depender de clique: garante os lançamentos do mês
    corrente pra todo consultor com fixo (antes, se ninguém clicasse o botão
    em /financeiro, o fixo simplesmente não existia — nem na DRE nem pro
    consultor). gerar_fixo_mes é idempotente por consultor+dia, então rodar de
    novo só cria o que falta — consultor novo no meio do mês entra na próxima
    passada. Tenta no máximo 1x a cada 6h (pega o mutirão do throttle de 10min
    do auto-pull, mas não martela o banco)."""
    global _ULTIMO_FIXO_AUTO
    agora = time.time()
    if agora - _ULTIMO_FIXO_AUTO < 6 * 3600:
        return
    _ULTIMO_FIXO_AUTO = agora
    try:
        ano_mes = datetime.now(TZ_SP).strftime('%Y-%m')
        criados = gerar_fixo_mes(ano_mes)
        if criados:
            app.logger.info(f"[FIXO] {criados} lançamento(s) de fixo gerados automaticamente pra {ano_mes}")
    except Exception as e:
        app.logger.warning(f"[FIXO] geração automática falhou: {e}")

def _auto_pull_leads_throttled():
    global _ULTIMO_AUTO_PULL
    try:
        agora = time.time()
        if agora - _ULTIMO_AUTO_PULL < _AUTO_PULL_INTERVALO:
            return
        if not _AUTO_PULL_LOCK.acquire(blocking=False):
            return
        _ULTIMO_AUTO_PULL = agora
        def _run():
            try:
                _importar_leads_automatico()
            except Exception:
                pass
            try:
                _enviar_lembretes_agenda()
            except Exception:
                pass
            try:
                _processar_fluxos_pendentes()
            except Exception:
                pass
            try:
                _gerar_fixo_automatico()
            except Exception:
                pass
            finally:
                try: _AUTO_PULL_LOCK.release()
                except Exception: pass
        threading.Thread(target=_run, daemon=True).start()
    except Exception:
        pass


def _iniciar_scheduler_backup():
    """Liga agendador de backup automático JSON (22:00 SP todo dia)."""
    global _SCHEDULER_INICIADO
    if _SCHEDULER_INICIADO:
        return
    try:
        from apscheduler.schedulers.background import BackgroundScheduler
        
        def fazer_backup_agendado():
            """Função que roda automaticamente às 22:00 SP."""
            try:
                conn = db()
                propostas = conn.execute("SELECT * FROM propostas").fetchall()
                parcelas = conn.execute("SELECT * FROM parcelas").fetchall()
                usuarios = conn.execute("SELECT * FROM usuarios").fetchall()
                operadoras = conn.execute("SELECT * FROM operadoras").fetchall()
                recebimento = conn.execute("SELECT * FROM recebimento").fetchall()
                repasse_corretor = conn.execute("SELECT * FROM repasse_corretor").fetchall()
                
                backup = {
                    'versao': 'v14',
                    'data_backup': datetime.now(TZ_SP).isoformat(),
                    'total_propostas': len(propostas),
                    'propostas': [dict(p) for p in propostas],
                    'parcelas': [dict(p) for p in parcelas],
                    'usuarios': [dict(u) for u in usuarios],
                    'operadoras': [dict(o) for o in operadoras],
                    'recebimento': [dict(r) for r in recebimento],
                    'repasse_corretor': [dict(r) for r in repasse_corretor],
                }
                
                close_db(conn)
                
                os.makedirs('/data/backups', exist_ok=True)
                timestamp = datetime.now(TZ_SP).strftime('%Y%m%d-%H%M%S')
                backup_file = f"/data/backups/backup-{timestamp}.json"
                
                with open(backup_file, 'w', encoding='utf-8') as f:
                    json.dump(backup, f, indent=2, default=str, ensure_ascii=False)
                
                app.logger.info(f"[BACKUP AUTO] ✅ {backup_file} ({len(propostas)} propostas)")
            except Exception as e:
                app.logger.error(f"[BACKUP AUTO] ❌ {e}")
        
        # Agendar para 22:00 (SP) todos os dias
        sched = BackgroundScheduler(daemon=True, timezone=TZ_SP)
        sched.add_job(fazer_backup_agendado, 'cron', hour=22, minute=0, max_instances=1)
        # Importação automática de leads das planilhas: roda LOGO ao subir e depois
        # a cada 15 minutos (antes só rodava 30 min após o boot).
        sched.add_job(_importar_leads_automatico, 'interval', minutes=15, max_instances=1,
                      next_run_time=datetime.now(TZ_SP) + timedelta(seconds=20))
        # Lembretes da agenda do CRM (sino + WhatsApp) a cada 5 min
        sched.add_job(_enviar_lembretes_agenda, 'interval', minutes=5, max_instances=1,
                      next_run_time=datetime.now(TZ_SP) + timedelta(seconds=40))
        # Leads parados (7+ dias sem atividade): resumo diário às 09:00 SP
        sched.add_job(_notificar_leads_parados, 'cron', hour=9, minute=0, max_instances=1)
        # Fluxos de nutrição do CRM: dispara os passos pendentes 1x/dia às 08:00 SP
        sched.add_job(_processar_fluxos_pendentes, 'cron', hour=8, minute=0, max_instances=1)
        sched.start()
        _SCHEDULER_INICIADO = True
        app.logger.info("[SCHEDULER] ✅ Backup (22:00 SP) + Importação de leads (boot + a cada 15 min) agendados")
    except Exception as e:
        app.logger.warning(f"[SCHEDULER] ❌ Falha ao iniciar: {e}")

try:
    _iniciar_scheduler_backup()
except Exception as e:
    app.logger.warning(f"[SCHEDULER] Falha final: {e}")


# ──── IMPORTAÇÃO DE LEADS DO GOOGLE SHEETS ─────────────────────────────────
# Mapeamento de apelidos de consultores → nomes reais
CONSULTOR_ALIASES = {
    # Guilherme
    'guilherme': 'Guilherme',
    'guilherme santos': 'Guilherme',
    'gui': 'Guilherme',
    'gui santos': 'Guilherme',
    'gui2': 'Guilherme',
    'guilherme2': 'Guilherme',
    # Danilo
    'danilo': 'Danilo',
    'danilo sampaio': 'Danilo',
    'danilo2': 'Danilo',
    'danilo 2': 'Danilo',
    # Bianca
    'bianca': 'Bianca',
    'bianca sampaio': 'Bianca',
    'bianca2': 'Bianca',
    'bianca 2': 'Bianca',
    # Gabriel
    'gabriel': 'Gabriel',
    'gabriel maggiotto': 'Gabriel',
    'gabriel humberto maggiotto': 'Gabriel',
    'gabriel2': 'Gabriel',
    'gabriel 2': 'Gabriel',
    # Juliana (supervisora)
    'juliana': 'Juliana',
    # Jack / JACK
    'jack': 'Jack',
    'jack2': 'Jack',
}

def _normalizar_telefone(tel_raw):
    """
    Extrai só os dígitos do telefone e normaliza para o padrão brasileiro.
    Retorna apenas dígitos: '5519991046030' ou '19991046030'.
    Usado para comparação/dedup.
    """
    if not tel_raw:
        return ''
    import re
    dig = re.sub(r'\D', '', str(tel_raw))
    # Remove código do país 55 se tiver 12-13 dígitos (55 + DDD + número)
    if len(dig) >= 12 and dig.startswith('55'):
        dig = dig[2:]
    return dig


def _buscar_lead_por_telefone(conn, telefone_norm):
    """Busca de lead por telefone: SEMPRE a base de verdade pro dedup (nunca
    nome — nome tem falso-negativo fácil, ex: contato salvo como 'Karine' no
    CRM vs 'Karine - Lead' no WhatsApp, que nunca bateria numa comparação
    exata e geraria duplicata). Exata primeiro; se não achar, tenta pelos
    últimos 8 dígitos (mesmo número, só variando presença do 9º dígito —
    '19991046030' vs '1991046030' têm o mesmo sufixo de 8). Usado em todo
    lugar que cria lead a partir de telefone: import de planilha (manual e
    automático) e análise de WhatsApp — critério único, sem duplicar lógica."""
    if not telefone_norm:
        return None
    lead = conn.execute("SELECT id, nome, responsavel_id FROM crm_leads WHERE telefone_norm=?",
                        (telefone_norm,)).fetchone()
    if lead:
        return lead
    suf = telefone_norm[-8:]
    if len(suf) == 8:
        lead = conn.execute("SELECT id, nome, responsavel_id FROM crm_leads WHERE telefone_norm LIKE ?",
                            ('%' + suf,)).fetchone()
    return lead

def _formatar_telefone(tel_raw):
    """
    Formata telefone para exibição bonita: (19) 99104-6030 ou (19) 3104-6030.
    Aceita qualquer formato de entrada (com 55, com traços, espaços, etc.).
    """
    if not tel_raw:
        return ''
    dig = _normalizar_telefone(tel_raw)
    if not dig:
        return str(tel_raw).strip()
    # Celular com DDD: 11 dígitos → (XX) XXXXX-XXXX
    if len(dig) == 11:
        return f'({dig[0:2]}) {dig[2:7]}-{dig[7:11]}'
    # Fixo com DDD: 10 dígitos → (XX) XXXX-XXXX
    if len(dig) == 10:
        return f'({dig[0:2]}) {dig[2:6]}-{dig[6:10]}'
    # Celular sem DDD: 9 dígitos → XXXXX-XXXX
    if len(dig) == 9:
        return f'{dig[0:5]}-{dig[5:9]}'
    # Fixo sem DDD: 8 dígitos → XXXX-XXXX
    if len(dig) == 8:
        return f'{dig[0:4]}-{dig[4:8]}'
    # Outros tamanhos: retorna os dígitos como estão
    return dig

def _normalizar_consultor(nome_raw):
    """Normaliza apelido/nome para o primeiro nome real. Retorna None se vazio."""
    if not nome_raw:
        return None
    nome_lower = nome_raw.strip().lower()
    # Tenta match exato no alias
    if nome_lower in CONSULTOR_ALIASES:
        return CONSULTOR_ALIASES[nome_lower]
    # Tenta pelo primeiro nome
    primeiro = nome_lower.split()[0] if nome_lower else ''
    if primeiro in CONSULTOR_ALIASES:
        return CONSULTOR_ALIASES[primeiro]
    # Se não achou alias, retorna o nome capitalizado (pode ser consultor novo)
    return nome_raw.strip().title() if nome_raw.strip() else None

def _buscar_responsavel_id(conn, consultor_nome):
    """
    Busca o ID do usuário responsável de forma DETERMINÍSTICA (sem acento/caixa):
    nome completo exato → primeiro nome exato (palavra inteira) → None.
    O LIKE por prefixo foi removido: 'Ana' casava com 'Anastácia' e atribuía
    o lead ao consultor errado.
    """
    if not consultor_nome:
        return None
    alvo = _norm_txt(consultor_nome)
    if not alvo:
        return None
    alvo_primeiro = alvo.split()[0]
    try:
        rows = conn.execute("SELECT id, nome FROM usuarios WHERE ativo=1 ORDER BY id").fetchall()
    except Exception:
        return None
    # 1) nome completo exato
    for r in rows:
        rid = r['id'] if hasattr(r, 'keys') else r[0]
        rnome = _norm_txt(r['nome'] if hasattr(r, 'keys') else r[1])
        if rnome == alvo:
            return rid
    # 2) primeiro nome exato (palavra inteira, não prefixo)
    candidatos = []
    for r in rows:
        rid = r['id'] if hasattr(r, 'keys') else r[0]
        rnome = _norm_txt(r['nome'] if hasattr(r, 'keys') else r[1])
        if rnome.split() and rnome.split()[0] == alvo_primeiro:
            candidatos.append(rid)
    # Só atribui se houver UM único usuário com esse primeiro nome (ambíguo → None)
    if len(candidatos) == 1:
        return candidatos[0]
    return None

# ─── DATAS: parsing flexível e formatação dd/mm/aaaa ─────────────────────────────
def _parse_data_lead(data_str):
    """
    Converte string de data da planilha em objeto date.
    Aceita múltiplos formatos: ISO, DD/MM/YYYY, YYYY-MM-DD, etc.
    Retorna None se não conseguir.
    """
    if not data_str:
        return None
    s = str(data_str).strip()
    if not s:
        return None

    # 1. ISO com T: 2026-04-19T02:09:58.778-03:00
    try:
        if 'T' in s:
            # Remove timezone e milissegundos
            parte_iso = s.split('T')[0]  # pega 2026-04-19
            a, m, d = parte_iso.split('-')
            return date(int(a), int(m), int(d))
    except Exception:
        pass

    # 2. DD/MM/YYYY [HH:MM:SS]
    try:
        parte_data = s.split()[0]  # remove hora se houver
        if '/' in parte_data and parte_data.count('/') == 2:
            partes = parte_data.split('/')
            if len(partes[2]) == 4:  # YYYY tem 4 dígitos
                d, m, a = partes
                return date(int(a), int(m), int(d))
    except Exception:
        pass

    # 3. YYYY-MM-DD [HH:MM:SS]
    try:
        parte_data = s.split()[0]  # remove hora se houver
        if '-' in parte_data and parte_data.count('-') == 2:
            a, m, d = parte_data.split('-')
            return date(int(a), int(m), int(d))
    except Exception:
        pass

    # Se chegou aqui e tem números, tenta extrair ano/mês/dia da forma que conseguir
    try:
        import re as _re
        nums = _re.findall(r'\d+', s)
        if len(nums) >= 3:
            # Tenta várias combinações
            # 1. DD MM YYYY
            if len(nums[2]) == 4:
                return date(int(nums[2]), int(nums[1]), int(nums[0]))
            # 2. YYYY MM DD
            elif len(nums[0]) == 4:
                return date(int(nums[0]), int(nums[1]), int(nums[2]))
    except Exception:
        pass

    return None

def _fmt_data_br(valor):
    """Formata qualquer data/datetime/string para dd/mm/aaaa. Vazio se não der."""
    if not valor:
        return ''
    # Se já é date/datetime
    if isinstance(valor, (datetime, date)):
        return valor.strftime('%d/%m/%Y')
    # String
    d = _parse_data_lead(str(valor))
    return d.strftime('%d/%m/%Y') if d else str(valor)[:10]

def _fmt_datahora_br(valor):
    """Formata para dd/mm/aaaa HH:MM."""
    if not valor:
        return ''
    if isinstance(valor, (datetime, date)):
        try:
            return valor.strftime('%d/%m/%Y %H:%M')
        except Exception:
            return valor.strftime('%d/%m/%Y')
    s = str(valor).replace('T', ' ')
    d = _parse_data_lead(s)
    if d:
        # tenta extrair hora
        hora = ''
        try:
            if ' ' in s and ':' in s:
                hora = ' ' + s.split()[1][:5]
        except Exception:
            pass
        return d.strftime('%d/%m/%Y') + hora
    return str(valor)[:16]

def _status_esfriando(atualizado_em):
    """Card do Kanban muda de cor conforme tempo sem nenhuma ação (pedido do
    Gabriel via PDF 04/07: "esfriando" sem contato). Retorna classe CSS + texto."""
    dt = _parse_dt_seguro(atualizado_em) if atualizado_em else None
    if not dt:
        return {'classe': '', 'texto': ''}
    if dt.tzinfo is None:
        dt = TZ_SP.localize(dt)
    dias = int((datetime.now(TZ_SP) - dt).total_seconds() / 86400)
    if dias >= 5:
        return {'classe': 'card-frio', 'texto': f'Frio há {dias}d'}
    if dias >= 2:
        return {'classe': 'card-esfriando', 'texto': f'Esfriando há {dias}d'}
    return {'classe': '', 'texto': ''}


# Registra filtros Jinja para uso nos templates
try:
    app.jinja_env.filters['data_br'] = _fmt_data_br
    app.jinja_env.filters['datahora_br'] = _fmt_datahora_br
    app.jinja_env.filters['status_esfriando'] = _status_esfriando
except Exception:
    pass

def _ler_google_sheets(sheet_id, aba):
    """Lê Google Sheets público como CSV. Retorna lista de dicts.
    IMPORTANTE: o nome da aba precisa ser URL-encoded — nomes com espaço
    ('LEADS GERAIS') ou acento ('Página1') quebram a urlopen sem o quote."""
    import csv
    from io import StringIO
    import urllib.request, urllib.parse
    try:
        aba_q = urllib.parse.quote(aba)
        url = f"https://docs.google.com/spreadsheets/d/{sheet_id}/gviz/tq?tqx=out:csv&sheet={aba_q}"
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0 (JOB Serenus)'})
        response = urllib.request.urlopen(req, timeout=15)
        csv_text = response.read().decode('utf-8-sig')
        reader = csv.DictReader(StringIO(csv_text))
        return list(reader) if reader else []
    except Exception as e:
        app.logger.error(f"[LEAD_IMPORT] Erro ao ler sheets {sheet_id}/{aba}: {e}")
        return []


def _ler_google_sheets_por_gid(sheet_id, gid):
    """Lê Google Sheets público como CSV via /export (por gid, não por nome).
    Usar quando /gviz/tq mostrar dado desatualizado (confirmado 04/07/2026 na
    planilha META — /gviz cacheava a coluna Consultor com valor antigo mesmo
    minutos/horas depois da edição; /export?format=csv reflete o valor real)."""
    import csv
    from io import StringIO
    import urllib.request
    try:
        url = f"https://docs.google.com/spreadsheets/d/{sheet_id}/export?format=csv&gid={gid}"
        req = urllib.request.Request(url, headers={'User-Agent': 'Mozilla/5.0 (JOB Serenus)'})
        response = urllib.request.urlopen(req, timeout=15)
        csv_text = response.read().decode('utf-8-sig')
        reader = csv.DictReader(StringIO(csv_text))
        return list(reader) if reader else []
    except Exception as e:
        app.logger.error(f"[LEAD_IMPORT] Erro ao ler sheets (por gid) {sheet_id}/{gid}: {e}")
        return []

def _listar_leads_do_sheets():
    """Lê ambas as planilhas (Facebook e Google) e retorna lista de leads brutos."""
    leads = []
    
    # Facebook: "LEADS GERAIS" (gid=0) — por gid, não por nome: /gviz cacheava
    # a coluna Consultor desatualizada (confirmado 04/07/2026)
    facebook_id = '1VOChFfTkuVO4eO0FCAkBjrP9qDFnvWZnk5rLdUrNm64'
    facebook_leads = _ler_google_sheets_por_gid(facebook_id, 0)
    for row in facebook_leads:
        row['_origem'] = 'Facebook'
        leads.append(row)
    
    # Google: "Página1", "Página2" e "MEDSENIOR"
    google_id = '1QT8y8rfbMaHb5POrYFZKjdccpgMLLY3WRjBjxFmold8'
    for aba in ['Página1', 'Página2', 'MEDSENIOR']:
        google_leads = _ler_google_sheets(google_id, aba)
        for row in google_leads:
            row['_origem'] = f'Google ({aba})'
            leads.append(row)
    
    return leads

def _col(row, *names):
    """Primeiro valor não-vazio entre várias colunas possíveis (case-insensitive).
    As planilhas usam nomes diferentes: 'Celular' vs 'Whatsapp', 'Email' vs 'email',
    'CONSULTOR' vs 'Consultor', 'DATA e HORA' vs 'Data', etc."""
    low = {}
    for k, v in row.items():
        if k is not None:
            low[str(k).strip().lower()] = v
    for n in names:
        v = low.get(str(n).strip().lower())
        if v and str(v).strip():
            return str(v).strip()
    return ''


def _processar_lead(row, conn):
    """
    Processa um lead bruto da planilha:
    - Normaliza consultor
    - Filtra "teste"
    - Detecta duplicados
    - Retorna (sucesso, msg, dados_processados)
    """
    # Mapeamento FLEXÍVEL de colunas (cada planilha nomeia diferente)
    nome = _col(row, 'Nome', 'nome')
    telefone = _col(row, 'Celular', 'Whatsapp', 'WhatsApp', 'Telefone', 'Tel', 'Fone', 'Contato')
    email = _col(row, 'Email', 'email', 'E-mail', 'e-mail')
    cidade = _col(row, 'Cidade', 'Qual sua Cidade?', 'Qual sua cidade?', 'cidade')
    tipo = _col(row, 'Tipo', 'tipo') or 'PF'
    num_pessoas = _col(row, 'numero de pessoas', 'número de pessoas', 'Idades que tem interesse em cotar?', 'IDADE', 'Idade')
    data_hora_raw = _col(row, 'DATA e HORA', 'Data', 'data', 'Data e Hora')
    origem = row.get('_origem', 'Google Sheets')
    # UTM (pago vs orgânico + qual campanha/página). utm_medium=cpc/ppc/paid = PAGO.
    utm_source = _col(row, 'UTM SOURCE', 'utm_source', 'utm source')
    utm_medium = _col(row, 'utm_medium', 'UTM MEDIUM', 'utm medium')
    utm_campaign = _col(row, 'utm_campaign', 'UTM CAMPAIGN', 'utm campaign')
    utm_term = _col(row, 'utm_term', 'UTM TERM', 'utm term')
    utm_content = _col(row, 'UTM_Content', 'utm_content', 'UTM CONTENT', 'utm content')
    _med = (utm_medium or '').strip().lower()
    if _med in ('cpc', 'ppc', 'paid', 'paidsearch', 'paid_search', 'paid-search', 'display', 'cpm'):
        trafego = 'Pago'
    elif utm_source or utm_medium or utm_campaign or utm_content:
        trafego = 'Orgânico'
    else:
        trafego = ''
    utm = {k: v for k, v in {'source': utm_source, 'medium': utm_medium, 'campaign': utm_campaign,
                             'term': utm_term, 'content': utm_content}.items() if v}
    # Ids de clique (conversão offline): gclid (Google), gbraid/wbraid (iOS/app),
    # fbclid (Meta) + landing page. Vêm do snippet colado na landing (campo oculto).
    gclid = _col(row, 'gclid', 'GCLID', 'GClid')
    click = {k: v for k, v in {
        'gclid': gclid, 'gbraid': _col(row, 'gbraid', 'GBRAID'),
        'wbraid': _col(row, 'wbraid', 'WBRAID'), 'fbclid': _col(row, 'fbclid', 'FBCLID'),
        'landing': _col(row, 'landing_url', 'landing', 'Landing', 'page', 'url'),
        'device': _col(row, 'device', 'Device', 'aparelho')}.items() if v}
    # Planilha META/Facebook: SEMPRE só a coluna "Consultor" (nunca "Consultor 2" —
    # pedido explícito do Guilherme, não é confiável pra atribuição). Outras planilhas
    # mantêm o mapeamento flexível (nomeiam colunas de forma diferente).
    if origem == 'Facebook':
        consultor_raw = _col(row, 'Consultor')
    else:
        consultor_raw = _col(row, 'CONSULTOR', 'Consultor', 'Consultor 2', 'consultor')
    
    # Filtro 1: "teste" em nome ou email
    if nome and 'teste' in nome.lower():
        return (False, 'Ignorado (teste no nome)', None)
    if email and 'teste' in email.lower():
        return (False, 'Ignorado (teste no email)', None)
    
    # Normalizar consultor + busca FLEXÍVEL. Planilha sem Consultor preenchido →
    # fica SEM responsável (nunca chuta 'Guilherme' — mascarava leads órfãos).
    consultor = _normalizar_consultor(consultor_raw)
    responsavel_id = _buscar_responsavel_id(conn, consultor) if consultor else None
    
    # Data do lead
    data_lead = _parse_data_lead(data_hora_raw)
    
    # Filtro 2: Duplicado — SEMPRE por telefone normalizado (nunca nome, nunca
    # telefone cru). Bug real que gerava duplicata em massa: essa checagem
    # comparava o telefone CRU da planilha (ex: "19991046030") contra a coluna
    # `telefone` do banco, que guarda o valor JÁ FORMATADO pra exibição
    # (ex: "(19) 99104-6030") — as duas strings quase nunca batiam, então
    # praticamente todo lead "duplicado" passava como novo. Corrigido pra
    # comparar normalizado-com-normalizado, com tolerância de 9º dígito
    # (mesmo critério usado na análise de WhatsApp — _buscar_lead_por_telefone).
    telefone_norm = _normalizar_telefone(telefone)
    if telefone_norm:
        dup = _buscar_lead_por_telefone(conn, telefone_norm)
        if dup:
            return (False, f'Duplicado (tel {telefone})', None)

    if email:
        dup = conn.execute(
            "SELECT id FROM crm_leads WHERE email = ?",
            (email,)
        ).fetchone()
        if dup:
            return (False, f'Duplicado (email {email})', None)

    # Validação mínima
    if not nome:
        return (False, 'Nome vazio', None)

    det = []
    if tipo and str(tipo).strip():
        det.append(f"Tipo: {tipo}")
    if num_pessoas and str(num_pessoas).strip():
        det.append(f"Pessoas: {num_pessoas}")
    obs = ', '.join(det)
    if trafego:
        obs = (obs + ' · ' if obs else '') + f"Tráfego: {trafego}"
        if utm.get('campaign'):
            obs += f" ({utm['campaign']})"
    if utm.get('content'):
        obs = (obs + ' · ' if obs else '') + f"Página: {utm['content']}"
    return (True, 'OK', {
        'nome': nome,
        'telefone': telefone,
        'telefone_norm': telefone_norm,
        'email': email,
        'empresa': cidade,
        'origem': origem,
        'etapa': 'topo',
        'responsavel_id': responsavel_id,
        'valor_estimado': None,
        'consultor_nome': consultor,
        'data_lead': data_lead.strftime('%Y-%m-%d 12:00:00') if data_lead else None,
        'observacoes': obs,
        'trafego': trafego,
        'gclid': gclid or None,
        'dados_extras': json.dumps({'utm': utm, 'click': click}, ensure_ascii=False) if (utm or click) else None,
    })


