@app.route('/crm/frios/campanha/<int:cid>/enviar', methods=['POST'])
@login_required
@admin_required
def crm_frios_enviar(cid):
    """Disparo em massa (e-mail ou SMS) pros contatos selecionados da campanha.
    Reaproveita os MESMOS modelos e a MESMA infra de envio do CRM principal —
    SMS sempre com link wa.me puro (nunca rastreado, ver nota em _texto_sms_lead
    sobre aprovação da operadora)."""
    d = request.json or {}
    canal = (d.get('canal') or '').strip()
    template_key = (d.get('template') or '').strip()
    contato_ids = d.get('contato_ids') or []
    if canal not in ('email', 'sms') or not template_key or not contato_ids:
        return jsonify({"ok": False, "erro": "Dados incompletos"}), 400
    conn = db()
    campanha = conn.execute("SELECT * FROM campanhas_frias WHERE id=?", (cid,)).fetchone()
    if not campanha:
        close_db(conn); return jsonify({"ok": False, "erro": "Campanha não encontrada"}), 404

    if canal == 'sms' and template_key not in SMS_TEMPLATES_LEAD:
        close_db(conn); return jsonify({"ok": False, "erro": "Template de SMS inválido"}), 400
    if canal == 'email' and template_key not in _EMAIL_CONTATO_TEMPLATES:
        close_db(conn); return jsonify({"ok": False, "erro": "Template de e-mail inválido"}), 400

    enviados, falhas = 0, 0
    for cont_id in contato_ids:
        contato = conn.execute("SELECT * FROM contatos_frios WHERE id=? AND campanha_id=?", (cont_id, cid)).fetchone()
        if not contato:
            falhas += 1; continue
        ct = dict(contato)
        ok = False
        # Link do WhatsApp SEMPRE do consultor logado (número aprovado pela
        # operadora pra ELE especificamente, ver planilha SMS_consultores) —
        # nunca o WhatsApp genérico da empresa, isso quebra a aprovação do
        # template na operadora e o SMS some sem erro nenhum (já aconteceu).
        numero_wpp = _whatsapp_do_consultor(conn, session.get('user_id'))
        consultor_nome = session.get('nome') or 'Serenus'
        if canal == 'sms':
            if not ct.get('telefone'):
                falhas += 1; continue
            link = f"https://wa.me/{numero_wpp}"
            mensagem, _ = _texto_sms_lead(template_key, consultor_nome.split()[0], link, ct['nome'].split()[0] if ct.get('nome') else '')
            ok, erro = _enviar_sms(ct['telefone'], mensagem)
        else:
            if not ct.get('email') or '@' not in ct.get('email', ''):
                falhas += 1; continue
            tpl = _EMAIL_CONTATO_TEMPLATES[template_key]
            # Contato frio ainda não é lead — sem crm_email_log/token, então sem
            # rastreio de clique/abertura (que depende de lead_id). Link direto pro zap.
            link_zap = f"https://wa.me/{numero_wpp}"
            pixel_1x1 = 'data:image/gif;base64,R0lGODlhAQABAIAAAAAAAP///yH5BAEAAAAALAAAAAABAAEAAAIBTAA7'
            urow = conn.execute("SELECT id, nome, foto FROM usuarios WHERE id=?", (session.get('user_id'),)).fetchone()
            foto_url = f"{request.host_url.rstrip('/')}/avatar/{urow['id']}" if urow and urow['foto'] else None
            corpo = _corpo_email_contato(tpl, ct.get('nome'), session.get('nome') or 'Serenus',
                                         link_zap, pixel_1x1, foto_url=foto_url)
            try:
                ok = _enviar_email(ct['email'], tpl['assunto'], corpo, remetente_nome='Cotação de Plano de Saúde')
            except Exception:
                ok = False
        if ok:
            conn.execute("""INSERT INTO contato_frio_envio (contato_id, campanha_id, canal, template, enviado_por, criado_em)
                VALUES (?,?,?,?,?,?)""", (cont_id, cid, canal, template_key, session.get('user_id'), _agora_sp()))
            conn.execute("UPDATE contatos_frios SET status='contatado' WHERE id=? AND status='novo'", (cont_id,))
            enviados += 1
        else:
            falhas += 1
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "enviados": enviados, "falhas": falhas})


@app.route('/webhook/botconversa', methods=['POST'])
def webhook_botconversa():
    """Recebe o aviso do Bloco de Integração do BotConversa quando um contato
    da base fria responde no fluxo — NÃO cria o lead direto (pedido explícito:
    gestão quer revisar antes de promover pro CRM principal). Só marca o
    contato como 'respondeu', pronto pra promoção manual em /crm/frios.
    Protegido por token na query string (não tem sessão de usuário aqui, é
    uma chamada servidor-a-servidor do BotConversa).
    Payload esperado: {telefone: '5519...'}."""
    token_esperado = os.environ.get('BOTCONVERSA_WEBHOOK_TOKEN', '').strip()
    if token_esperado and request.args.get('token', '').strip() != token_esperado:
        return jsonify({"ok": False, "erro": "Token inválido"}), 401
    d = request.json or {}
    telefone = (d.get('telefone') or d.get('phone') or '').strip()
    tel_norm = _normalizar_telefone(telefone)
    if not tel_norm:
        return jsonify({"ok": False, "erro": "Telefone ausente ou inválido no payload"}), 400

    conn = db()
    contato = conn.execute(
        "SELECT * FROM contatos_frios WHERE telefone_norm=? AND status NOT IN ('respondeu','convertido') ORDER BY id DESC LIMIT 1",
        (tel_norm,)).fetchone()
    if not contato:
        close_db(conn)
        return jsonify({"ok": False, "erro": "Nenhum contato frio pendente com esse telefone"}), 404
    ct = dict(contato)

    conn.execute("UPDATE contatos_frios SET status='respondeu' WHERE id=?", (ct['id'],))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "contato_id": ct['id']})


@app.route('/webhook/botconversa/disparo', methods=['POST'])
def webhook_botconversa_disparo():
    """Recebe o aviso do Bloco de Integração colocado no INÍCIO do fluxo de
    disparo (o mesmo fluxo que a Transmissão do BotConversa dispara pra cada
    contato da lista). Chega um POST por contato, no momento exato em que a
    mensagem é enviada — assim a lista inteira do disparo cai automaticamente
    na Base Fria do JOB, sem precisar subir CSV duas vezes.
    Protegido por token na query string.
    Payload esperado: {telefone, nome, campanha (opcional, texto livre)}."""
    token_esperado = os.environ.get('BOTCONVERSA_WEBHOOK_TOKEN', '').strip()
    if token_esperado and request.args.get('token', '').strip() != token_esperado:
        return jsonify({"ok": False, "erro": "Token inválido"}), 401
    d = request.json or {}
    telefone = (d.get('telefone') or d.get('phone') or '').strip()
    nome = (d.get('nome') or d.get('name') or '').strip() or 'Sem nome'
    campanha_nome = (d.get('campanha') or 'Disparos BotConversa').strip()
    tel_norm = _normalizar_telefone(telefone)
    if not tel_norm:
        return jsonify({"ok": False, "erro": "Telefone ausente ou inválido no payload"}), 400

    conn = db()
    campanha = conn.execute("SELECT id FROM campanhas_frias WHERE nome=?", (campanha_nome,)).fetchone()
    if campanha:
        cid = campanha['id']
    else:
        conn.execute("INSERT INTO campanhas_frias (nome, descricao, criado_em) VALUES (?,?,?)",
                     (campanha_nome, 'Criada automaticamente a partir do disparo do BotConversa', _agora_sp()))
        cid = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
               else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])

    ja_existe = conn.execute(
        "SELECT id FROM contatos_frios WHERE campanha_id=? AND telefone_norm=?", (cid, tel_norm)).fetchone()
    if ja_existe:
        close_db(conn)
        return jsonify({"ok": True, "contato_id": ja_existe['id'], "duplicado": True})

    conn.execute("""INSERT INTO contatos_frios (campanha_id, nome, telefone, telefone_norm, status, criado_em)
        VALUES (?,?,?,?,'novo',?)""", (cid, nome, telefone, tel_norm, _agora_sp()))
    contato_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                  else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "contato_id": contato_id, "campanha_id": cid})


@app.route('/crm/frios/contato/<int:cid>/promover', methods=['POST'])
@login_required
@admin_required
def crm_frios_contato_promover(cid):
    """Promoção manual: gestão revisa o contato que respondeu no WhatsApp e
    decide se ele vira lead de verdade no CRM principal."""
    conn = db()
    contato = conn.execute("SELECT * FROM contatos_frios WHERE id=?", (cid,)).fetchone()
    if not contato:
        close_db(conn); return jsonify({"ok": False, "erro": "Contato não encontrado"}), 404
    ct = dict(contato)
    if ct['status'] == 'convertido':
        close_db(conn); return jsonify({"ok": False, "erro": "Contato já foi promovido"}), 400
    tel_norm = ct.get('telefone_norm')

    lead_existente = conn.execute("SELECT id FROM crm_leads WHERE telefone_norm=?", (tel_norm,)).fetchone() if tel_norm else None
    if lead_existente:
        lead_id = lead_existente['id']
    else:
        conn.execute("""INSERT INTO crm_leads (nome, telefone, telefone_norm, email, origem, etapa, criado_em, atualizado_em)
            VALUES (?,?,?,?,'base_fria','lead_novo',?,?)""",
            (ct['nome'], ct['telefone'], tel_norm, ct.get('email'), _agora_sp(), _agora_sp()))
        lead_id = (conn.execute("SELECT lastval() AS id").fetchone()['id'] if DB_MODE == "postgres"
                   else conn.execute("SELECT last_insert_rowid() id").fetchone()['id'])
        conn.execute("INSERT INTO crm_atividades (lead_id, usuario_nome, tipo, descricao, criado_em) VALUES (?,?,?,?,?)",
                     (lead_id, session.get('nome') or 'Sistema', 'criacao',
                      'Lead promovido manualmente a partir da base fria (respondeu no WhatsApp)', _agora_sp()))

    conn.execute("UPDATE contatos_frios SET status='convertido', lead_id=?, convertido_em=? WHERE id=?",
                 (lead_id, _agora_sp(), ct['id']))
    conn.commit(); close_db(conn)
    return jsonify({"ok": True, "lead_id": lead_id})


@app.route('/crm/importar', methods=['GET', 'POST'])
@login_required
def crm_importar():
    """GET: mostra form com seletor de datas. POST: processa importação."""
    usuario = session.get('usuario')
    if session.get('perfil') != 'admin':
        return jsonify({'erro': 'Acesso negado'}), 403
    
    conn = db()
    
    if request.method == 'GET':
        # Buscar min/max datas nas planilhas
        leads_raw = _listar_leads_do_sheets()
        datas = []
        for row in leads_raw:
            data_str = row.get('DATA e HORA', '') or row.get('28/05/2026', '')
            if data_str:
                datas.append(data_str[:10])  # YYYY-MM-DD ou DD/MM/YYYY
        
        min_data = min(datas) if datas else '2026-01-01'
        max_data = max(datas) if datas else date.today().isoformat()
        
        html = f"""
        <html><head><title>Importar Leads</title>
        <style>
            body {{ font-family: Arial; background: #f4f6f9; padding: 40px; }}
            .container {{ max-width: 600px; margin: 0 auto; background: white; padding: 30px; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }}
            h1 {{ color: #333; }}
            .form-group {{ margin: 20px 0; }}
            label {{ display: block; font-weight: bold; margin-bottom: 8px; color: #555; }}
            input, select {{ width: 100%; padding: 10px; border: 1px solid #ddd; border-radius: 4px; font-size: 14px; }}
            button {{ background: #3b82f6; color: white; padding: 12px 20px; border: none; border-radius: 4px; cursor: pointer; font-size: 16px; }}
            button:hover {{ background: #2563eb; }}
            .info {{ background: #e3f2fd; padding: 15px; border-radius: 4px; margin: 20px 0; color: #1976d2; }}
        </style>
        </head><body>
        <div class="container">
            <h1>Importar Leads das Planilhas</h1>
            <form method="POST">
                <div class="info">
                    ✓ Facebook (aba "LEADS GERAIS")<br>
                    ✓ Google (abas "Página1" + "MEDSENIOR")<br><br>
                    <strong>Filtros automáticos:</strong> remove "teste" + duplicados (tel/email)
                </div>
                
                <div class="form-group">
                    <label>Data Inicial:</label>
                    <input type="date" name="data_inicio" required value="{min_data}">
                </div>
                
                <div class="form-group">
                    <label>Data Final:</label>
                    <input type="date" name="data_fim" required value="{max_data}">
                </div>
                
                <div class="form-group">
                    <button type="submit">Importar Leads</button>
                </div>
            </form>
            <p style="margin-top: 30px; text-align: center;">
                <a href="/crm" style="color: #3b82f6; text-decoration: none;">← Voltar ao CRM</a>
            </p>
        </div>
        </body></html>
        """
        close_db(conn)
        return html
    
    # POST: processar importação
    data_inicio = request.form.get('data_inicio', '')
    data_fim = request.form.get('data_fim', '')
    
    if not data_inicio or not data_fim:
        close_db(conn)
        return jsonify({'erro': 'Datas obrigatórias'}), 400
    
    # Parse datas (YYYY-MM-DD)
    try:
        di = datetime.strptime(data_inicio, '%Y-%m-%d').date()
        df = datetime.strptime(data_fim, '%Y-%m-%d').date()
    except:
        close_db(conn)
        return jsonify({'erro': 'Formato de data inválido'}), 400
    
    # Ler planilhas
    leads_raw = _listar_leads_do_sheets()
    
    total = 0
    importados = 0
    ignorados = []
    
    for row in leads_raw:
        # Parse data da linha
        data_str = row.get('DATA e HORA', '')
        if not data_str:
            continue
        
        # Tentar vários formatos
        data_lead = None
        for fmt in ['%Y-%m-%dT%H:%M:%S.%f%z', '%d/%m/%Y %H:%M', '%d/%m/%Y']:
            try:
                data_lead = datetime.strptime(data_str[:19], fmt.split('T')[0] if 'T' in fmt else fmt).date()
                break
            except:
                pass
        
        if not data_lead:
            continue
        
        # Filtrar por intervalo de datas
        if not (di <= data_lead <= df):
            continue
        
        total += 1
        sucesso, msg, dados = _processar_lead(row, conn)
        
        if sucesso:
            try:
                # BUG CORRIGIDO: esse INSERT nunca gravava telefone_norm — o
                # lead criado aqui ficava PRA SEMPRE invisível pra qualquer
                # busca por telefone no resto do sistema (análise de WhatsApp,
                # próxima importação...), garantindo duplicata toda vez que
                # esse mesmo contato aparecesse de novo em qualquer outro lugar.
                conn.execute(
                    """INSERT INTO crm_leads
                       (nome, telefone, telefone_norm, email, empresa, origem, etapa, responsavel_id, valor_estimado, observacoes, criado_em, trafego, gclid, dados_extras)
                       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)""",
                    (dados['nome'], _formatar_telefone(dados['telefone']) or dados['telefone'], dados['telefone_norm'],
                     dados['email'], dados['empresa'], dados['origem'], dados['etapa'], dados['responsavel_id'],
                     dados['valor_estimado'], dados['observacoes'], dados.get('data_lead') or _agora_sp(),
                     dados.get('trafego') or None, dados.get('gclid'), dados.get('dados_extras'))
                )
                importados += 1
            except Exception as e:
                ignorados.append(f"{dados['nome']}: {str(e)}")
        else:
            ignorados.append(f"{row.get('Nome', 'SEM NOME')}: {msg}")
    
    conn.commit()
    close_db(conn)
    
    html = f"""
    <html><head><title>Resultado da Importação</title>
    <style>
        body {{ font-family: Arial; background: #f4f6f9; padding: 40px; }}
        .container {{ max-width: 700px; margin: 0 auto; background: white; padding: 30px; border-radius: 8px; box-shadow: 0 2px 8px rgba(0,0,0,0.1); }}
        h1 {{ color: #333; }}
        .stats {{ display: grid; grid-template-columns: 1fr 1fr; gap: 20px; margin: 30px 0; }}
        .stat {{ background: #f0f4f8; padding: 20px; border-radius: 6px; text-align: center; }}
        .stat-num {{ font-size: 32px; font-weight: bold; color: #3b82f6; }}
        .stat-label {{ color: #666; margin-top: 8px; }}
        .ignorados {{ background: #fff3cd; padding: 15px; border-radius: 6px; max-height: 300px; overflow-y: auto; }}
        .ignorados p {{ margin: 5px 0; font-size: 13px; color: #856404; }}
        a {{ color: #3b82f6; text-decoration: none; }}
        a:hover {{ text-decoration: underline; }}
    </style>
    </head><body>
    <div class="container">
        <h1>Importação Concluída</h1>
        <div class="stats">
            <div class="stat">
                <div class="stat-num">{importados}</div>
                <div class="stat-label">Leads Importados</div>
            </div>
            <div class="stat">
                <div class="stat-num">{len(ignorados)}</div>
                <div class="stat-label">Ignorados/Duplicados</div>
            </div>
        </div>
        
        <p><strong>Período:</strong> {data_inicio} até {data_fim}</p>
        <p><strong>Total analisado:</strong> {total}</p>
        
        {f'<div class="ignorados"><strong>Ignorados:</strong>' + ''.join(f'<p>• {ig}</p>' for ig in ignorados[:20]) + (f'<p><em>... e mais {len(ignorados)-20}</em></p>' if len(ignorados) > 20 else '') + '</div>' if ignorados else ''}
        
        <p style="margin-top: 30px; text-align: center;">
            <a href="/crm">← Voltar ao CRM</a>
        </p>
    </div>
    </body></html>
    """
    
    return html

